import { useState } from 'react';
import {
  cartApi,
  updateCart,
  publishLoaderEvent,
  getActiveCart,
  deletePaymentDetails,
  ExceptionsEnum,
  createOrFetchCart,
  type Cart,
  CartConstantsEnum,
  ApiProjections,
  CartEntryRequest,
  CartEventsEnum,
  PublishEvent,
  Price,
  Product,
  CartEntryDetails,
  MyShopStorageConstant,
  getdefaultRegistrtaionConfig,
  myListApi,
  AccountProcessType,
  OrderType,
  BundleSlot,
  ErrorResponse,
  CartEntry,
  CartEvents,
  SopElementResponse,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch, useSelector } from 'react-redux';
import { useNextgenRouter, useTranslation, AccountType, useSession } from '@nextgen-web-framework/all';
import { AppState, ConsoleLogger, StorageService } from '@nextgen-web-framework/core';
import { AdvanceShareCodeResponse, isRegistrationMandatory } from '@commerce-webcomponents/sdk';
import {
  CartNotificationTheme,
  TOAST_TIMEOUT,
  useCartNotification,
  useExceptionToast,
} from '@commerce-cart-webcomponents/ui';
import { MouseClickOrKeyPressEventTye } from '../types/propsTypes';
import { RouteType } from '../../../../ui-composite/components/cart-container/types/enums';

interface UseAddToCartProps {
  entryObj: {
    productId: string;
    productName?: string;
    bundleSlots?: BundleSlot[];
    quantity?: number;
    brandName?: string;
    productPrice?: number;
    pointValue?: string;
    businessVolume?: string;
  };
  onProductAdded?: (event: unknown, cart: Cart) => void;
  closeDrawer?: (event?: unknown) => void;
  isMinProjection?: boolean;
  transitionToStepper?: boolean;
  addToCartSuccessMsg?: string;
  sopMappingKey?: string;
  sopMetaDataRes?: SopElementResponse[];
}

export const useAddToCart = ({
  entryObj,
  onProductAdded,
  closeDrawer,
  isMinProjection = false,
  transitionToStepper,
  addToCartSuccessMsg,
  sopMappingKey,
  sopMetaDataRes,
}: UseAddToCartProps) => {
  const t = useTranslation();
  const router = useNextgenRouter();
  const { isAnonymous } = useSession();

  const addToCartSuccess = t('cart.addToCartButton.addToCartSuccess');
  const maxLimitReachedText = t('cart.addToCartButton.maxLimitText');
  const limitWillExceedText = t('cart.addToCartButton.limitExceedText');
  const maxLimitReachedHeading = t('cart.addToCartButton.maxLimitHeading');
  const limitWillExceedHeading = t('cart.addToCartButton.limitExceedHeading');

  const [loading, setLoading] = useState(false);
  const [showStepper, setShowStepper] = useState(false);
  const [productEntryId, setProductEntryId] = useState(0);
  //const [productQuantity, setProductQuantity] = useState(0);
  const dispatch = useDispatch();
  const { cart } = useSelector((state: AppState) => state.commerceCart);
  const activeCart = cart?.id ? getActiveCart(cart, '') : {};

  const { createToast, deleteToast } = useCartNotification('addToCartButton');
  const triggerToast = useExceptionToast();

  /** Helper: show error toast */
  const handleMaxQuantityError = (error?: ErrorResponse) => {
    if (!error) {
      return;
    }

    let theme = CartNotificationTheme.RED;
    let heading = maxLimitReachedHeading;
    let message = maxLimitReachedText;

    if (error.code === ExceptionsEnum.Exceptions.ProductQtyPartiallyAdded) {
      heading = limitWillExceedText;
      message = limitWillExceedHeading;
      theme = CartNotificationTheme.SUCCESS;
    }

    createToast(
      {
        theme,
        rightSeperator: false,
        content: heading,
        clickIcon: 'times',
        icon: 'check-circle',
        subtext: message,
        timeOut: TOAST_TIMEOUT,
      },
      deleteToast,
    );
  };

  const clickSuccessHandler = (res: Cart, e?: MouseClickOrKeyPressEventTye) => {
    setLoading(false);
    const entry = getProductEntry();
    PublishEvent({
      cartEvent: CartEventsEnum.AddToCart,
      cartEntry: entry,
      cartId: res.id,
      cart: res,
    });

    if (e && onProductAdded) {
      onProductAdded(e, res);
    }

    // CB for Product team to close drawer.
    closeDrawer?.();
  };

  const getProductEntry = () => {
    const result = activeCart?.entries?.find((entry) => entryObj.productId === entry.product.id);
    const data: CartEntryDetails = {
      ...(result as CartEntryDetails),
      product: {
        ...(result?.product as Product),
        brand: entryObj.brandName,
        name: entryObj.productName,
      },
      retailPrice: {
        ...(result?.retailPrice as Price),
        amwayValue: {
          pointValue: Number(entryObj.pointValue),
          businessVolume: Number(entryObj.businessVolume),
        },
        value: entryObj?.productPrice as number,
      },
    };
    return data;
  };

  const updateCartWithRegistrationProduct = async (cartId: string) => {
    const shareCode = StorageService.getLocalStorage().retrieve(
      MyShopStorageConstant.SHARECODEATTRIBUTES,
    ) as AdvanceShareCodeResponse;
    const enableRegistration = isRegistrationMandatory() || shareCode?.registrationAccountType;
    const defaultRegistration = getdefaultRegistrtaionConfig();
    const businessNatureType = defaultRegistration ? shareCode?.acctType : AccountType.Customer;
    const businessNature = shareCode?.registrationAccountType ?? businessNatureType;
    let isSponserBlocked = false;
    if (shareCode) {
      const data = await myListApi.getSponserBlockDetail(shareCode?.accountId ?? '');
      isSponserBlocked = data.isSponsorBlock;
    }

    if (isAnonymous() && !isSponserBlocked && enableRegistration && businessNature) {
      const res = (await cartApi.updateCart(cartId, cartId, {
        accountProcess: {
          type: AccountProcessType.Registration,
          businessNature: businessNature as AccountType,
        },
        orderType: OrderType.Regular,
        version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
      })) as Cart;
      dispatch(updateCart(res));
      PublishEvent({
        cartEvent: CartEventsEnum.UpdateMiniCartIcon,
        cart: res,
      });
    }
  };

  /** Main handler */
  const addToCart = async (e?: MouseClickOrKeyPressEventTye) => {
    setLoading(true);
    publishLoaderEvent(true);
    try {
      let fetchCartRes = activeCart;
      const localstorage = StorageService.getLocalStorage();
      const cartIdInLS = localstorage.retrieve(CartConstantsEnum.CartId);
      if (!cartIdInLS) {
        const res = await createOrFetchCart();
        fetchCartRes = getActiveCart(res);
      }

      const { productId, bundleSlots, quantity = 1 } = entryObj;

      const payload = {
        subCarts: [
          {
            subCartId: fetchCartRes?.subCartId ?? localstorage.retrieve(CartConstantsEnum.CartId),
            entries: [
              {
                product: { id: productId },
                quantity,
                bundleSlots,
                ...(sopMappingKey && { sopMappingKey: sopMappingKey }),
              },
            ],
            ...(sopMappingKey && sopMetaDataRes && { sopMetaData: sopMetaDataRes }),
          },
        ],
        version: Number(localstorage.retrieve(CartConstantsEnum.CartReqVersion)),
      } as CartEntryRequest;

      const res = (await cartApi.addToCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        projections:
          isMinProjection && !router.pathname?.includes(RouteType.CART) ? ApiProjections.MIN : ApiProjections.DETAILED,
        payload,
      })) as Cart;

      const error = (res as Cart).subCarts?.[0].errors?.find(
        (error) =>
          error.code === ExceptionsEnum.Exceptions.ProductQtyPartiallyAdded ||
          error.code === ExceptionsEnum.Exceptions.ProductQtyLimitExceed,
      );
      updateCartWithRegistrationProduct((res as Cart).id);
      handleMaxQuantityError(error);

      // Optional cleanup (payment, etc.)
      const deletePaymentRes = await deletePaymentDetails(activeCart);
      const updatedCart = (deletePaymentRes ?? res) as Cart;

      if (transitionToStepper) {
        const currentEntry = res?.subCarts?.[0]?.entries?.find(
          (entry: CartEntry) => entryObj.productId == entry.product.id && !entry.sopMappingKey,
        );
        setProductEntryId(currentEntry?.entryId);
        //setProductQuantity(currentEntry.quantity);
        setShowStepper(true);
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCount,
          payload: {
            cartId: (res as Cart).id,
            product_id: entryObj.productId,
            product_unitPrice: currentEntry.quantity,
          },
        });
      }

      // Update redux
      dispatch(updateCart(res));

      // Success toast if no error
      if (!error) {
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: addToCartSuccessMsg ?? addToCartSuccess,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
      }

      clickSuccessHandler(updatedCart, e);
      closeDrawer?.(e);
    } catch (error) {
      ConsoleLogger.log(error);
      triggerToast();
      closeDrawer?.(e);
    } finally {
      setLoading(false);
      publishLoaderEvent(false);
    }
  };

  return { addToCart, loading, showStepper, productEntryId, setShowStepper };
};
