import { useEffect, useRef, useState } from 'react';
import {
  CartEventDataInterface,
  CartEvents,
  CartEventsEnum,
  CartEventsVersionsEnum,
} from '@commerce-cart-webcomponents/sdk';

export const useCartLoaderEvents = () => {
  const subscriptionIds = useRef<string[]>([]);
  const [showPromotionLoadings, setShowPromotionLoadings] = useState<{ [key: string]: boolean }>({});

  useEffect(() => {
    const showLoaderEvent = CartEvents.subscribeEvents({
      topics: [CartEventsEnum.ShowLoader],
      version: CartEventsVersionsEnum['1.0.0'],
      cb: (message: string, { entryId }: CartEventDataInterface) => {
        setShowPromotionLoadings((prev) => ({ ...prev, [entryId as string]: true }));
      },
    });

    const hideLoaderEvent = CartEvents.subscribeEvents({
      topics: [CartEventsEnum.HideLoader],
      version: CartEventsVersionsEnum['1.0.0'],
      cb: (message: string, { entryId }: CartEventDataInterface) => {
        setShowPromotionLoadings((prev) => ({ ...prev, [entryId as string]: false }));
      },
    });

    subscriptionIds.current = [...hideLoaderEvent, ...showLoaderEvent];

    return () => CartEvents.unsubscribe(subscriptionIds.current);
  }, []);

  return { showPromotionLoadings };
};
