import { type Cart, SubCartDetail, isGroupOrder } from '@commerce-cart-webcomponents/sdk';
import { formatPrice } from '@nextgen-web-framework/core';
import { FAIcon, Theme, useTranslation } from '@nextgen-web-framework/all';
import { useState } from 'react';
import { code } from '../types/enums';
import styles from './TaxesIncluded.module.scss';

export interface TaxesIncludedProps {
  data: SubCartDetail;
  cartData: Cart;
  displayCheckoutBtn: boolean;
}

export const TaxesIncluded = ({ data, cartData, displayCheckoutBtn }: TaxesIncludedProps) => {
  const t = useTranslation();
  const [showTaxOverview, setShowTaxOverview] = useState(false);

  const getAppliedValueByCode = (code: string) => {
    const isGCO = isGroupOrder(cartData.orderType) && displayCheckoutBtn;
    const details = isGCO ? cartData?.totalPrice?.tax?.taxDetails : data?.totalPrice?.tax?.taxDetails;
    return details?.find((item) => item.code === code)?.appliedValue;
  };

  const taxDetails = {
    VAT: getAppliedValueByCode(code.VAT),
    IEPS: getAppliedValueByCode(code.IEPS),
    IEPSCuota: getAppliedValueByCode(code.IEPSCuota),
  };

  return (
    <>
      <div className={styles['taxes_included']}>
        <span className={styles['taxes_included_text']}>{t('cart.cartTotal.TaxesIncluded')}</span>
        <FAIcon
          theme={Theme.GRAY}
          className={styles['taxes_included_icon']}
          onClick={() => setShowTaxOverview(!showTaxOverview)}
          iconName={showTaxOverview ? 'chevron-up' : 'chevron-down'}
        />
      </div>
      {showTaxOverview && (
        <div>
          <div className={styles['tax_container']}>
            <div className={styles['tax_container_text']}>{t('cart.cartTotal.tax')}</div>
            <div className={styles['tax_container_amt']}>
              <span className={styles['tax_container_amt']}>{formatPrice(Number(taxDetails.VAT ?? 0))}</span>
            </div>
          </div>

          {taxDetails.IEPS > 0 && (
            <div className={styles['tax_container']}>
              <div className={styles['tax_container_text']}>{t('cart.cartTotal.IEPS')}</div>
              <div className={styles['tax_container_amt']}>
                <span className={styles['tax_container_amt']}>{formatPrice(Number(taxDetails.IEPS ?? 0))}</span>
              </div>
            </div>
          )}

          {taxDetails.IEPSCuota > 0 && (
            <div className={styles['tax_container']}>
              <div className={styles['tax_container_text']}>{t('cart.cartTotal.IEPSCuota')}</div>
              <div className={styles['tax_container_amt']}>
                <span className={styles['tax_container_amt']}>{formatPrice(Number(taxDetails.IEPSCuota ?? 0))}</span>
              </div>
            </div>
          )}
        </div>
      )}
    </>
  );
};
