export const showEditLabel = () => !!getCountrySpecificMasterConfig()?.showEditLabel;
export const showRecommendedProducts = () => !!getCountrySpecificMasterConfig()?.showRecommendedProducts;
export const hideBV = () => !!getCountrySpecificMasterConfig()?.hideBV;
export const hidePromotionBanner = () => !!getCountrySpecificMasterConfig()?.hidePromotionBanner;
export const forceAddRenewalProduct = () => getCountrySpecificMasterConfig()?.forceAddRenewalProduct;
export const enableSavedForLaterList = () => getCountrySpecificMasterConfig()?.enableSavedForLaterList;
export const enableSopSection = () => getCountrySpecificMasterConfig()?.enableSopSection;
export const enableTaxesIncluded = () => getCountrySpecificMasterConfig()?.enableTaxesIncluded;
export const enablePartialListSelection = () => getCountrySpecificMasterConfig()?.enablePartialListSharing;
export const hideInstalmentBanner = () => !!getCountrySpecificMasterConfig()?.hideInstalmentBanner;
export const pageNameForAPR = () => getCountrySpecificMasterConfig()?.pageNameForAPR;

