import { useEffect, useState } from 'react';
import { type IconName } from '@fortawesome/fontawesome-svg-core';
import {
  AlertMessage,
  FAIcon,
  TextLink,
  TextLinkUnderlineStyle,
  Theme,
  useTranslation,
  useSession,
  Button,
  ButtonStyles,
  ButtonWidth,
  ButtonSize,
  Checkbox,
} from '@nextgen-web-framework/all';
import { ConsoleLogger, type AppState } from '@nextgen-web-framework/core';
import { useDispatch, useSelector } from 'react-redux';
import {
  AmwayUserDetails,
  CartEventsEnum,
  InitialCartState,
  OrderType,
  PublishEvent,
  getActiveCart,
  getInstallProductDetails,
  getOrderTypeConfig,
  isProxyOrder,
  switchCart,
  updateAddressAfterCartSwitch,
  updateCart,
} from '@commerce-cart-webcomponents/sdk';
import { useAddressUpdate } from '@commerce-webcomponents/ui';
import { CancelProxyModal } from '../proxy-switch-warning-modal/CancelProxyModal';
import { InstallmentWarningModal } from '../proxy-switch-warning-modal/InstallmentWarningModal';
import { SOPWarningModal } from '../proxy-switch-warning-modal/SOPWarningModal';
import { CartNotificationTheme, useCartNotification, TOAST_TIMEOUT, useFeatureFlag } from '../../common';
import styles from './CartSwitchBanner.module.scss';
import AccountSearchDrawer from './../../common/components/account-search-drawer/AccountSearchDrawer';

interface CartSwitchBannerTypes {
  accountHolderName?: string;
  accountHolderId?: string;
}
export const CartSwitchBanner = ({ accountHolderName, accountHolderId }: CartSwitchBannerTypes) => {
  const t = useTranslation();
  const { isABO } = useSession();
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { cart }: InitialCartState = commerceCartState;
  const regularCartText = t('cart.cartSwitchBanner.regularCart');
  const downLineCartText = t('cart.cartSwitchBanner.downLineCart');
  const changeText = t('cart.proxyOrderBanner.change');
  const ordererText = t('cart.cartSwitchBanner.ordererText');
  const [showAccountDrawer, setShowAccountDrawer] = useState(false);
  const [showCancelProxyModal, setShowCancelProxyModal] = useState(false);
  const [showInstallmentWarningModal, setShowInstallmentWarningModal] = useState(false);
  const [showSOPWarningModal, setShowSOPWarningModal] = useState(false);
  const [cartOrderType, setCartOrderType] = useState<string>('');
  const drawerHeaderTitle = t('cart.cartTypeSelectionDrawer.ProxyOrder');
  const placeHolderText = t('cart.cartTypeSelectionDrawer.ABONumber');
  const accountCancelText = t('cart.addToCartDrawer.accountCancel');
  const accountAddCartText = t('cart.addToCartDrawer.accountAddCart');
  const cartChanged = t('cart.cartTypeSelectionDrawer.cartChanged');
  const cartChangedHeading = t('cart.cartTypeSelectionDrawer.cartChangedHeading');
  const confirmBtnText = t('cart.cartSwitchBanner.confirmBtn');
  const { createToast, deleteToast } = useCartNotification('cartTypeSelectionDrawer');
  const [proxyProfile, setProxyProfile] = useState<AmwayUserDetails>();
  const [consentChecked, setConsentChecked] = useState(false);
  const [isInputError, setIsInputError] = useState(false);
  const [disableProxyAgreement, setDisableProxyAgreement] = useState(true);
  const { newAddressApiFlag } = useFeatureFlag();

  useEffect(() => {
    if (isInputError && proxyProfile?.amwayUserId) {
      setProxyProfile({ amwayUserId: '' });
    }
  }, [isInputError]);

  const showSuccessNotification = () =>
    createToast(
      {
        theme: CartNotificationTheme.SUCCESS,
        rightSeperator: false,
        content: cartChangedHeading,
        subtext: cartChanged,
        clickIcon: 'times',
        icon: 'check-circle',
        timeOut: TOAST_TIMEOUT,
      },
      deleteToast,
    );
  const dataEntries = cart?.subCarts?.[0]?.entries ?? [];
  const installmentProducts = dataEntries && getInstallProductDetails(dataEntries);
  const sopProducts = cart?.subCarts[0].sopMetaData;

  const { updateAddress } = useAddressUpdate();
  const dispatch = useDispatch();

  const getText = (orderType: string) => {
    switch (orderType) {
      case OrderType.Proxy:
        return downLineCartText;
      default:
        return regularCartText;
    }
  };

  const getIcon = (orderType: string): IconName => {
    switch (orderType) {
      case OrderType.Proxy:
        return 'user-group';
      default:
        return 'user';
    }
  };

  useEffect(() => {
    if (!cartOrderType && cart.orderType) {
      setCartOrderType(cart.orderType);
    }
  }, [cart.orderType]);

  const handleOnRadioChange = async (profile: AmwayUserDetails) => {
    try {
      const previousOrderType = cart.orderType;
      const res = await switchCart(cart, OrderType.Proxy, profile as AmwayUserDetails);
      PublishEvent({
        cartEvent: CartEventsEnum.UpdateMiniCartIcon,
        cart: res,
      });
      const proxyCart = getActiveCart(res);
      // const addressRes = await updateShippingAddressInLS(
      //   proxyCart.amwayUser?.amwayUserId as string,
      //   proxyCart.amwayUser?.accountId as string,
      // );
      // if (isProxyOrder(previousOrderType) && (addressRes === null || !addressRes?.shippingAddresses.length)) {
      //   const res = await updateShippingAddressInLS(
      //     cart.amwayUser?.amwayUserId as string,
      //     cart.amwayUser?.accountId as string,
      //   );
      //   if (res === null || res?.shippingAddresses.length === 0) {
      //     updateShippingAddressToEmpty();
      // }
      // }
      // updateAddress();
      await updateAddressAfterCartSwitch(proxyCart, cart, previousOrderType, newAddressApiFlag, updateAddress);

      dispatch(updateCart(res));
      setShowAccountDrawer(false);
      showSuccessNotification();
      setConsentChecked(false);
      setProxyProfile({ amwayUserId: '' });
    } catch (error) {
      ConsoleLogger.error(error);
    } finally {
      setShowAccountDrawer(false);
    }
  };
  const isProxyAllowed = cart?.subCarts?.[0]?.amwayUser?.allowUplineForProxyOrder;

  const getOrderTypeFromConfig = () => (isABO() && cart.id === '' ? getOrderTypeConfig() : cart.orderType);

  const handleProxyAgreement = (hasRecord: boolean) => {
    setDisableProxyAgreement(!hasRecord);
  };

  const handleInputChanged = () => {
    setProxyProfile({ amwayUserId: '' });
    setDisableProxyAgreement(true);
    setConsentChecked(false);
  };

  return (
    <>
      {cart?.showCartSwitchBanner && (
        <>
          {showCancelProxyModal && (
            <CancelProxyModal setShowCancelProxyModal={setShowCancelProxyModal} cartData={cart} />
          )}
          {showInstallmentWarningModal && (
            <InstallmentWarningModal
              setShowInstallmentWarningModal={setShowInstallmentWarningModal}
              onInstallmentRemove={() => setShowAccountDrawer(true)}
            />
          )}
          {showSOPWarningModal && (
            <SOPWarningModal
              setShowSOPWarningModal={setShowSOPWarningModal}
              onSOPRemove={() => setShowAccountDrawer(true)}
              // setShowAccountDrawer={setShowAccountDrawer}
              cartEntries={cart?.subCarts[0]?.entries}
            />
          )}
          {showAccountDrawer && (
            <AccountSearchDrawer
              cartData={cart}
              onPrimaryButtonClick={() => {
                setShowAccountDrawer(false);
                setConsentChecked(false);
                setProxyProfile({ amwayUserId: '' });
              }}
              drawerHeaderTitle={drawerHeaderTitle}
              placeHolderText={placeHolderText}
              handleProxyAgreement={handleProxyAgreement}
              drawerFooter={
                <div className={styles['drawer-footer-btn']}>
                  <div className={styles['drawer-footer-btn-consent']}>
                    <Checkbox
                      text={t('cart.cartSwitchBanner.proxyAgreement')}
                      checked={consentChecked && !isInputError}
                      onClick={() => setConsentChecked(!consentChecked)}
                      disabled={disableProxyAgreement || isInputError || !proxyProfile?.amwayUserId}
                    />
                  </div>
                  <Button
                    title={confirmBtnText}
                    onClick={() => handleOnRadioChange(proxyProfile)}
                    disabled={!(consentChecked && proxyProfile?.amwayUserId)}
                    buttonStyle={ButtonStyles.SOLID}
                    buttonWidth={ButtonWidth.FULL_WIDTH}
                    size={ButtonSize.MEDIUM}
                  />
                </div>
              }
              primaryButtonText={accountCancelText}
              secondaryButtonText={accountAddCartText}
              onRadioChange={(profile) => setProxyProfile(profile)}
              setIsInputError={setIsInputError}
              isInputChanged={handleInputChanged}
            />
          )}
          <div data-testid="proxy-order-banner" className={styles['alert-message-wrapper-container']}>
            {!isProxyAllowed && isProxyOrder(cart?.orderType) && (
              <AlertMessage
                theme={Theme.ERROR}
                icon={'exclamation-square'}
                content={{
                  heading: t('cart.cartSwitchBanner.proxyNotAllowed'),
                }}
              />
            )}
            <AlertMessage className={styles['alert-message-wrapper']} hasIcon={false} theme={Theme.PURPLE}>
              <div className={styles['alert-message-banner']}>
                <div className={styles['alert-message-banner-icon-and-text']}>
                  <FAIcon
                    className={styles['alert-message-banner-icon']}
                    iconName={getIcon(getOrderTypeFromConfig())}
                    theme={Theme.WHITE}
                  />
                  <span className={styles['alert-message-banner-text']}>{getText(getOrderTypeFromConfig())}</span>
                </div>

                {getOrderTypeFromConfig() === OrderType.Proxy ? (
                  <span className={styles['alert-message-banner-change']}>
                    <TextLink
                      onClick={() => {
                        setShowCancelProxyModal(true);
                      }}
                      underline={TextLinkUnderlineStyle.FIXED}
                      text={accountCancelText}
                      theme={Theme.WHITE}
                    />
                  </span>
                ) : (
                  <span className={styles['alert-message-banner-change']}>
                    <TextLink
                      onClick={() => {
                        if (installmentProducts?.length > 0) {
                          setShowInstallmentWarningModal(true);
                          return;
                        }
                        if (sopProducts?.length > 0) {
                          setShowSOPWarningModal(true);
                          return;
                        }
                        setShowAccountDrawer(true);
                      }}
                      underline={TextLinkUnderlineStyle.FIXED}
                      text={changeText}
                      theme={Theme.WHITE}
                    />
                  </span>
                )}
              </div>
            </AlertMessage>
          </div>
          {getOrderTypeFromConfig() === OrderType.Proxy && (
            <div className={styles['orderer-info']}>
              <div className={styles['orderer-text']}> {ordererText} </div>
              <div className={styles['orderer-name']}> {`${accountHolderName}: ${accountHolderId}`}</div>
            </div>
          )}
        </>
      )}
    </>
  );
};
