import { memo } from 'react';
import styles from './../cart-overview/CartOverview.module.scss';

export interface CartOverviewItemProps {
  itemName: string;
  itemValue: string;
  containerClass?: string;
  itemNameClass?: string;
  itemValueClass?: string;
  isJapanOverview?: boolean;
  itemSubNameJP?: string;
  itemSubNameClassJP?: string;
  itemNameWrapperClassJP?: string;
}

export const CartOverviewItem = memo(
  ({
    itemName,
    itemValue,
    containerClass,
    itemNameClass,
    itemValueClass,
    isJapanOverview,
    itemSubNameJP,
    itemSubNameClassJP,
    itemNameWrapperClassJP,
  }: CartOverviewItemProps) => (
    <div className={styles[containerClass || '']}>
      {isJapanOverview ? (
        <div className={styles[itemNameWrapperClassJP || '']}>
          <div className={styles[itemNameClass || '']}>{itemName}</div>
          <div className={styles[itemSubNameClassJP || '']}>{itemSubNameJP}</div>
        </div>
      ) : (
        <div className={styles[itemNameClass || '']}>{itemName}</div>
      )}
      <div className={styles[itemValueClass || '']}>{itemValue}</div>
    </div>
  ),
);

CartOverviewItem.displayName = 'CartOverviewItem';
