import {
  Button,
  ButtonIconPosition,
  ButtonStyles,
  Theme,
  ButtonWidth,
  useTranslation,
} from '@nextgen-web-framework/all';
import { CartConstantsEnum, BundleSlot } from '@commerce-cart-webcomponents/sdk';
import { StorageService } from '@nextgen-web-framework/core';
import { useRef } from 'react';
import { getFulfillmentType, productApi, ProductData, Slot } from '@commerce-product-webcomponents/sdk';
import { BundleSlotEntriesType, BundleSlotType } from '@commerce-product-webcomponents/ui-composite';
import { ButtonLoader } from '../../../ui/common/components/cart-loader/button-loader/ButtonLoader';
import { QtySelector } from '../qty-selector/QtySelector';
import { useAddToCart } from './hook/useAddToCart';
import { AddToCartButtonPropTypes } from './types/propsTypes';
import styles from './AddToCartButton.module.scss';

export const AddToCartButton = ({
  onProductAdded,
  closeDrawer,
  disabled = false,
  showRightIcon = false,
  className = '',
  entryObj,
  size,
  textSize,
  isMinProjection = false,
  title,
  transitionToStepper = false,
  buttonWidth = ButtonWidth.FULL_WIDTH,
  showVariantDrawer = false,
  onAddToCartClick,
}: AddToCartButtonPropTypes) => {
  const t = useTranslation();
  const addToCartButtonText = t('cart.addToCartButton.addToCart');
  const bundleSlotsRef = useRef<BundleSlot[]>([]);

  const fetchBundleSlots = () =>
    productApi
      .getProductByIdOrError({
        productId: entryObj.productId,
        warehouseId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.WarehouseId),
        fulfillmentType: getFulfillmentType(),
      })
      .then((productData: ProductData | Response) => {
        if (!(productData instanceof Response)) {
          const bundleSlotsState: BundleSlotType[] = productData?.bundle?.slots?.map((slot: Slot) => {
            const bundleSlot = {
              id: slot.id?.toString() as string,
              entries: slot.products?.map((product: ProductData) => {
                const bundleSlotEntry = {
                  product: {
                    id: product.items[0].itemNumber as string,
                  },
                  quantity: slot.minQty,
                };
                return bundleSlotEntry;
              }) as unknown as BundleSlotEntriesType[],
            };
            return bundleSlot;
          }) as BundleSlotType[];
          bundleSlotsRef.current = bundleSlotsState;
          return bundleSlotsState;
        }
        return [];
      });

  const { addToCart, loading, showStepper, productEntryId, setShowStepper } = useAddToCart({
    entryObj: {
      ...entryObj,
      get bundleSlots() {
        return entryObj?.isStaticBundle ? bundleSlotsRef.current : entryObj?.bundleSlots;
      },
    },
    onProductAdded,
    closeDrawer,
    isMinProjection,
    transitionToStepper,
  });

  return (
    <>
      <div className={`${styles['add-to-cart-container']} ${className}`}>
        <div className={styles['container']}>
          {loading && <ButtonLoader size={size} className={styles['button-loader']} />}
          {!showStepper && (
            <Button
              id={'add-to-cart-button'}
              onClick={async (event: React.MouseEvent<HTMLSpanElement, MouseEvent>) => {
                if (entryObj?.isStaticBundle) {
                  const slots = await fetchBundleSlots();
                  if (slots && slots.length > 0) {
                    addToCart(event);
                  }
                } else if (showVariantDrawer) {
                  onAddToCartClick();
                } else {
                  addToCart(event);
                }
              }}
              buttonWidth={buttonWidth}
              title={title ?? addToCartButtonText}
              buttonStyle={ButtonStyles.SOLID}
              textSize={textSize}
              theme={Theme.BLACK}
              icon={showRightIcon ? { iconName: 'cart-shopping' } : undefined}
              iconPosition={ButtonIconPosition.RIGHT}
              size={size}
              tabIndex={0}
              disabled={disabled}
              aria-label="Add to Cart Button"
              role="button"
            />
          )}
          {showStepper && (
            <QtySelector
              entryObj={{
                productId: entryObj.productId,
                entryId: productEntryId,
              }}
              //initialQty={productQuantity}
              transitionToStepper={transitionToStepper}
              setShowStepper={setShowStepper}
            />
          )}
        </div>
      </div>
    </>
  );
};

export type { AddToCartButtonPropTypes };
