import { useEffect, useState } from 'react';
import { getExceptionProducts, CartEntryDetails } from '@commerce-cart-webcomponents/sdk';

export const useRemoveInvalidProducts = (
  cartEntries: CartEntryDetails[] | undefined,
  removeEntry: (entryId: number, entryIdArray?: number[], isInvalid?: boolean) => void,
) => {
  const { invalidProducts } = getExceptionProducts(cartEntries ?? []);
  const [invalidFlag, setInvalidFlag] = useState(false);

  useEffect(() => {
    if (invalidProducts && invalidProducts.length && !invalidFlag) {
      setInvalidFlag(true);
      const removedEntriesPayload = invalidProducts.map((entry) => entry.entryId).filter((id): id is number => !!id);
      removeEntry(0, removedEntriesPayload, true);
    }
  }, [cartEntries, invalidProducts]);
};
