import { useState, useEffect, useRef } from 'react';
import { useSelector, shallowEqual, useDispatch } from 'react-redux';
import { useNextgenRouter, useTranslation, useSession } from '@nextgen-web-framework/all';
import { StorageService, Logger, type AppDispatch, type AppState } from '@nextgen-web-framework/core';
import { CartItemsContainer } from '../../../ui/components/cart-line-items/cart-items-container/CartItemsContainer';
import { CartLoader } from '../../../ui/common/components/cart-loader/CartLoader';
import { CartLoaderType } from '../../../ui/common/components/cart-loader/types/enums';
import { useFeatureFlag } from '../../../ui/common/hooks/useFeatureFlag';
import {
  type Cart,
  type InitialCartState,
  getActiveCart,
  updateEntriesFromCheckoutData,
  ExceptionsEnum,
  Severity,
  getAllExceptionWithSeverity,
  isExceptionExist,
  CartConstantsEnum,
  CartEvents,
  CartEventsEnum,
  CartEventsVersionsEnum,
  CartRoutePaths,
  showEmptyCart,
  getLoaderType,
  getUpdatedEntriesFromModificationArray,
  cartApi,
  updateBlockerException,
  updateCart,
  updateShippingAddress,
  SubCartDetail,
  CartEntryDetails,
  showRecommendedProducts,
  enableSavedForLaterList,
  isGroupOrder,
  CartResponse,
} from '@commerce-cart-webcomponents/sdk';
import { ErrorCard, Errors, useAddressUpdate } from '@commerce-webcomponents/ui';
import { RecommendedProducts } from '../recommended-products/RecommendedProducts';
import { SavedForLater } from '../saved-for-later/SavedForLater';
import { errorImagePath, ExceptionTitleData } from './types/enums';

import Styles from './CartContainer.module.scss';

export type CartContainerProps = {
  checkoutHandler: () => void;
  isMainCart?: boolean;
  isSubCart?: boolean;
  displayCheckoutButton?: boolean;
  cartDetailsPage?: boolean;
};
export type ModificationsType = {
  subCartId: string;
  entries: CartEntryDetails[];
};

export const CartContainer = ({
  checkoutHandler,
  isSubCart = false,
  displayCheckoutButton = true,
  isMainCart = true,
  cartDetailsPage = false,
}: CartContainerProps) => {
  const t = useTranslation();
  const configs = ConfigService.getConfigs();
  const assetsBasePath = configs.NEXT_ASSETS_BASE_PATH as string;
  const { isAnonymous } = useSession();
  const router = useNextgenRouter();
  const subscriptionIds = useRef<string[]>([]);
  const [cartId, setCartId] = useState(router.params?.cartId ?? '');
  const [exceptionModal, setExceptionModal] = useState(false);
  const [isToggled, setIsToggled] = useState(false);
  const [gcoFlagLS, setGCOFlagLS] = useState<boolean>(false);
  const [exceptionTitleData, setExceptionTitleData] = useState<ExceptionTitleData>({
    title: '',
    description: '',
  });
  const { cart, isLoading, cartCheckoutData } = useSelector(
    (state: { commerceCart: InitialCartState }) => state.commerceCart,
    shallowEqual,
  );
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { isBlockerException }: InitialCartState = commerceCartState;

  let activeCart = getActiveCart(cart, (cartId as string) ?? cart.id);
  const [cartData, setCartData] = useState<Cart>({ ...cart });
  const [showErrorCard, setShowErrorCard] = useState(false);
  const dispatch = useDispatch<AppDispatch>();
  const [isApiInProgress, setIsApiInProgress] = useState(false);
  const loggerInstance = Logger.getInstance();
  const { newAddressApiFlag } = useFeatureFlag();

  const productExceptionDescriptionText = t('cart.cartContainer.productExecptionDescription');
  const productExceptionTitleText = t('cart.cartContainer.productExecptionTitle');
  const promotionExceptionTitleText = t('cart.cartContainer.promotionExecptionTitle');
  const promotionExceptionDescriptionText = t('cart.cartContainer.promotionExecptionDescription');
  const { updateAddress } = useAddressUpdate();
  const localstorage = StorageService.getLocalStorage();

  const isEmptyCart = showEmptyCart({
    cart,
    activeCart,
    cartId: cartId as string,
    isLoading,
  });

  const updateCartEntries = (cart?: Cart) => {
    const subcartModifications: ModificationsType[] = [];

    cart?.subCarts.map((subcart: SubCartDetail) => {
      if (
        subcart?.modificationResult &&
        subcart?.modificationResult?.isDbUpdateRequired &&
        subcart.modificationResult?.modifications?.length
      ) {
        const allEntries = getUpdatedEntriesFromModificationArray(subcart.modificationResult?.modifications);
        subcartModifications.push({
          subCartId: subcart.subCartId ?? cart.id,
          entries: allEntries,
        });
      }
    });
    const payload = {
      subCarts: subcartModifications,
      version: Number(localstorage.retrieve(CartConstantsEnum.CartReqVersion)),
    };

    setIsApiInProgress(true);
    cartApi
      .updateCartEntries({
        cartId: localstorage.retrieve(CartConstantsEnum.CartId),
        payload,
      })
      .then((res) => {
        dispatch(updateBlockerException(false));
        dispatch(updateCart(res as CartResponse));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart: res,
            cartId: localstorage.retrieve(CartConstantsEnum.CartId),
          },
        });
      })
      .catch(() => dispatch(updateBlockerException(true)))
      .finally(() => {
        loggerInstance.log(' On Finally Block', isApiInProgress);
        setIsApiInProgress(false);
      });
  };

  useEffect(() => {
    setCartId((router.params?.cartId as string) ?? '');
  }, [router.params]);

  useEffect(() => {
    activeCart = getActiveCart(cart, (cartId as string) ?? cart.id);
  }, [cartId]);

  useEffect(() => {
    const gcoFlag = StorageService.getLocalStorage().retrieve(CartConstantsEnum.IsGroupCart);

    setGCOFlagLS(!!gcoFlag);
    if (isLoading) {
      return;
    }
    if (isSubCart && !isGroupOrder(cart.orderType)) {
      router.back();
    }

    const blockerExceptions = getAllExceptionWithSeverity(
      [ExceptionsEnum.Exceptions.ProductService],
      Severity.Error,
      cart.errors ?? [],
    );
    if (blockerExceptions.length > 0) {
      setShowErrorCard(true);
    }

    if (isExceptionExist(ExceptionsEnum.Exceptions.ProductService, cart.errors ?? [])) {
      setExceptionTitleData({
        description: productExceptionDescriptionText,
        title: productExceptionTitleText,
      });
      setExceptionModal(true);
    }

    if (isExceptionExist(ExceptionsEnum.Exceptions.PromotionService, cart.errors ?? [])) {
      setExceptionTitleData({
        description: promotionExceptionDescriptionText,
        title: promotionExceptionTitleText,
      });
      setExceptionModal(true);
    }

    const updatedInventoryData = updateEntriesFromCheckoutData(cartCheckoutData, cart);
    setCartData(updatedInventoryData);
  }, [cart, isLoading]);

  useEffect(() => {
    const toggleEventStart = CartEvents.subscribeEvents({
      topics: [CartEventsEnum.IsGCOToggledStart],
      version: CartEventsVersionsEnum['1.0.0'],
      cb: () => {
        setIsToggled(true);
      },
    });

    const toggleEventEnd = CartEvents.subscribeEvents({
      topics: [CartEventsEnum.IsGCOToggledEnd],
      version: CartEventsVersionsEnum['1.0.0'],
      cb: () => {
        setIsToggled(false);
      },
    });

    subscriptionIds.current = [...toggleEventEnd, ...toggleEventStart];

    return () => {
      CartEvents.unsubscribe(subscriptionIds.current);
    };
  }, []);

  useEffect(() => {
    loggerInstance.log('inside useEffect', isApiInProgress);

    const hasModificationResults = cart.subCarts.some(
      (subCart: SubCartDetail) =>
        subCart?.modificationResult &&
        subCart?.modificationResult?.isDbUpdateRequired &&
        subCart.modificationResult?.modifications?.length,
    );
    if (!isApiInProgress && hasModificationResults) {
      updateCartEntries(cart);
    }
    //in case of GCO we will match owner id with all subcarts and update address with parent subcart

    const amwayUserIdinCheckoutLS = localstorage.retrieve('checkoutProfile') as unknown as {
      fulfillmentType: {
        serviceLevel: {
          deliveryAddress: {
            ownerId?: string;
            accountNumber?: string;
          };
        };
      };
    };

    const ownerId = amwayUserIdinCheckoutLS?.fulfillmentType?.serviceLevel?.deliveryAddress?.ownerId;
    const accountNum = amwayUserIdinCheckoutLS?.fulfillmentType?.serviceLevel?.deliveryAddress?.accountNumber;
    //added accountNum check for multi profile and same account scenario
    const subcartsOwnerIdNotMatched = cart.subCarts.every(
      (subCart: SubCartDetail) =>
        subCart?.amwayUser?.amwayUserId !== ownerId && subCart?.amwayUser?.accountId !== String(accountNum),
    );

    if (!isAnonymous() && activeCart && subcartsOwnerIdNotMatched && ownerId !== cart?.amwayUser?.amwayUserId) {
      updateShippingAddress(
        activeCart?.amwayUser?.amwayUserId as string,
        activeCart?.amwayUser?.accountId as string,
        newAddressApiFlag,
        updateAddress,
      );
    }
  }, [cart]);

  if (isLoading) {
    return <CartLoader loaderType={getLoaderType(cart, isToggled, gcoFlagLS, CartLoaderType) as CartLoaderType} />;
  }

  if (showErrorCard || isBlockerException) {
    return (
      <ErrorCard
        title={t('cart.cartContainer.errorTitle')}
        description={t('cart.cartContainer.errorDescription')}
        buttonLabel={t('cart.cartContainer.backToHomeCTA')}
        imageUrl={`${assetsBasePath}/${errorImagePath}`}
        onActionClick={() => {
          if (router?.push) {
            router.push(CartRoutePaths.HOME);
          }
        }}
        type={Errors.General}
      />
    );
  }

  return (
    <div className={Styles['cart-container']}>
      <CartItemsContainer
        cartData={cartData}
        cartId={cartId}
        isSubCart={isSubCart}
        cart={cart}
        isEmptyCart={isEmptyCart}
        activeCart={activeCart}
        exceptionModal={exceptionModal}
        setExceptionModal={setExceptionModal}
        exceptionTitleData={exceptionTitleData}
        isMainCart={isMainCart}
        cartDetailsPage={cartDetailsPage}
        checkoutHandler={checkoutHandler}
        displayCheckoutButton={displayCheckoutButton}
      />
      {showRecommendedProducts() && <RecommendedProducts />}
      {enableSavedForLaterList() && <SavedForLater />}
    </div>
  );
};
