import { Dispatch } from 'redux';
import { AnyAction } from '@reduxjs/toolkit';
import { StorageService } from '@nextgen-web-framework/core';
import { Cart, cartApi, updateCart, CartEvents, CartEventsEnum, CartConstantsEnum } from '../../sdk';

export const clearEntriesFromCart = (
  dispatch: Dispatch<AnyAction>,
  currentCartId: string,
  setShowLoader: (value: boolean) => void,
  setClearCart: (value: boolean) => void,
  setShowEllipses: (value: boolean) => void,
) => {
  setShowLoader(true);
  setClearCart(false);

  cartApi
    .clearCartEntries({
      cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
      subCartId: currentCartId,
    })
    .then((res) => {
      setShowLoader(false);
      setShowEllipses(false);

      dispatch(updateCart(res as Cart));

      CartEvents.publishEvent({
        event: CartEventsEnum.UpdateCartEntryQty,
        payload: {
          cart: res,
          cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        },
        sync: true,
      });
    });
};
