import { useState, useEffect, useMemo } from 'react';
import {
  Cart,
  SopElementResponse,
  VariantDimensions,
  getAllEntries,
  updateCart,
  getStockStatus,
  getBundleEntriesAndChildPromoitions,
  getVariantName,
  createProductEntryKey,
  getStrikeThroughPrice,
  CartConstantsEnum,
  type CartEntryDetails,
  getActiveCart,
  getErrorFromEntryOrSubCart,
  OrderType,
  isPickUpItemUnavailable,
  isDeliveryItemUnavailable,
  isThirdPartyPickUpUnavailable,
  isGroupOrder,
  transformedSOPEntries,
  RenewalFlag,
  AccountProcessType,
  cartApi,
  MyShopStorageConstant,
  bottomMsgPresent,
  getPlanName,
  isSellableCheck,
  getUniqueFiredPromotionsExceptCoupons,
  hideVariantSelector,
  updateIsCheckoutDisabled,
  getpkitAndeKitProductId,
  CartRoutePaths,
  includesAny,
  getEKitTermsAndConditionsConfig,
  getRenewalLateFeeOnlyConfig,
  hideBV,
  hidePromotionBanner,
  hideInstalmentBanner,
  AccountProductType,
  isExceptionExist,
  ExceptionsEnum,
  forceAddRenewalProduct,
  AccountType,
  enableSopSection,
  promosWhichAreNonSilent,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { nextgenDebounce, StorageService, type AppDispatch } from '@nextgen-web-framework/core';
import { useTranslation, useSession, useNextgenRouter, TagStyle } from '@nextgen-web-framework/all';
import { AdvanceShareCodeResponse } from '@commerce-webcomponents/sdk';
import { exceptionsBasedOnActionType } from '@commerce-cart-webcomponents/sdk';
import { calculateThemeForJapan, getTagLabel, isUserTypeMatched } from '@commerce-purchaseproduct-webcomponents/ui';
import { ProductCartEntryComponentV2, ProductCartVersion } from '@commerce-purchaseproduct-webcomponents/ui-composite';
import { ChangeToSOPButton, SOPBenefitLink, SOPCartContainer } from '@commerce-subscription-webcomponents/ui-composite';
import {
  CartNotificationTheme,
  ModalWrapper,
  useBuyLater,
  useExceptionToast,
  useFetchSubscriptionCmsContent,
  useFeatureFlag,
} from '../../common';
import { ItemsUnavailable } from '../cart-total/items-unavailable/ItemsUnavailable';
import { ItemsRemovedModal } from '../items-removed-modal/ItemsRemovedModal';
import { CartLineItemErrorMessages } from '../cartLineItem-error-msgs/CartLineItemErrorMessages';
import { AddProductsFromList } from '../lists/components/add-products-from-list/AddProductsFromList';
import { createDataObject } from '../../utils';
import { ErrorActionType } from '../../common/types/enums';
import GCOList from '../gco-list/GCOList';
import { useCartLoaderEvents } from '../../common/hooks/useCartLoaderEvents';
//import { useRemoveInvalidProducts } from '../../common/hooks/useRemoveInvalidProducts';
import { KitTermsAndConditions } from './kitTermsAndConditions/KitTermsAndConditions';
import styles from './CartLineItems.module.scss';
import { INFINITE_SHIPMENTS, UNLIMITED_MONTH_CYCLE } from './types/enum';
import { CartLineItemsFooter } from './cart-line-items-footer/CartLineItemsFooter';
import { SOPVariantDrawer } from './sop-variant-drawer/SOPVariantDrawer';
import { RenderAuxiliaryProducts } from './renderAuxiliaryProducts/RenderAuxiliaryProducts';
import { SopItemErrorMsgs } from './sop-items-error-msgs/SopItemErrorMsgs';
interface CartLineItemsProps {
  data: Cart;
  clickedShowCart: (arg: string) => void;
  displayGCO: boolean;
  isMainUserCart: boolean;
  cartDetailsPage?: boolean;
  removeEntry: (entryId: number, entryIdArray?: number[], isInvalid?: boolean) => Promise<void>;
  onEntryRemove: (entry: CartEntryDetails) => Promise<void>;
  showCompensatedModal: boolean;
  setShowCompensatedModal: React.Dispatch<React.SetStateAction<boolean>>;
}

export const CartLineItems = (props: CartLineItemsProps) => {
  const {
    data,
    clickedShowCart,
    displayGCO,
    isMainUserCart,
    cartDetailsPage,
    removeEntry,
    onEntryRemove,
    showCompensatedModal,
    setShowCompensatedModal,
  } = props;
  const t = useTranslation();
  const currentlyUnavailableText = t('cart.errorMessages.currentlyUnavailble');
  const cartPromoNotEligibleText = t('cart.errorMessages.cartPromotions');
  const showInstalmentAvailableText = t('cart.cartLineitems.instalmentsAvailable');
  const [regDetailsLost, setRegDetailsLost] = useState(false);
  const { buyLater, changeToStandardOrder } = useBuyLater();

  const { isABO, isAnonymous } = useSession();
  const dispatch = useDispatch<AppDispatch>();

  const { showPromotionLoadings } = useCartLoaderEvents();
  const router = useNextgenRouter();
  const [removeEntryId, setRemoveEntryId] = useState<number[]>([]);
  const triggerOnlyEKitToast = useExceptionToast({
    theme: CartNotificationTheme.PURPLE,
    content: t('cart.cartLineItems.eligibleForEKit'),
    subtext: t('cart.cartLineItems.AcceptTAndC'),
    icon: 'bolt',
  });

  const cartId = router.params?.cartId ?? '';

  const mainSubCart = getActiveCart(data, cartId as string);
  const { entries: cartEntries, sopMetaData } = mainSubCart;
  const showTermsAndConditions = getEKitTermsAndConditionsConfig();
  const enableRenewalLateFeeOnly = getRenewalLateFeeOnlyConfig();

  const { showProxyConsentFlag, hideSilentPromoFlag } = useFeatureFlag();

  const sopCMSData = useFetchSubscriptionCmsContent(sopMetaData || []);
  const [openDrawerId, setOpenDrawerId] = useState<number | null>(null);
  const [cartEntryData, setCartEntryData] = useState<CartEntryDetails>();

  const shareCode = StorageService.getLocalStorage().retrieve(
    MyShopStorageConstant.SHARECODEATTRIBUTES,
  ) as AdvanceShareCodeResponse;

  const { withSOPEntry, withoutSOPEntry, withoutSOPAndFeeEntry } = getAllEntries(cartEntries as CartEntryDetails[]);
  const renderedEntries = enableRenewalLateFeeOnly ? withoutSOPEntry : withoutSOPAndFeeEntry; //country specific entries

  //useRemoveInvalidProducts(cartEntries, removeEntry);

  const regEntry = withoutSOPEntry?.find((entry) =>
    includesAny(entry, [AccountProductType.Ekit, AccountProductType.Pkit]),
  );

  const hideSelector = hideVariantSelector?.(data, regEntry as CartEntryDetails, withoutSOPEntry);
  const { defaultKitId } = getpkitAndeKitProductId(data?.accountProcess?.businessNature);

  const debouncedTriggerToast = useMemo(
    () =>
      nextgenDebounce(() => {
        triggerOnlyEKitToast();
      }, 500),
    [],
  );

  useEffect(() => {
    if (hideSelector && data.accountProcess?.type === AccountProcessType.Registration) {
      if (regEntry?.product?.id !== defaultKitId) {
        const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
        cartApi
          .updateCart(cartId, cartId, {
            accountProcess: {
              ...data.accountProcess,
              variantProduct: defaultKitId,
            },
            version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
          })
          .then((res) => {
            dispatch(updateIsCheckoutDisabled(true));
            dispatch(updateCart(res as Cart));
          });
      }
      if (data?.accountProcess?.businessNature === AccountType.BusinessOwner) {
        debouncedTriggerToast();
      }
    }
    return () => debouncedTriggerToast.cancel();
  }, [hideSelector]);

  useEffect(() => {
    const isSelfLedReg =
      isAnonymous() &&
      regEntry &&
      data?.accountProcess?.type === AccountProcessType.Registration &&
      Boolean(!shareCode);

    if (isSelfLedReg) {
      router.events?.setIsBackBlocked(true);

      router.events?.on('browserBackWarn', () => setRegDetailsLost(true));
      window.history.pushState(null, document.title, window.location.href);
    }
    return () => {
      if (isSelfLedReg) {
        router.events?.setIsBackBlocked(false);
        router.events?.off('browserBackWarn', () => setRegDetailsLost(true));
        window.history.replaceState(null, document.title, window.location.href);
      }
    };
  }, [regEntry]);

  const onSOPRemoveClickHandler = (receivedSOPId?: string, receivedEntryIds?: number[]) => {
    let updatedCount = 0;
    const hasCompensatedOrder = sopMetaData?.reduce((count, data) => {
      if (data.entryIds !== undefined && data.sopId === receivedSOPId) {
        setRemoveEntryId((prev) => [...prev, ...(data.entryIds as number[])]);
        updatedCount = count + 1;
      }
      return updatedCount;
    }, 0);

    if (hasCompensatedOrder && hasCompensatedOrder > 1) {
      setShowCompensatedModal(true);
    } else {
      removeEntry(0, receivedEntryIds);
    }
  };

  //will be removed as now for all entry we will show delete icon
  const showRemoveIconRenewal = (entry: CartEntryDetails) =>
    !includesAny(entry, [AccountProductType.Ekit, AccountProductType.Pkit, AccountProductType.LateFee]) ||
    (data.accountProcess?.type === AccountProcessType.Renewal &&
      (data.amwayUser.renewalFlag === RenewalFlag.CanRenew ||
        (data.amwayUser.renewalFlag === RenewalFlag.MustRenew && !forceAddRenewalProduct)));

  const allExceptions = exceptionsBasedOnActionType(
    (isGroupOrder(data.orderType) ? data.errors : mainSubCart.errors) ?? [],
    ErrorActionType.ShowPopup,
  );

  return (
    <div
      className={`${styles['commerce-cart-line-items-page']} ${
        !isMainUserCart ? 'commerce-cart-line-items-page-padding' : ''
      }`}
    >
      {showCompensatedModal && (
        <ItemsUnavailable
          notAvailableEntries={[]}
          isCompensatedModal
          onPrimaryBtnClick={() => removeEntry(0, removeEntryId)}
          onSecondaryBtnClick={() => setShowCompensatedModal(false)}
        />
      )}

      {!!allExceptions?.length && <ItemsRemovedModal cart={data} />}
      {/* GCOList Start */}
      {displayGCO && Object.keys(data).length > 0 && (
        <GCOList subCarts={(data.subCarts || []) as Cart[]} clickedShowCart={clickedShowCart} />
      )}
      {/* GCOList End */}
      {/* Cart line items */}

      {!displayGCO && cartEntries && cartEntries?.length != 0 && (
        <div className={styles['commerce-cart-line-item']}>
          {sopMetaData && sopMetaData?.length !== 0 && !enableSopSection() && (
            <div className={`${showProxyConsentFlag ? styles['commerce-cart-line-item-jp'] : ''}`}>
              {sopMetaData?.map((sopElement: SopElementResponse, index: number) => {
                const {
                  totalPrice,
                  elementSequence,
                  totalShipments,
                  images,
                  promotionResults,
                  totalPriceWithoutDiscount,
                  sopCode,
                  planCode,
                  enablePromotionTag,
                } = sopElement;
                const dataObjectFromEntry = createDataObject(
                  undefined,
                  totalPrice,
                  promotionResults,
                  isABO(),
                  hideBV(),
                  hideSilentPromoFlag,
                );

                const handleDropdown = (cartEntry: CartEntryDetails) => {
                  setOpenDrawerId((prevId) => (prevId === cartEntry.entryId ? null : cartEntry.entryId ?? null));
                  setCartEntryData(cartEntry);
                };
                const receivedSOPData = transformedSOPEntries(
                  withSOPEntry,
                  sopElement,
                  isABO(),
                  currentlyUnavailableText,
                  cartPromoNotEligibleText,
                  handleDropdown,
                );
                const isSingleSOPItem = receivedSOPData.sopProducts.length === 1;
                const receivedPlanName = getPlanName(planCode, sopCMSData);

                return (
                  <>
                    <div
                      key={sopElement.sopElementId}
                      className={`${styles['commerce-cart-line-item-product']} ${
                        showProxyConsentFlag && index === cartEntries.length - 1
                          ? styles['commerce-cart-line-item-product-jp-end']
                          : styles['commerce-cart-line-item-product-jp']
                      }`}
                    >
                      {openDrawerId && sopElement.entryIds?.includes(openDrawerId) && (
                        <SOPVariantDrawer
                          planCode={planCode}
                          entryData={cartEntryData as CartEntryDetails}
                          onCloseClick={() => setOpenDrawerId(null)}
                        />
                      )}
                      <ProductCartEntryComponentV2
                        version={showProxyConsentFlag ? ProductCartVersion.V3 : ProductCartVersion.V2}
                        onRemoveProduct={() => onSOPRemoveClickHandler(sopElement.sopId, sopElement.entryIds)}
                        showPropertiesCollection={{
                          showSubscriptionCard: !isSingleSOPItem,
                          showHeartIcon: isSingleSOPItem,
                          showQtyStepper: false,
                          showQuantityLabel: isSingleSOPItem,
                          showSubscriptionTag: true,
                          showRemoveIcon: true,
                          showCompensatedSOPTag: sopElement.isCompensated,
                          showInstallment: isSingleSOPItem && withSOPEntry[0].product.flags?.isInstallmentPlanEligible,
                          showPromotionTag:
                            enablePromotionTag || (isSingleSOPItem && receivedSOPData.sopProducts[0].showPromotionTag),
                        }}
                        data={{
                          ...dataObjectFromEntry,
                          productName: isSingleSOPItem
                            ? receivedSOPData.sopProducts[0].productName
                            : (receivedPlanName as string),
                          link: isSingleSOPItem
                            ? receivedSOPData.sopProducts[0].link
                            : (images?.[0]?.imageUrl as string),
                          mainLink: isSingleSOPItem
                            ? receivedSOPData.sopProducts[0].link
                            : (images?.[0]?.imageUrl as string),
                          alt: isSingleSOPItem ? receivedSOPData.sopProducts[0].alt : (images?.[0]?.altText as string),
                          firedPromotions: hidePromotionBanner()
                            ? []
                            : hideSilentPromoFlag
                            ? promosWhichAreNonSilent(promotionResults?.firedPromotions)
                            : promotionResults?.firedPromotions,
                          minOrder: elementSequence,
                          maxOrder: totalShipments === INFINITE_SHIPMENTS ? UNLIMITED_MONTH_CYCLE : totalShipments,
                          subscriptionId: sopCode,
                          strikethroughPrice: totalPriceWithoutDiscount?.value,
                          subscriptionProducts: receivedSOPData.sopProducts,
                          items: [],
                          ...(isSingleSOPItem && {
                            derivedAvailabilityStatus: receivedSOPData?.sopProducts[0]?.derivedAvailablityStatus,
                            firstAvailableFutureDate: receivedSOPData?.sopProducts[0]?.firstAvailableFutureDate,
                            showPrefix: false,
                            productType: receivedSOPData?.sopProducts[0]?.productType,
                            productQuantity: receivedSOPData?.sopProducts[0]?.quantity,
                            productId: receivedSOPData?.sopProducts[0]?.productId,
                            bundle: receivedSOPData?.sopProducts[0]?.bundle,
                            variantName: receivedSOPData?.sopProducts[0]?.variantName,
                            handleDropdown: receivedSOPData?.sopProducts[0]?.handleDropdown,
                            itemDisposition: receivedSOPData?.sopProducts[0].itemDisposition,
                            entryId: receivedSOPData?.sopProducts[0].entryId,
                          }),
                        }}
                      />
                      <SopItemErrorMsgs
                        sopElement={sopElement}
                        onSOPRemoveClickHandler={onSOPRemoveClickHandler}
                        classname={styles['cart-exceptionAlert']}
                        isSingleSOPItem={isSingleSOPItem}
                      />
                    </div>
                    {RenderAuxiliaryProducts(sopElement.sopElementId, withoutSOPEntry)}
                  </>
                );
              })}
            </div>
          )}
          {renderedEntries?.length > 0 && (
            <div className={`${showProxyConsentFlag ? styles['commerce-cart-line-item-jp'] : ''}`}>
              {renderedEntries?.map((entry: CartEntryDetails, index: number) => {
                const { product, promotionResults, totalPrice, rationingResult, bundleSlots } = entry;
                const { tags = [] } = product;
                const productTags = [...(tags ?? [])]
                  .sort((a, b) => a.priority - b.priority)
                  .slice(0, 3)
                  .map((tag) => {
                    const { tagTypeCode, label, userTypes } = tag;
                    const tagText = getTagLabel(
                      label,
                      '',
                      isUserTypeMatched(userTypes as unknown as Parameters<typeof isUserTypeMatched>[0]),
                    );
                    const isBundle = bundleSlots.length > 0;
                    const bundleCase = isBundle ? t('cart.cartLineitems.bundle') : '';
                    const theme = calculateThemeForJapan(
                      getTagLabel(
                        tagTypeCode,
                        bundleCase.toLocaleUpperCase(),
                        isUserTypeMatched(userTypes as unknown as Parameters<typeof isUserTypeMatched>[0]),
                      ),
                    );
                    return {
                      text: tagText,
                      style: TagStyle.OUTLINE,
                      theme,
                      id: tag.id,
                    };
                  });
                const dataObjectFromEntry = createDataObject(
                  product,
                  totalPrice,
                  promotionResults,
                  isABO(),
                  hideBV(),
                  hideSilentPromoFlag,
                );
                const { bundleEntries, childPromotions } = getBundleEntriesAndChildPromoitions(
                  entry,
                  currentlyUnavailableText,
                  cartPromoNotEligibleText,
                );
                const productStockstatus = getStockStatus(entry);

                const isBottomMsgPresent = bottomMsgPresent(promotionResults, productStockstatus);
                const hasShippingError =
                  isPickUpItemUnavailable(true, {}, entry) ||
                  isDeliveryItemUnavailable(true, {}, entry) ||
                  isThirdPartyPickUpUnavailable(true, {}, entry);

                const isAccountKitProduct = includesAny(entry, [
                  AccountProductType.Ekit,
                  AccountProductType.Pkit,
                  AccountProductType.LateFee,
                ]);

                return (
                  <>
                    {!entry.isFreeItem && !entry.partnerPromotionId && (
                      <>
                        <div
                          key={entry.entryId}
                          className={`
                ${styles['commerce-cart-line-item-product']} ${
                            showProxyConsentFlag
                              ? index === withoutSOPAndFeeEntry?.length - 1
                                ? styles['commerce-cart-line-item-product-jp-end']
                                : styles['commerce-cart-line-item-product-jp']
                              : index === withoutSOPAndFeeEntry?.length - 1
                              ? styles['commerce-cart-shipping-seperator-end']
                              : ''
                          }`}
                          data-testid="product-card-test-id"
                        >
                          {regDetailsLost && (
                            <ModalWrapper
                              headLineText={t('cart.cartLineitems.regDetailsLostHeading')}
                              description={t('cart.cartLineitems.regDetailsLostDesc')}
                              primaryButtonLabel={t('cart.cartLineitems.underStandAndGoBack')}
                              secondaryButtonLabel={t('cart.groupOrder.button.cancel')}
                              onPrimarySuccess={() => {
                                router.push(CartRoutePaths.SELF_LED_REGISTRAION);
                              }}
                              onSecondarySuccess={() => setRegDetailsLost(false)}
                            />
                          )}

                          <ProductCartEntryComponentV2
                            version={showProxyConsentFlag ? ProductCartVersion.V3 : ProductCartVersion.V2}
                            key={createProductEntryKey(entry, mainSubCart.amwayUser)}
                            onRemoveProduct={() => onEntryRemove(entry)}
                            onBuyLaterClick={() => {
                              buyLater(entry);
                              onEntryRemove(entry);
                            }}
                            showPropertiesCollection={{
                              showHeartIcon: !isAnonymous() && !isAccountKitProduct,
                              showRemoveIcon: showRemoveIconRenewal(entry),
                              showQtyStepper: !isAccountKitProduct,
                              showPVBV: !isAccountKitProduct && totalPrice?.value !== 0,
                              showStockStatus: !isAccountKitProduct,
                              showItemId: !isAccountKitProduct,
                              showInstallment:
                                product.flags?.isInstallmentPlanEligible &&
                                data.orderType === OrderType.Regular &&
                                !hideInstalmentBanner(),
                              showPriceLabel: !isAccountKitProduct,
                              showPromotionTag: entry?.enablePromotionTag,
                              showInstalmentTag: product.flags?.isInstallmentPlanEligible,
                              showInstalmentTagText: showInstalmentAvailableText,
                              //showApointTag: entry?.isAmpointRedeem,
                              showCartInventoryUpdate: !!getErrorFromEntryOrSubCart(entry),
                              showPromotionLoader: showPromotionLoadings[entry.entryId as number],
                            }}
                            tags={productTags}
                            data={{
                              ...dataObjectFromEntry,
                              productName: product.name ?? '',
                              items: [],
                              link: product.cartIconPublicUrl ?? '',
                              mainLink: product.cartIconPublicUrl ?? '',
                              alt: product.cartIconAltText as string,
                              disabled: rationingResult?.[0]?.availableQuantity === 0,
                              variantName: hideVariantSelector?.(data, entry, withoutSOPEntry)
                                ? ''
                                : getVariantName(product.variantDimensions as VariantDimensions[]),
                              bundle: bundleEntries,
                              strikethroughPrice: getStrikeThroughPrice(entry),
                              firedPromotions: hidePromotionBanner()
                                ? []
                                : getUniqueFiredPromotionsExceptCoupons([
                                    ...(promotionResults?.firedPromotions ?? []),
                                    ...childPromotions,
                                  ]),
                              derivedAvailabilityStatus:
                                !entry.errors?.length ||
                                isExceptionExist(ExceptionsEnum.Exceptions.ProductOutOfStock, entry.errors) ||
                                isExceptionExist(ExceptionsEnum.Exceptions.ProductNaw, entry.errors)
                                  ? productStockstatus
                                  : '',
                              firstAvailableFutureDate:
                                product.firstAvailableFutureDate && String(product.firstAvailableFutureDate),
                              showPrefix: false, // to hide available on prefix from BO
                              showSubText: true, // to show subtext but priority will be given to firstAvailableFutureDate
                              entryId: entry?.entryId,
                              productType: product.type,
                              restrictFromPdpDisplay: isAccountKitProduct || isSellableCheck(product),
                            }}
                            showBuyLater={false}
                            showSOPBenefits={showProxyConsentFlag && entry?.isSopPurchasable}
                            changeToSOPCTA={<ChangeToSOPButton subCartData={mainSubCart} />}
                            sopBenefitLink={<SOPBenefitLink productId={entry.product.id} />}
                          />

                          <CartLineItemErrorMessages
                            data={data}
                            entry={entry}
                            removeRationingItemCB={removeEntry}
                            bottomMsgPresent={isBottomMsgPresent}
                            hasShippingError={hasShippingError}
                          />
                          {includesAny(entry, [AccountProductType.Ekit]) && showTermsAndConditions && (
                            <KitTermsAndConditions />
                          )}
                        </div>
                        {RenderAuxiliaryProducts(String(entry?.entryId), withoutSOPEntry)}
                      </>
                    )}
                  </>
                );
              })}
            </div>
          )}
          {enableSopSection() && !!sopMetaData?.length && (
            <>
              {showProxyConsentFlag && withoutSOPAndFeeEntry?.length > 0 && (
                <div className={styles['commerce-cart-line-item-SOP-seperator']}></div>
              )}
              <SOPCartContainer
                subCartData={mainSubCart}
                onRemoveProduct={(entry) => onEntryRemove(entry)}
                onStandardOrderClick={(entry) => changeToStandardOrder(entry)}
                onBuyLaterClick={(entry) => {
                  buyLater(entry, mainSubCart?.sopMetaData);
                  removeEntry(0, [entry.entryId]);
                }}
              />
            </>
          )}
          <CartLineItemsFooter cartDetailsPage={cartDetailsPage} cartData={data} />
          <AddProductsFromList />
        </div>
      )}
    </div>
  );
};

export type { CartLineItemsProps };
