import { AlertMessage, Theme, useNextgenRouter, useTranslation } from '@nextgen-web-framework/all';
import {
  type Cart,
  CartConstantsEnum,
  type CartEntryDetails,
  CartEventsEnum,
  cartApi,
  getActiveCart,
  updateCart,
  Frequency,
  isExceptionExist,
  ExceptionsEnum,
  CartEvents,
  DeliveryType,
} from '@commerce-cart-webcomponents/sdk';
import { StorageService, type AppDispatch } from '@nextgen-web-framework/core';
import { useDispatch } from 'react-redux';
import { ProductFlag } from '../product-flag/ProductFlag';
import styles from './CartLineItemErrorMessages.module.scss';

export type CartLineItemErrorMessagesProps = {
  data: Cart;
  entry: CartEntryDetails;
  removeRationingItemCB: (entryId: number) => void;
  bottomMsgPresent?: boolean;
  hasShippingError?: boolean;
};
const CartLineItemErrorMessages = ({
  data,
  entry,
  removeRationingItemCB,
  bottomMsgPresent,
  hasShippingError,
}: CartLineItemErrorMessagesProps) => {
  const { rationingResult } = entry;
  const availableQty = rationingResult?.[0]?.availableQuantity;
  const t = useTranslation();

  const router = useNextgenRouter();
  const dispatch = useDispatch<AppDispatch>();

  const cartId = router.params?.cartId ?? '';
  const mainSubCart = getActiveCart(data, cartId as string);

  const bundleRemoveException = isExceptionExist(
    ExceptionsEnum.Exceptions.BundleRationingExceedRemove,
    entry.errors ?? [],
  );
  const bundleUpdateException = isExceptionExist(
    ExceptionsEnum.Exceptions.BundleRationingExceedUpdate,
    entry.errors ?? [],
  );
  const pleException = isExceptionExist(ExceptionsEnum.Exceptions.RationingPurchaseLimitExceed, entry.errors ?? []);
  const pleExceptionRemove = isExceptionExist(
    ExceptionsEnum.Exceptions.RationingPurchaseLimitExceedRemove,
    entry.errors ?? [],
  );
  const limitExceedException = isExceptionExist(ExceptionsEnum.Exceptions.RationingLimitExceed, entry.errors ?? []);

  const updateRationingItemCB = (entry: CartEntryDetails) => {
    // cart count will be available quantity for that product
    const payload = {
      entry: {
        entryId: entry.entryId,
        product: {
          id: entry.product.id,
        },
        quantity: entry.rationingResult?.[0]?.availableQuantity as number,
        bundleSlots: entry?.bundleSlots?.map((slot) => ({
          ...slot,
          entries: slot.entries.map((data) => ({
            ...data,
            quantity: data.quantity / entry.quantity,
          })),
        })),
      },
      version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
    };
    cartApi
      .changeQtyForEntryFromCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: mainSubCart?.subCartId,
        entryId: entry.entryId,
        payload,
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart: res,
            cartId: (res as Cart).id,
          },
        });
      });
  };

  const frequency = rationingResult?.[0]?.frequency;

  const rationingHeading = t('cart.cartLineItem.remainingLimit')
    .replace(/{{frequency}}/g, frequency === Frequency.Lifetime ? '' : t(`cart.cartLineItem.frequency.${frequency}`))
    .replace(/{{availableQuantity}}/g, String(availableQty));

  const purchaseLimitExceeded = t('cart.cartLineItem.purchaseLimit');

  const remainingLimit = t('cart.cartLineItem.remLimit').replace(/{{availableQuantity}}/g, String(availableQty));

  const errorHeading = (() => {
    if (
      bundleRemoveException ||
      bundleUpdateException ||
      pleExceptionRemove ||
      (pleException && entry.bundleSlots.length > 0)
    ) {
      return purchaseLimitExceeded;
    } else if (pleException) {
      return remainingLimit;
    } else {
      return rationingHeading;
    }
  })();

  const showAlertErrorMsg = (heading: string, textLinkText: string, onTextLinkClick?: () => void) => (
    <div className={`${styles['lineItem-bottom-msg']} ${bottomMsgPresent && styles['adjust-padding']}`}>
      <div className={styles['cart-exceptionAlert']}>
        <AlertMessage
          theme={Theme.ERROR}
          icon={'exclamation-square'}
          content={{
            heading: heading,
          }}
          textLink={{
            text: textLinkText,
            onClick: onTextLinkClick,
          }}
        />
      </div>
    </div>
  );

  return (
    <>
      {(limitExceedException || pleException || bundleRemoveException || bundleUpdateException || pleExceptionRemove) &&
        !hasShippingError &&
        showAlertErrorMsg(
          errorHeading,
          (() => {
            if (bundleUpdateException || (limitExceedException && availableQty)) {
              return t('cart.errorMsgs.updateRationingItem');
            } else if (
              limitExceedException ||
              bundleRemoveException ||
              pleExceptionRemove ||
              (pleException && availableQty < 1)
            ) {
              return t('cart.errorMsgs.removeRationingItem');
            } else {
              return '';
            }
          })(),
          () => {
            if (bundleUpdateException || (limitExceedException && availableQty) || (pleException && availableQty)) {
              updateRationingItemCB(entry);
            } else if (
              limitExceedException ||
              bundleRemoveException ||
              pleExceptionRemove ||
              (pleException && availableQty < 1)
            ) {
              removeRationingItemCB(entry.entryId as number);
            }
          },
        )}
      {isExceptionExist(DeliveryType.Bopis, entry.errors ?? []) &&
        showAlertErrorMsg(t('cart.cartLineItemsHeader.noPickUp'), t('cart.cartLineItemErrorMsgs.remove'), () => {
          removeRationingItemCB(entry.entryId as number);
        })}

      {isExceptionExist(DeliveryType.Homedelivery, entry.errors ?? []) &&
        showAlertErrorMsg(t('cart.cartLineItemsHeader.noHomedelivery'), t('cart.cartLineItemErrorMsgs.remove'), () => {
          removeRationingItemCB(entry.entryId as number);
        })}

      {(isExceptionExist(DeliveryType.Kerry, entry.errors ?? []) ||
        isExceptionExist(DeliveryType.Seveneleven, entry.errors ?? [])) &&
        showAlertErrorMsg(
          t('cart.cartLineItemsHeader.no3rdPartyPickup'),
          t('cart.cartLineItemErrorMsgs.remove'),
          () => {
            removeRationingItemCB(entry.entryId as number);
          },
        )}
      {isExceptionExist(ExceptionsEnum.Exceptions.Restricted, entry.errors ?? []) &&
        showAlertErrorMsg(t('cart.errorMessages.currentlyUnavailble'), t('cart.cartLineItemErrorMsgs.remove'), () => {
          removeRationingItemCB(entry.entryId as number);
        })}
      {isExceptionExist(ExceptionsEnum.Exceptions.PurchaseRestriction, entry.errors ?? []) &&
        showAlertErrorMsg(
          t('cart.errorMessages.userSegmentRestriction'),
          t('cart.cartLineItemErrorMsgs.remove'),
          () => {
            removeRationingItemCB(entry.entryId as number);
          },
        )}
      {isExceptionExist(ExceptionsEnum.Exceptions.CartLevelPromotion, entry.errors ?? []) && (
        <ProductFlag iconName="tags" text={t('cart.errorMessages.cartPromotions')} theme={Theme.GRAY} />
      )}
    </>
  );
};

export { CartLineItemErrorMessages };
