import { useState } from 'react';
import { FAIcon, InputTypes } from '@nextgen-web-framework/all';
import { getMaxProductQty } from '@commerce-cart-webcomponents/sdk';
import { AddToCartButton } from '../add-to-cart-button/AddToCartButton';
import { AddToCartWithStepperProps } from './types/propsType';
import { MAX_COUNT, MIN_COUNT } from './types/enums';
import styles from './AddToCartWithStepper.module.scss';

export const AddToCartWithStepper = ({
  entryObj,
  showRightIcon = false,
  closeDrawer = () => null,
  onProductAdded = () => null,
  miniusButtonDisabled,
  plusButtonDisabled,
  onQuantityChange = () => null,
  overrideClassName = '',
  addToCartButtonDisable,
  disableQtyStepper = false,
  size,
  isMinProjection = false,
}: AddToCartWithStepperProps) => {
  const [count, setCount] = useState(1);
  const [active, setActive] = useState(false);
  const maxProductCount = getMaxProductQty();

  const disablePlusIcon = count === MAX_COUNT;
  const disableMinusIcon = count === MIN_COUNT;

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    if (!e.target.validity.valid) {
      return;
    }
    setCount(+e.target.value);
    onQuantityChange(+e.target.value);
  }

  function handleBlur(e: React.FocusEvent<HTMLInputElement, Element>) {
    if (+e.target.value == 0) {
      setCount(1);
    }
    setActive(false);
  }

  const increaseCount = () => !plusButtonDisabled && count !== MAX_COUNT && setCount((num) => num + 1);
  const decreaseCount = () => count !== MIN_COUNT && !miniusButtonDisabled && setCount((num) => num - 1);

  return (
    <div className={`${styles['add-to-cart-stepper-component']} ${overrideClassName}`}>
      <div
        className={`${styles['add-to-cart-stepper-container']} ${
          disableQtyStepper && styles['add-to-cart-stepper-container-disabled']
        }`}
      >
        {!active && (
          <span
            role="button"
            tabIndex={0}
            aria-label="minus"
            data-testid="test-minus-button"
            onClick={decreaseCount}
            onKeyDown={decreaseCount}
            className={`${styles['add-to-cart-stepper-container-icon']} ${styles['add-to-cart-stepper-container-icon-minus']}`}
          >
            <FAIcon
              className={`${(miniusButtonDisabled || disableMinusIcon) && styles['disable-icon']}`}
              iconName="minus"
            />
          </span>
        )}
        <input
          disabled={disableQtyStepper}
          min={1}
          readOnly={plusButtonDisabled || miniusButtonDisabled ? true : false}
          maxLength={String(maxProductCount).length}
          name="inputQty"
          aria-label="inputQty"
          type={InputTypes.TEXT}
          pattern="[1-9]?[0-9]{1,2}"
          onChange={handleChange}
          className={styles['add-to-cart-stepper-container-count']}
          value={count}
          onClick={() => setActive(!(miniusButtonDisabled || plusButtonDisabled) as boolean)}
          onBlur={handleBlur}
        />
        {!active && (
          <span
            role="button"
            tabIndex={0}
            aria-label="plus"
            onKeyDown={increaseCount}
            data-testid="test-plus-button"
            onClick={increaseCount}
            className={`${styles['add-to-cart-stepper-container-icon']} ${styles['add-to-cart-stepper-container-icon-plus']}`}
          >
            <FAIcon
              className={`${(plusButtonDisabled || disablePlusIcon) && styles['disable-icon']}`}
              iconName="plus"
            />
          </span>
        )}
      </div>
      <div className={styles['add-width']}>
        <AddToCartButton
          size={size}
          disabled={addToCartButtonDisable}
          onProductAdded={(...args) => {
            onProductAdded(...args);
            setCount(1);
          }}
          closeDrawer={closeDrawer}
          showRightIcon={showRightIcon}
          entryObj={{ ...entryObj, quantity: count }}
          isMinProjection={isMinProjection}
        />
      </div>
    </div>
  );
};
export type { AddToCartWithStepperProps };
