import {
  type InitialCartState,
  getActiveCart,
  isMainCart,
  OrderType,
  AmwayUserDetails,
  updateCart,
  switchCart,
  isGroupOrder,
  isProxyOrder,
  SWITCH_PROXY_TYPE,
  switchOrOverrideCart,
  Cart,
  PublishEvent,
  CartEventsEnum,
  switchCartNewStrategy,
  updateAddressAfterCartSwitch,
} from '@commerce-cart-webcomponents/sdk';
import { useTranslation, useNextgenRouter, FAIcon } from '@nextgen-web-framework/all';
import { useSelector, useDispatch } from 'react-redux';
import { type AppState } from '@nextgen-web-framework/core';
import { useState } from 'react';
import { useAddressUpdate } from '@commerce-webcomponents/ui';
import { FrameRectangle } from '../../common/components/cart-loader/frame-rectangle/FrameRectangle';
import { CartEllipsisMenu } from '../cart-ellipsis-menu/CartEllipsisMenu';
import { CartNotificationTheme, TOAST_TIMEOUT, useCartNotification, useFeatureFlag } from '../../common';
import { AccountSearchDrawer } from '../../common/components';
import styles from './CartMobileHeader.module.scss';

export type CartMobileHeaderProps = {
  isScrolled?: boolean;
  isGCOList?: boolean;
  isListDrawer?: boolean;
};
//a
const CartMobileHeader = ({ isScrolled = false, isGCOList = false, isListDrawer }: CartMobileHeaderProps) => {
  const t = useTranslation();
  const { showProxyConsentFlag, cartOverrideFlag, newAddressApiFlag } = useFeatureFlag();
  const { updateAddress } = useAddressUpdate();
  const router = useNextgenRouter();
  const cartId = router.params?.cartId ?? '';
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const dispatch = useDispatch();
  const [showAccountSearch, setShowAccountSearch] = useState(false);
  const [selectedProfile, setSelectedProfile] = useState<AmwayUserDetails>();
  const { isLoading, cart }: InitialCartState = commerceCartState;
  const activeCart = getActiveCart(cart, String(cartId));
  const cartForCount = cartId || cart.orderType !== OrderType.Gco ? activeCart : cart;
  const { createToast, deleteToast } = useCartNotification('cartTypeSelectionDrawer');

  const searchDrawerHeaderTitle = t('cart.cartTypeSelectionDrawer.drawerHeader');
  const inputPlaceHolderText = t('cart.cartTypeSelectionDrawer.inputPlaceHolder');
  const primaryButtonText = t('cart.cartTypeSelectionDrawer.primaryButtonText');
  const secondaryButtonText = t('cart.cartTypeSelectionDrawer.secondaryButtonText');
  const subHeadingText = t('cart.cartTypeSelectionDrawer.subHeading');
  const cartChanged = t('cart.cartTypeSelectionDrawer.cartChanged');
  const cartChangedHeading = t('cart.cartTypeSelectionDrawer.cartChangedHeading');
  const totalCartItems = !isGCOList
    ? cartForCount?.totalEntries
    : cart.subCarts.reduce((acc, item) => acc + (item.totalEntries ?? 0), 0);

  const showSuccessNotification = () =>
    createToast(
      {
        theme: CartNotificationTheme.SUCCESS,
        rightSeperator: false,
        content: cartChangedHeading,
        subtext: cartChanged,
        clickIcon: 'times',
        icon: 'check-circle',
        timeOut: TOAST_TIMEOUT,
      },
      deleteToast,
    );

  const showCartHeaderGCO = () => {
    if (!isMainCart(activeCart?.subCartId)) {
      return `${activeCart?.amwayUser?.firstName ?? ''} ${activeCart?.amwayUser?.lastName ?? ''} (${
        activeCart?.amwayUser?.accountId
      })`;
    }

    if (isGCOList) {
      return t('cart.cartLineitems.carts');
    } else {
      return t('cart.cartLineitems.cartTotalText');
    }
  };

  const showCartType = () => {
    const { primaryName = '' } = activeCart?.amwayUser || {};
    const placeHolder = 'DownLine';
    const showPlaceHolder = !primaryName;
    switch (cart.orderType) {
      case OrderType.Regular:
        return t('cart.cartLineitems.cartTotalText');
      case OrderType.Proxy:
        if (showProxyConsentFlag) {
          return t('cart.cartLineitems.cartText');
        }
        return (
          <div className={styles['downline-header']}>
            <div className={styles['downline-header-name']}>
              {primaryName} {showPlaceHolder && placeHolder}
            </div>
            <FAIcon
              className={styles['downline-header-icon']}
              onClick={() => setShowAccountSearch(true)}
              iconName="chevron-down"
            />
          </div>
        );
      case OrderType.Gco:
        return showCartHeaderGCO();
      default:
        return '';
    }
  };

  const showMutipleOrSingleText = (multipleText: string, singularText: string) => {
    const multipleItems = Number(totalCartItems) > 1;

    return multipleItems ? multipleText : singularText;
  };

  const getLabelGCO = (multipleItems: boolean) => {
    const multipleCarts = cart.subCarts.length > 1;
    if (cartId) {
      return multipleItems ? 'cart.cartMobileHeader.pluralItems' : 'cart.cartMobileHeader.items';
    }

    if (multipleCarts && multipleItems) {
      return 'cart.cartMobileHeader.pluralItemInCarts';
    }

    if (multipleCarts) {
      return 'cart.cartMobileHeader.pluralItemsInCart';
    }

    return multipleItems ? 'cart.cartMobileHeader.pluralItemInCart' : 'cart.cartMobileHeader.itemInCart';
  };

  const itemsCountInCartLabel = () => {
    let baseText = '';
    const multipleItems = Number(totalCartItems) > 1;
    if (isGroupOrder(cart.orderType)) {
      baseText = getLabelGCO(multipleItems);
    } else if (isProxyOrder(cart.orderType)) {
      const text = showMutipleOrSingleText(
        t('cart.cartMobileHeader.pluralListItems'),
        t('cart.cartMobileHeader.listItems'),
      );
      const itemCountText = text.replace(/{{itemCount}}/g, String(activeCart.totalEntries));

      return (
        <>
          {showProxyConsentFlag ? (
            <>({itemCountText})</>
          ) : (
            <>
              ({activeCart?.amwayUser?.accountId}{' '}
              <span className={styles['commerce-header-total-count-seperator']}>•</span> {itemCountText})
            </>
          )}
        </>
      );
    } else {
      baseText = showMutipleOrSingleText('cart.cartMobileHeader.pluralItems', 'cart.cartMobileHeader.items');
    }

    if (isListDrawer) {
      baseText = showMutipleOrSingleText('cart.cartMobileHeader.pluralListItems', 'cart.cartMobileHeader.listItems');
    }
    return t(baseText)
      .replace(/{{itemCount}}/g, String(totalCartItems ?? 0))
      .replace(/{{cartCount}}/g, String(cart?.subCarts?.length));
  };

  const headerClassName = () => {
    if (isScrolled) {
      return styles['commerce-header-total-text-scrolled'];
    } else if (isListDrawer) {
      return styles['commerce-header-total-text-listDrawer'];
    } else {
      return styles['commerce-header-total-text'];
    }
  };

  const backButton = (onClick: () => void, className = '') => (
    <div role="presentation" className={`${className}`} onClick={onClick} data-testId={'back-icon'}>
      <FAIcon iconName="chevron-left" />
    </div>
  );

  const showEllipsisMenu = () =>
    !isGCOList &&
    cart.orderType === OrderType.Gco &&
    activeCart?.entries?.length === 0 &&
    activeCart.subCartId !== cart.id;

  //for new subcarts
  const handleSecondaryButtonClick = async (profile: AmwayUserDetails) => {
    if (cartOverrideFlag && !switchCartNewStrategy()) {
      handleModalClick(SWITCH_PROXY_TYPE.OVERRIDE, profile);
      return;
    }
    setSelectedProfile(profile);
    const res = await switchCart(cart, OrderType.Proxy, profile);
    dispatch(updateCart(res));
    setShowAccountSearch(false);
    showSuccessNotification();
  };

  //for recent carts
  const handleModalClick = async (switchCartType?: SWITCH_PROXY_TYPE, profile?: AmwayUserDetails) => {
    const previousOrderType = cart.orderType;
    const res = (await switchOrOverrideCart(
      getActiveCart(cart),
      (profile ?? selectedProfile) as AmwayUserDetails,
      switchCartType as SWITCH_PROXY_TYPE,
    )) as Cart;
    setShowAccountSearch(false);
    dispatch(updateCart(res));
    const proxyCart = getActiveCart(res);
    await updateAddressAfterCartSwitch(proxyCart, cart, previousOrderType, newAddressApiFlag, updateAddress);
    // const addressRes = await updateShippingAddressInLS(
    //   proxyCart.amwayUser?.amwayUserId as string,
    //   proxyCart.amwayUser?.accountId as string,
    // );
    // if (isProxyOrder(previousOrderType) && (addressRes === null || !addressRes?.shippingAddresses.length)) {
    //   //If api return empty res or fails while switching to proxy revert back to main user default address.
    //   await updateShippingAddressInLS(cart.amwayUser?.amwayUserId, cart.amwayUser?.accountId as string);
    // }
    // updateAddress();
    PublishEvent({
      cartEvent: CartEventsEnum.UpdateMiniCartIcon,
      cart: res,
    });
    showSuccessNotification();
  };

  return (
    <>
      {showAccountSearch && (
        <AccountSearchDrawer
          modalConfirmClick={handleModalClick}
          showSwitchModal={true}
          showDisableCards={true}
          drawerHeaderTitle={searchDrawerHeaderTitle}
          placeHolderText={inputPlaceHolderText}
          primaryButtonText={primaryButtonText}
          secondaryButtonText={secondaryButtonText}
          subHeading={subHeadingText}
          showActiveCart={true}
          onRadioChange={handleSecondaryButtonClick}
          onPrimaryButtonClick={() => setShowAccountSearch(false)}
          cartData={cart}
          onClose={() => setShowAccountSearch(false)}
        />
      )}
      {isLoading ? (
        <FrameRectangle width="146" height="48" borderRadius="8" />
      ) : (
        <div className={`${styles['commerce-header-total-sec']} ${cartId ? styles['child-cart'] : ''}`}>
          <div className={`${styles['commerce-header-total']} ${cartId ? styles['child-cart'] : ''}`}>
            {cartId ? backButton(() => router.back(), styles['commerce-header-back']) : ''}
            <div className={styles['commerce-header-back-with-title']}>
              {!cartId && backButton(() => router.back(), styles['hide-desktop'])}
              <div>
                <div
                  className={`${headerClassName()}
          ${!isMainCart(activeCart?.subCartId) && styles['commerce-header-total-subcart-text']}
          `}
                  data-testid="cart-title-test-id"
                >
                  {showCartType()}
                </div>

                <div className={styles['commerce-header-total-count']}>{itemsCountInCartLabel()}</div>
              </div>
            </div>
          </div>
          {showEllipsisMenu() && (
            <div className={styles['commerce-header-ellipsis-wrapper']}>
              <CartEllipsisMenu currentCartId={activeCart?.subCartId} />
            </div>
          )}
        </div>
      )}
    </>
  );
};

export { CartMobileHeader };
