export const monthNames = [
  'January',
  'February',
  'March',
  'April',
  'May',
  'June',
  'July',
  'August',
  'September',
  'October',
  'November',
  'December',
];
export const formatPromoDate = (date: string | Date) => {
  const dateAtt = new Date(date);
  let dateStr = '';
  if (new Date(dateAtt).setHours(0, 0, 0, 0) == new Date().setHours(0, 0, 0, 0)) {
    return true;
  }
  dateStr += monthNames[dateAtt.getMonth()];
  dateStr += ' ';
  dateStr += String(dateAtt.getDate());
  dateStr += ', ';
  dateStr += String(dateAtt.getFullYear());
  return dateStr;
};

