export const isExpiredInCurrentMonth = (expiryDate: string) => {
  if (!expiryDate) {
    return false;
  }
  const date = new Date();
  const currentDate = formatDate(date.toString(), DateFormats.SHORT_DATE, 'en' as string);
  const expiredDate = formatDate(expiryDate?.toString(), DateFormats.SHORT_DATE, 'en' as string);
  const newCurrentDate = new Date(currentDate);
  const newExpiredDate = new Date(expiredDate);
  const isCurrentMonth =
    newCurrentDate?.getMonth() === newExpiredDate?.getMonth() &&
    newCurrentDate?.getFullYear() === newExpiredDate?.getFullYear();
  return isCurrentMonth;
};

export const isExceptionExist = (
  exceptionName: Exceptions | DeliveryType,
  errors: ErrorResponse[],
  getException = false,
) => {
  const exception = errors?.find(({ title, code }) => title === exceptionName || code === exceptionName);
  return getException ? exception : Boolean(exception);
};

export const getAllExceptionWithSeverity = (
  exceptionNames: Exceptions[],
  exceptionSeverity: Severity,
  errors: ErrorResponse[],
) =>
  errors?.filter(
    ({ severity, title }) => severity === exceptionSeverity && exceptionNames.includes(title as Exceptions),
  );

export const isMainCart = (currentCartId?: string) => {
  if (typeof window !== 'undefined' && window.localStorage) {
    const SubCartID = currentCartId || StorageService.getLocalStorage().retrieve(CartConstantsEnum.SubCartID);
    return StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId) === SubCartID;
  }
  return false;
};

export const exceptionsBasedOnActionType = (errors: ErrorResponse[], actionType: string) => {
  if (errors.length === 0) {
    return null;
  } else {
    const filteredErrors = errors.filter((error) => error.actionType === actionType);
    if (filteredErrors.length === 0) {
      return null;
    } else {
      return filteredErrors;
    }
  }
};

export const getActiveCart = (cart: Cart, queryParamCartId = '') => {
  const toSearchId = queryParamCartId ? queryParamCartId : cart.id;
  if (cart.orderType === OrderType.Gco) {
    return (
      cart?.subCarts?.find((subCart) => subCart.subCartId === decodeURIComponent(toSearchId)) ?? cart?.subCarts?.[0]
    );
  }

  return cart?.subCarts?.[0];
};

