export const isGroupOrder = (orderType: string) => orderType === OrderType.Gco;
export const isProxyOrder = (orderType: string) => orderType === OrderType.Proxy;
export const isRegularOrder = (orderType: string) => orderType === OrderType.Regular;

export const createEmptyCart = async (skipLSUpdate = false) => {
  const options: CartReqOtherOptions = skipLSUpdate
    ? {
        skipCartIdStoreInLS: true,
        skipCartResStoreInLS: true,
        skipVersionStoreInLS: true,
        skipIsGroupCartStoreInLS: true,
      }
    : {};
  const payload = {
    orderType: OrderType.Regular,
    subCarts: [
      {
        entries: [],
      },
    ],
  };
  const res = (await cartApi.createCart({
    payload,
    options,
  })) as Cart;
  if (!skipLSUpdate) {
    StorageService.getLocalStorage().store(CartConstantsEnum.CartId, res.id);
    StorageService.getLocalStorage().store(CartConstantsEnum.CartReqVersion, res.version);
  }

  return res;
};

export const switchCartV2 = async (
  incomingOrderType: OrderType,
  incomingAmwayUserDetails: AmwayUserDetails,
  cartData?: Cart,
) => {
  let cart = cartData;
  const cartIdFromLS = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  let mainCartId = cartIdFromLS;
  if (!cartIdFromLS) {
    cart = await createOrFetchCart();
    mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  }

  const currentCartVersion = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);
  const currentOrderType = cart?.orderType as string;

  switch (true) {
    case isRegularOrder(currentOrderType) && isProxyOrder(incomingOrderType): {
      const entriesFromMainCart = cartData?.subCarts?.[0]?.entries ?? [];
      const { withoutSOPEntry } = getAllEntries(entriesFromMainCart);
      return cartApi.createSubCart({
        cartId: mainCartId,
        payload: {
          amwayUser: incomingAmwayUserDetails,
          entries: validateBundleInEntries(withoutSOPEntry),
          orderType: incomingOrderType,
          version: +currentCartVersion,
        },
      }) as Promise<Cart>;
    }
    case isProxyOrder(currentOrderType) && isProxyOrder(incomingOrderType): {
      const currentActiveProxyCart = getActiveCart(cartData as Cart);
      return cartApi.reassignCart({
        cartId: mainCartId,
        subCartId: currentActiveProxyCart.subCartId,
        payload: {
          amwayUser: incomingAmwayUserDetails,
          orderType: OrderType.Proxy,
          version: +currentCartVersion,
        },
      }) as Promise<Cart>;
    }
    case isGroupOrder(currentOrderType) && isProxyOrder(incomingOrderType): {
      const existingProxyCart = cartData?.subCarts.find(
        ({ amwayUser }) => amwayUser?.accountId === incomingAmwayUserDetails.accountId,
      );

      if (existingProxyCart) {
        return cartApi.updateGCOFlag({
          payload: {
            amwayUser: incomingAmwayUserDetails,
            orderType: incomingOrderType,
            version: +currentCartVersion,
          },
          cartId: mainCartId,
          subCartId: existingProxyCart.subCartId,
          options: {
            skipCartIdStoreInLS: true,
            skipCartResStoreInLS: true,
            skipVersionStoreInLS: false,
          },
        }) as Promise<Cart>;
      }

      return cartApi.createSubCart({
        cartId: mainCartId,
        payload: {
          amwayUser: incomingAmwayUserDetails,
          entries: [],
          orderType: incomingOrderType,
          version: +currentCartVersion,
        },
      }) as Promise<Cart>;
    }
    case (isProxyOrder(currentOrderType) && isGroupOrder(incomingOrderType)) ||
      (isRegularOrder(currentOrderType) && isGroupOrder(incomingOrderType)): {
      return cartApi.updateGCOFlag({
        payload: {
          amwayUser: cartData?.amwayUser,
          orderType: OrderType.Gco,
          version: +currentCartVersion,
        },
        cartId: mainCartId,
        subCartId: mainCartId,
        options: {
          skipCartIdStoreInLS: true,
          skipCartResStoreInLS: true,
          skipVersionStoreInLS: false,
        },
      }) as Promise<Cart>;
    }
    case (isGroupOrder(currentOrderType) && isRegularOrder(incomingOrderType)) ||
      (isProxyOrder(currentOrderType) && isRegularOrder(incomingOrderType)): {
      return cartApi.updateGCOFlag({
        payload: {
          amwayUser: cartData?.amwayUser,
          orderType: OrderType.Regular,
          version: +currentCartVersion,
        },
        cartId: mainCartId,
        subCartId: mainCartId,
        options: {
          skipCartIdStoreInLS: true,
          skipCartResStoreInLS: true,
          skipVersionStoreInLS: false,
        },
      }) as Promise<Cart>;
    }

    default: {
      cleanUpCartLS();
      const latestCart = await createOrFetchCart();
      return latestCart;
    }
  }
};

export const switchCart = async (
  cartData: Cart,
  orderType: OrderType,
  selectedProfile: AmwayUserDetails,
): Promise<Cart> => {
  if (switchCartNewStrategy()) {
    return switchCartV2(orderType, selectedProfile, cartData) as Promise<Cart>;
  }
  let cart = cartData;
  const cartIdFromLS = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  let mainCartId = cartIdFromLS;
  if (!cartIdFromLS) {
    cart = await createOrFetchCart();
    mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  }
  const accountId = selectedProfile?.accountId;
  const amwayUser = {
    amwayUserId: selectedProfile?.amwayUserId,
    accountId: selectedProfile?.accountId,
  };

  //Get all sub-carts
  const res = await cartApi.getSubCart({
    cartId: mainCartId,
    subCartId: mainCartId,
    projections: ApiProjections.FULL,
    options: {
      skipCartResStoreInLS: true,
      skipCartIdStoreInLS: true,
      skipVersionStoreInLS: true,
    },
  });

  const { subCarts } = res ?? {
    subCarts: [],
  };
  mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  const cartReqVersion = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);

  //Check if the cart already exist for the selected account
  const cartProxy = subCarts.find(({ amwayUser }) => accountId === amwayUser?.accountId);
  let currentEntries: CartEntryDetails[] = [];

  if (cart.orderType === OrderType.Gco) {
    currentEntries = cart.subCarts.find(({ subCartId }) => cart.id === subCartId)?.entries as CartEntryDetails[];
  } else {
    currentEntries = cart.subCarts?.[0]?.entries as CartEntryDetails[];
  }

  const { withoutSOPEntry } = getAllEntries(currentEntries);

  if (cartProxy) {
    const switchedCart = (await cartApi.updateGCOFlag({
      cartId: mainCartId,
      subCartId: cartProxy.subCartId,
      payload: {
        orderType,
        amwayUser,
        version: +cartReqVersion,
      },
      options: {
        skipCartIdStoreInLS: true,
        skipCartResStoreInLS: true,
        skipVersionStoreInLS: false,
      },
    })) as Cart;

    if (!switchedCart.subCarts?.[0]?.entries?.length) {
      const payload = {
        subCarts: [
          {
            subCartId: switchedCart.subCarts?.[0].subCartId,
            entries: validateBundleInEntries(withoutSOPEntry),
          },
        ],
        orderType: OrderType.Proxy,
        version: switchedCart.version,
      };
      return cartApi.addToCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: cart.id,
        projections: ApiProjections.DETAILED,
        payload,
      }) as Promise<Cart>;
    }

    return switchedCart;
  } else {
    //call create cart with selected product
    return cartApi.createSubCart({
      cartId: mainCartId,
      payload: {
        amwayUser,
        entries: validateBundleInEntries(withoutSOPEntry),
        orderType,
        version: +cartReqVersion,
      },
    }) as Promise<Cart>;
  }
};

