export const switchToRegularCart = async (cart: Cart, cartOverrideFlag = false) => {
  if (switchCartNewStrategy()) {
    return switchCartV2(OrderType.Regular, cart.amwayUser, cart) as Promise<Cart>;
  }
  const payload = {
    amwayUser: {
      amwayUserId: cart.amwayUser?.amwayUserId,
      accountId: cart.amwayUser?.accountId,
    },
    orderType: OrderType.Regular,
    version: cart.version,
  };
  const previousEntries = cart.subCarts?.[0]?.entries as CartEntryDetails[];
  const filteredEntries = getFilteredEntries(previousEntries || [], {
    filterPromotion: false,
    filterSOP: true,
    filterIsAccountFeeProduct: true,
    filterIsAccountKitProduct: true,
    filterUnsellableProduct: false,
    filterAuxiliaryProducts: true,
  });
  //const { withoutSOPEntry } = getAllEntries(previousEntries);
  const previousOrderType = cart.orderType;
  const mainCart = (await cartApi.updateGCOFlag({
    payload,
    cartId: cart.id,
    subCartId: cart.id,
    options: {
      skipCartIdStoreInLS: true,
      skipCartResStoreInLS: true,
      skipVersionStoreInLS: false,
    },
  })) as Cart;
  const entriesConditionCheck = cartOverrideFlag ? true : !mainCart.subCarts?.[0]?.entries?.length;

  if (entriesConditionCheck && previousOrderType === OrderType.Proxy) {
    const res =
      cartOverrideFlag &&
      (await cartApi.clearCartEntries({
        cartId: cart.id,
        subCartId: mainCart.id,
      }));

    const payload = {
      subCarts: [
        {
          subCartId: mainCart.id,
          entries: validateBundleInEntries(filteredEntries),
        },
      ],
      orderType: OrderType.Regular,
      version: cartOverrideFlag ? (res as Cart).version : mainCart.version,
    };

    return cartApi.addToCart({
      cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
      subCartId: cart.id,
      projections: ApiProjections.DETAILED,
      payload,
    });
  }
  return mainCart;
};

export const switchOrOverrideCart = async (
  activeCart: SubCartDetail,
  amwayUser: AmwayUserDetails,
  switchType: SWITCH_PROXY_TYPE,
) => {
  if (switchCartNewStrategy()) {
    return switchCartV2(OrderType.Proxy, activeCart.amwayUser as AmwayUserDetails, {
      id: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
      subCarts: [activeCart],
      orderType: OrderType.Proxy,
      amwayUser,
      metaData: {},
      version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
    }) as Promise<Cart>;
  }
  let mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  let cartVersion = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);

  if (!mainCartId) {
    await createOrFetchCart();
    mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    cartVersion = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);
  }

  //Get all sub-carts
  const res = await cartApi.getSubCart({
    cartId: mainCartId,
    subCartId: mainCartId,
    projections: ApiProjections.FULL,
    options: {
      skipCartResStoreInLS: true,
      skipCartIdStoreInLS: true,
      skipVersionStoreInLS: true,
    },
  });

  const proxyCart = res.subCarts.find(
    (subCart) => subCart?.amwayUser?.accountId === amwayUser?.accountId,
  ) as SubCartDetail;

  const mainCartEntries = activeCart.entries?.map((entry) => ({
    entryId: entry.entryId as number,
    partnerPromotionId: entry.partnerPromotionId,
    sopElementId: entry.sopElementId,
    product: {
      id: entry.product.id,
      isAuxiliary: entry?.product?.isAuxiliary,
    },
    bundleSlots: entry.bundleSlots ?? [],
    quantity: entry.quantity,
  })) as CartEntryDetails[];

  //Entries for override cart
  const filteredEntries = getFilteredEntries(mainCartEntries || [], {
    filterPromotion: false,
    filterSOP: true,
    filterIsAccountFeeProduct: true,
    filterIsAccountKitProduct: true,
    filterUnsellableProduct: false,
    filterAuxiliaryProducts: true,
  });

  if (!proxyCart) {
    return (await cartApi.createSubCart({
      cartId: mainCartId,
      payload: {
        amwayUser,
        entries: validateBundleInEntries(filteredEntries),
        orderType: OrderType.Proxy,
        version: +cartVersion,
      },
    })) as Promise<Cart>;
  }

  mainCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  const switchedCart = (await cartApi.updateGCOFlag({
    cartId: mainCartId,
    subCartId: proxyCart?.subCartId,
    payload: {
      orderType: OrderType.Proxy,
      amwayUser,
      version: +res.version,
    },
    options: {
      skipCartIdStoreInLS: true,
      skipCartResStoreInLS: true,
      skipVersionStoreInLS: false,
    },
  })) as Cart;

  if (switchType === SWITCH_PROXY_TYPE.OVERRIDE) {
    //Entries to be deleted
    const updatedEntries = proxyCart.entries?.map((entry) => ({
      entryId: entry.entryId,
      partnerPromotionId: entry.partnerPromotionId,
      product: {
        id: entry.product.id,
      },
      quantity: 0,
    })) as CartEntryDetails[];

    return cartApi.updateCartEntries({
      cartId: mainCartId,
      subCartId: proxyCart.subCartId,
      payload: {
        subCarts: [
          {
            subCartId: proxyCart.subCartId,
            entries: validateBundleInEntries(updatedEntries?.concat(filteredEntries)),
          },
        ],
        version: switchedCart.version,
      },
      options: {
        skipCartIdStoreInLS: true,
        skipCartResStoreInLS: true,
        skipVersionStoreInLS: false,
      },
    });
  }

  return switchedCart;
};

export const filterOutRegistrationProducts = (entries: CartEntryDetails[]) =>
  entries.filter(
    (entry) =>
      !includesAny(entry, [
        AccountProductType.Fee,
        AccountProductType.LateFee,
        AccountProductType.Ekit,
        AccountProductType.Pkit,
      ]),
  );

export const validateBundleInEntries = (cartEntries: CartEntryDetails[] = []) =>
  cartEntries.map((entry) => {
    if (entry?.bundleSlots?.length) {
      const clonedEntry = structuredClone(entry);

      clonedEntry.bundleSlots?.forEach((slot) => {
        slot.entries.forEach((slotEntry) => {
          slotEntry.quantity = slotEntry.baseQuantity ?? slotEntry.quantity;
        });
      });
      return clonedEntry;
    }
    return entry;
  });

export const UNAUTHORIZED = 'unauthorized';

export const requestWithVersionFix = (requestOptions: RequestOptions, augments?: HttpAugments): Promise<CartResponse> =>
  request<Cart>(requestOptions, augments).catch(async (e: ErrorAPI) => {
    if (e.responseBody?.title === Exceptions.EntityVersionConflict) {
      const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
      const latestCart = (await cartApi.getSubCart({
        cartId,
        subCartId: cartId,
        projections: ApiProjections.MIN,
      })) as Cart;
      StorageService.getLocalStorage().store(CartConstantsEnum.CartReqVersion, latestCart.version);
      (requestOptions.body as unknown as { version: number }).version = latestCart.version;
      return request<Cart>(requestOptions, augments);
    }

    if (e.responseBody?.title === Exceptions.CartNotFound) {
      const currentRequestionOption = structuredClone(requestOptions);
      const currentCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
      const currentRequestBody = currentRequestionOption.body as unknown as {
        subCarts: SubCartDetail[];
      };
      const { id, version } = await createOrFetchCart();

      if (currentRequestionOption.method !== HTTPVerbs.POST && currentRequestionOption.method !== HTTPVerbs.GET) {
        const latestCart = await cartApi.getSubCart({
          cartId: id,
          subCartId: id,
          projections: ApiProjections.DETAILED,
        });
        return latestCart;
      }

      currentRequestionOption.url = currentRequestionOption.url.replaceAll(
        encodeURIComponent(currentCartId),
        encodeURIComponent(id),
      );

      if ((currentRequestionOption.body as unknown as { version?: number })?.version) {
        (currentRequestionOption.body as unknown as { version: number }).version = version;
      }

      if (currentRequestBody?.subCarts) {
        currentRequestBody.subCarts[0].subCartId = id;
      }
      return request<Cart>(currentRequestionOption, augments);
    }

    if (e.responseBody?.title === Exceptions.SubCartNotFound) {
      window.location.reload();
      // const { id } = await createOrFetchCart();
      // const latestCart = await cartApi.getSubCart({
      //   cartId: id,
      //   subCartId: id,
      //   projections: ApiProjections.DETAILED,
      // });

      // return latestCart;
    }

    if (
      e.responseBody?.title === Exceptions.CartEntryNotFound ||
      e.responseBody?.title === Exceptions.ProfileAlreadyExist
    ) {
      const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
      const latestCart = await cartApi.getSubCart({
        cartId,
        subCartId: cartId,
        projections: ApiProjections.DETAILED,
      });

      return latestCart;
    }

    if (e.responseBody?.code === UNAUTHORIZED) {
      cleanUpCartLS();
      const latestCart = await createOrFetchCart();
      return latestCart;
    }
    throw e;
  });
