export const getCurrentCartId = async () => {
  const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  // If cart id is present in the localstorage then return that cart id.
  if (cartId) {
    return cartId;
  }

  // If cart id is not present in the localstorage then create a new cart and then return new cart id.
  const cartRes = await createOrFetchCart();
  return cartRes.id;
};

/**
 * This method is used to create the cart and update the cart.
 *
 * @param updateCartPayload
 *
 * @returns Update Cart Response
 */
export const createAndUpdateCart = async (updateCartPayload: UpdateCartRequest, skipLSUpdate = false) => {
  const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  // If cart id is present in the localstorage then update the same cart.
  if (cartId && !skipLSUpdate) {
    const updateCartRes = await updateCart(cartId, updateCartPayload);
    return updateCartRes;
  }

  // If cart id is not present in the localstorage then create a new cart and update new cart.
  const cartRes = await createEmptyCart(skipLSUpdate);
  if (cartRes.id) {
    const updateCartRes = await updateCart(cartRes.id, updateCartPayload, skipLSUpdate, cartRes.version);
    return updateCartRes;
  }

  return null;
};

const updateCart = async (
  cartId: string,
  updateCartPayload: UpdateCartRequest,
  skipLSUpdate = false,
  cartVer?: number,
) => {
  const subCartId = cartId || StorageService.getLocalStorage().retrieve(CartConstantsEnum.SubCartID);
  const version = cartVer ? cartVer : StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);

  const options: CartReqOtherOptions = skipLSUpdate
    ? {
        skipCartIdStoreInLS: true,
        skipCartResStoreInLS: true,
        skipVersionStoreInLS: true,
        skipIsGroupCartStoreInLS: true,
      }
    : {};

  const udpateCartRes = await cartApi.updateCart(
    cartId,
    subCartId,
    {
      ...updateCartPayload,
      // Overriding the cart version here to make sure we are passing updated version
      version: +version,
    },
    options,
  );
  return udpateCartRes;
};

export const hasInvalidCoupon = (data: Cart) => {
  const error =
    data?.errors &&
    data.errors?.find((error: ErrorResponse) => error.title === ExceptionsEnum.Exceptions.InvalidCoupons);

  return error;
};

export const hasCouponOrderDiscountError = (data: Cart) => {
  const error =
    data?.errors &&
    data.errors?.find((error: ErrorResponse) => error.title === ExceptionsEnum.Exceptions.OrderDiscountError);

  return error;
};

export const deletePaymentDetails = (subCart: SubCartDetail) => {
  const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
  const version = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);
  if (subCart?.paymentDetails?.[0]?.paymentPlanId) {
    return cartApi.updateCart(cartId, subCart?.subCartId as string, {
      removePaymentDetails: true,
      version: +version,
    });
  }

  return Promise.resolve(undefined);
};

export const userNotRegistered = (cartData: Cart) => {
  const accountData = cartData?.accountProcess;

  return accountData && !accountData?.id && accountData?.type != AccountProcessType.Renewal;
};

export const allProductDetailsForEventPublish = (cart: CartResponse) => {
  const productBrands: string[] = [];
  const productNames: string[] = [];
  const productIds: string[] = [];
  const productPVs: string[] = [];
  const productBVs: string[] = [];
  const productUnitPrices: string[] = [];
  const productUnits: string[] = [];
  const productPromo: string[] = [];
  const productReferrer: string[] = [];

  cart?.subCarts?.[0].entries?.forEach((entry) => {
    productBrands.push(entry?.product.brand || '');
    productNames.push(entry?.product.name || '');
    productIds.push(entry?.product.id || '');
    productBVs.push(String(entry?.retailPrice?.amwayValue?.businessVolume));
    productPVs.push(String(entry?.retailPrice?.amwayValue?.pointValue));
    productUnitPrices.push(String(entry?.retailPrice?.value));
    productUnits.push(String(entry?.quantity));
    productPromo.push(String(entry?.promotionResults?.firedPromotions?.map((promo) => promo?.promotion?.promoCode)));
    productReferrer.push('');
  });

  return {
    productBrands,
    productNames,
    productIds,
    productPVs,
    productBVs,
    productUnitPrices,
    productUnits,
    productPromo,
    productReferrer,
  };
};

export const getFilteredEntries = (
  cartEntries: CartEntryDetails[],
  options: {
    filterSOP: boolean;
    filterPromotion: boolean;
    filterIsAccountFeeProduct: boolean;
    filterIsAccountKitProduct: boolean;
    filterUnsellableProduct?: boolean;
    filterAuxiliaryProducts?: boolean;
  },
) =>
  cartEntries.filter((entry) => {
    if (options.filterPromotion && entry?.partnerPromotionId) {
      return false;
    }

    if (options.filterSOP && entry?.sopElementId) {
      return false;
    }

    if (options.filterIsAccountFeeProduct && includesAny(entry, [AccountProductType.Fee, AccountProductType.LateFee])) {
      return false;
    }

    if (options.filterIsAccountKitProduct && includesAny(entry, [AccountProductType.Ekit, AccountProductType.Pkit])) {
      return false;
    }

    if (options.filterSOP && entry?.sopElementId) {
      return false;
    }

    if (options?.filterUnsellableProduct && entry.product.isSellable !== undefined && !entry.product.isSellable) {
      return false;
    }
    if (options?.filterAuxiliaryProducts && entry?.product?.isAuxiliary) {
      return false;
    }

    return true;
  });

export const isPVBVEarnedAndUpliftPresent = (
  upliftPV?: number | undefined,
  upliftBV?: number | undefined,
  earnedBV?: number | undefined,
  earnedPV?: number | undefined,
) => {
  const pvbvUpliftPresent = upliftPV || upliftBV;
  const pvbvEarnedPresent = earnedBV || earnedPV;
  return pvbvEarnedPresent && pvbvUpliftPresent;
};

export const updateShippingAddressInLS = async (
  ownerId: string,
  accountNumber: string,
  newAddressApi: boolean,
  contactType: ContactType = ContactType.Shipping,
) => {
  try {
    const res = newAddressApi
      ? await FulfillmentApi.getShippingAddresses({
          params: {
            contactType,
            ownerId,
            accountNumber,
          },
        })
      : await profileApi.getShippingAddressList({
          contactType,
          ownerId,
          accountNumber,
        });

    //Find the primary address
    //const primaryAddress = addressResponse.contacts.find(({ isDefault }) => isDefault);
    let primaryAddress: ShippingAddressResponse | Contact | undefined;
    if ('shippingAddresses' in res) {
      primaryAddress = res.shippingAddresses.find(({ isDefault }) => isDefault);
    } else if ('contacts' in res) {
      primaryAddress = res.contacts.find(({ isDefault }) => isDefault);
    }
    //Update the primary address in local storage using checkout function if primary address exist

    if (primaryAddress && NEXT_PUBLIC_COUNTRY !== Country.JP) {
      CheckoutProfileService.updateDeliveryAddress(primaryAddress as unknown as Address, true);
    }

    return primaryAddress ? res : null;
  } catch {
    return null;
  }
};

export const updateShippingAddressToEmpty = () => {
  if (NEXT_PUBLIC_COUNTRY === Country.JP) {
    return;
  }
  CheckoutProfileService.updateDeliveryAddress(undefined, true);
};

export const updateShippingAddress = async (
  amwayUserId: string,
  accountId: string,
  newAddressApi: boolean,
  updateAddress?: () => void,
) => {
  const res = await updateShippingAddressInLS(amwayUserId, accountId, newAddressApi);

  // if (res === null || res?.contacts.length === 0) {
  //   updateShippingAddressToEmpty();
  // }

  if (
    res === null ||
    ('shippingAddresses' in res && res.shippingAddresses.length === 0) ||
    ('contacts' in res && res.contacts.length === 0)
  ) {
    updateShippingAddressToEmpty();
  }
  updateAddress?.();
  return res;
};

export const updateAddressAfterCartSwitch = async (
  proxyCart: SubCartDetail,
  mainCart: Cart,
  previousOrderType: OrderType,
  newAddressApi: boolean,
  updateAddress?: () => void,
) => {
  const proxyRes = await updateShippingAddressInLS(
    proxyCart.amwayUser?.amwayUserId as string,
    proxyCart.amwayUser?.accountId as string,
    newAddressApi,
  );

  const isEmpty = (res: ShippingAddressesResponse | ContactResponse | null) =>
    res === null ||
    ('shippingAddresses' in res && res.shippingAddresses.length === 0) ||
    ('contacts' in res && res.contacts.length === 0);

  if (isProxyOrder(previousOrderType) && isEmpty(proxyRes)) {
    const fallbackRes = await updateShippingAddressInLS(
      mainCart.amwayUser?.amwayUserId as string,
      mainCart.amwayUser?.accountId as string,
      newAddressApi,
    );

    if (isEmpty(fallbackRes)) {
      updateShippingAddressToEmpty();
    }
  }
  updateAddress();
};

