export const createOrFetchCart = async () => {
  const localStorage = StorageService.getLocalStorage();
  const res = (await cartApi.getCarts({
    projections: ApiProjections.DETAILED,
    options: {
      skipCartIdStoreInLS: true,
      skipCartResStoreInLS: true,
      skipIsGroupCartStoreInLS: true,
      skipVersionStoreInLS: true,
    },
  })) as GetCartsResponse;
  if (res?.carts?.length) {
    const [latestCart] = res.carts;
    localStorage.store(CartConstantsEnum.CartId, latestCart.id);
    localStorage.store(CartConstantsEnum.CartReqVersion, latestCart.version);
    return latestCart;
  }
  return createEmptyCart();
};

export const publishEventHandler = (msg: string, isSuccess = false) =>
  CartEvents.publishEvent({
    event: isSuccess ? CartEventsEnum.RedeemSuccessful : CartEventsEnum.RedeemFailed,
    payload: {
      cartId: '',
    },
    message: msg,
  });

export const redeemAndAddToCart = async (
  productId: string,
  quantity: number,
  isRestricted = false,
  bundleSlots?: BundleSlot[],
) => {
  try {
    const redeemRes = await cartApi.redeemAPoints({
      productId: productId,
    });
    let fetchCartRes: SubCartDetail = {};
    const cartIdInLS = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);

    if (redeemRes?.error?.title) {
      switch (redeemRes?.error?.title) {
        case Exceptions.RedeemAmpointInsufficient:
          return publishEventHandler('cart.cartCommonHelpers.redeemAmpointInsufficient');
        case Exceptions.RedeemAmpointMaxPerAccountQuotaExceed:
          return publishEventHandler('cart.cartCommonHelpers.redeemAmpointMonthlyQuota');
        case Exceptions.RedeemAmpointMaxTotalQuotaExceed:
          return publishEventHandler('cart.cartCommonHelpers.redeemAmpointFullQuota');
        default:
          return publishEventHandler('cart.addToCartButton.exceptionOccured');
      }
    }

    if (!cartIdInLS && !isRestricted) {
      const res = await createOrFetchCart();
      fetchCartRes = getActiveCart(res);
    }
    const payload = {
      subCarts: [
        {
          subCartId: fetchCartRes?.subCartId ?? cartIdInLS,
          entries: [
            {
              product: {
                id: productId,
              },
              quantity,
              bundleSlots,
            },
          ],
          couponCode: redeemRes.couponCode,
        },
      ],
      version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
    };

    try {
      if (!isRestricted) {
        await cartApi.addToCart({
          cartId: fetchCartRes?.subCartId ?? cartIdInLS,
          subCartId: fetchCartRes?.subCartId ?? cartIdInLS,
          projections: ApiProjections.DETAILED,
          payload,
        });
      }
    } catch (e) {
      ConsoleLogger.log(e);
    }
  } catch (e) {
    ConsoleLogger.log(e);
    return publishEventHandler('cart.addToCartButton.exceptionOccured');
  }

  return publishEventHandler('success', true);
};

export const isMainCartNotEmpty = (cart: CartResponse, cartId: string) => {
  const activeCart = getActiveCart(cart, cartId as string);
  //need to hide/show ellipses on main cart details page in gco mode and will always be shown on other subcarts
  const mainCartNotEmpty =
    isGroupOrder(cart.orderType) && (activeCart?.subCartId !== cart.id || !cartId)
      ? true
      : activeCart?.entries && activeCart?.entries?.length !== 0;

  return mainCartNotEmpty;
};

export const getAccountProductType = (cartEntries: CartEntryDetails[], productType: AccountProductType) =>
  cartEntries?.find((entry: CartEntryDetails) => entry?.accountProductTypes?.includes(productType));

export const includesAny = (entry: CartEntryDetails, types: AccountProductType[]) =>
  types.some((type) => entry?.accountProductTypes?.includes(type));

export const getProductEntry = (cart: Cart, productId: string) => {
  const activeCart = cart.subCarts?.find((subCart) => subCart.subCartId === cart.id);
  return activeCart?.entries?.find((entry) => productId === entry.product.id);
};

export const isNotValidUserForAwardLevel = (
  userGroup: Array<string> | undefined,
  userType: Array<string> | undefined,
) => {
  if (userType?.includes('ABO') || userGroup?.includes('ABO')) {
    return false;
  } else {
    return true;
  }
};
