import { Breakpoints, ButtonAlignment, Modal, useBreakpoint, useTranslation } from '@nextgen-web-framework/all';
import {
  Cart,
  cartApi,
  CartConstantsEnum,
  CartEvents,
  CartEventsEnum,
  switchToRegularCart,
  updateCart,
} from '@commerce-cart-webcomponents/sdk';
import { StorageService } from '@nextgen-web-framework/core';
import { useDispatch } from 'react-redux';

type CancelProxyModalProps = {
  setShowCancelProxyModal: React.Dispatch<React.SetStateAction<boolean>>;
  cartData: Cart;
};

export const CancelProxyModal = ({ setShowCancelProxyModal, cartData }: CancelProxyModalProps) => {
  const t = useTranslation();
  const viewport = useBreakpoint();
  const currentViewport = viewport === Breakpoints.XS ? ButtonAlignment.VERTICAL : ButtonAlignment.HORIZONTAL;
  const dispatch = useDispatch();
  const accountCancelText = t('cart.addToCartDrawer.accountCancel');

  const handleClearCart = () => {
    const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    cartApi
      .clearCartEntries({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: cartId,
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart: res,
            cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
          },
          sync: true,
        });
      })
      .catch(() => {});
  };

  const handlePrimaryClick = async () => {
    const res = (await switchToRegularCart(cartData)) as Cart;
    dispatch(updateCart(res));
    handleClearCart();
    setShowCancelProxyModal(false);
  };
  return (
    <Modal
      headline={t('cart.cartSwitchBanner.stopProxyOrderMode')}
      primaryButtonLabel={t('cart.cartSwitchBanner.stopProxyOrder')}
      secondaryButtonLabel={accountCancelText}
      buttonAlignment={currentViewport}
      onSecondaryButtonClick={() => setShowCancelProxyModal(false)}
      onPrimaryButtonClick={handlePrimaryClick}
      closeIcon={false}
    >
      <div style={{ textAlign: 'left' }}>{t('cart.cartSwitchBanner.stopProxyOrderModeDesc')}</div>
    </Modal>
  );
};
