import { useState, useEffect } from 'react';
import {
  type Cart,
  CartConstantsEnum,
  CartEvents,
  CartEventsEnum,
  cartApi,
  updateCart,
  type InitialCartState,
  isMainCart,
  type SubCarts,
  type AmwayUser,
  CartEntryDetails,
  ApiProjections,
  UserListResponse,
  updateMyList,
  getWishlist,
  ListResponse,
  myListApi,
  ListEntry,
  InitialCartListState,
  CartRoutePaths,
  getActiveCart,
  OrderType,
  updateListsByUser,
  getFilteredEntries,
  updateShippingAddressInLS,
  ErrorAPI,
  showEditLabel,
  type AmwayUserDetails,
} from '@commerce-cart-webcomponents/sdk';
import {
  Button,
  ButtonStyles,
  Modal,
  useNextgenRouter,
  useSession,
  useTranslation,
  Menu,
  type MenuItem,
  FAIcon,
  TextLink,
  TextLinkStyle,
} from '@nextgen-web-framework/all';
import { StorageService, type AppState } from '@nextgen-web-framework/core';
import { useDispatch, useSelector } from 'react-redux';
import { useAddressUpdate } from '@commerce-webcomponents/ui';
import { validateBundleInEntries, clearEntriesFromCart } from '@commerce-cart-webcomponents/sdk';
import { useCartNotification } from '../../common/hooks/useCartNotification';
import { CartNotificationTheme } from '../../common/components/cart-notification/types/enums';
import { TOAST_TIMEOUT } from '../../common/types/enums';
import { CircleLoader } from '../../common/components/cart-loader/circle-loader/CircleLoader';
import { ItemsUnavailable } from '../cart-total/items-unavailable/ItemsUnavailable';
import { ModalWrapper, useExceptionToast } from '../../common';
import { lazyLoad } from '../../utils';
import { useFeatureFlag } from '../../common/hooks/useFeatureFlag';
import styles from './CartEllipsisMenu.module.scss';
import { CART_ELLIPSIS_ID } from './types/enums';

export type CartEllipsisMenuProps = {
  currentCartId?: string;
  isNonGCO?: boolean;
  cartEntriesDetails?: CartEntryDetails[];
};

const AccountSearchDrawer = lazyLoad(
  () =>
    import('../../common/components').then((module) => ({
      default: module.AccountSearchDrawer,
    })),
  <></>,
);
const AddToListDrawer = lazyLoad(() => import('../lists/components/add-to-list-drawer/AddToListDrawer'), <></>);

export const CartEllipsisMenu = ({ currentCartId, isNonGCO, cartEntriesDetails }: CartEllipsisMenuProps) => {
  const t = useTranslation();
  const { updateAddress } = useAddressUpdate();
  const { isRegistered, isAnonymous, isEmployee } = useSession();
  const [menuData, setMenuData] = useState<MenuItem[]>([]);
  const [showLoader, setShowLoader] = useState(false);
  const [reassignForm, setReassignForm] = useState(false);
  const [deleteCart, setDeleteCart] = useState(false);
  const [clearCart, setClearCart] = useState(false);
  const [duplicateDrawer, setDuplicateDrawer] = useState(false);
  const [listDrawer, setListDrawer] = useState(false);
  const [showEllipses, setShowEllipses] = useState(false);
  const [showRemoveSOPModal, setShowRemoveSOPModal] = useState(false);
  const warningText = t('cart.clearCart.warningText');
  const dispatch = useDispatch();
  const router = useNextgenRouter();
  const { createToast, deleteToast } = useCartNotification('cartEllipisMenu');
  const cartId = router.params?.cartId;
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { cart }: InitialCartState = commerceCartState;
  const { myList }: InitialCartListState = useSelector((state: AppState) => state.commerceMyList);
  const { showProxyConsentFlag, newAddressApiFlag } = useFeatureFlag();

  const currentActiveCart = getActiveCart(cart, currentCartId as string);

  const isSOPMetaDataPresent =
    currentActiveCart?.sopMetaData !== undefined && currentActiveCart.sopMetaData.length !== 0;

  const cartReassignedText = t('cart.cartEllipsisMenu.cartReassiged');
  const cartDeletedText = t('cart.cartEllipsisMenu.cartDeleted');
  const btnCancelText = t('cart.groupOrder.button.cancel');
  const btnPlaceHolderText = t('cart.addToCartDrawer.placeHolderText');
  const duplicateCartText = t('cart.cartEllipsisMenu.cartDuplicate');
  const addedToWishlist = t('cart.cartEllipsis.ProductsAddedToWishlist');
  const duplicateText = t('cart.itemsUnavailable.cannotDuplicateSOPItems');
  const reassignText = t('cart.itemsUnavailable.cannotReassignSOPItems');
  const [modalHeadingText, setModalHeadingText] = useState<string>('');
  const triggerToast = useExceptionToast();

  const handleClearCart = () => {
    clearEntriesFromCart(dispatch, currentCartId, setShowLoader, setClearCart, setShowEllipses);
  };

  const deleteSubCart = () => {
    setDeleteCart(false);
    setShowLoader(true);
    const currentCart = cart.subCarts.find(({ subCartId }) => subCartId === currentCartId);
    cartApi
      .deleteSubCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: currentCartId,
        options: {
          skipCartIdStoreInLS: true,
          skipCartResStoreInLS: true,
          skipVersionStoreInLS: true,
        },
      })
      .then(() => {
        const amwayUserIdinCheckoutLS = StorageService.getLocalStorage().retrieve('checkoutProfile') as unknown as {
          fulfillmentType: {
            serviceLevel: {
              deliveryAddress: {
                ownerId?: string;
              };
            };
          };
        };
        if (
          amwayUserIdinCheckoutLS?.fulfillmentType.serviceLevel.deliveryAddress?.ownerId ===
          currentCart?.amwayUser?.amwayUserId
        ) {
          updateShippingAddressInLS(
            cart.amwayUser.amwayUserId,
            cart.amwayUser.accountId as string,
            newAddressApiFlag,
          ).then(updateAddress);
        }
        setShowLoader(false);
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: cartDeletedText,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
        CartEvents.publishEvent({
          event: CartEventsEnum.RemoveCartEntry,
          payload: {
            cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
            cart_type: '',
          },
        });

        if (cartId) {
          router?.push?.(CartRoutePaths.CART);
        } else {
          cartApi
            .getSubCart({
              cartId: cart.id,
              subCartId: cart.id,
              projections: ApiProjections.DETAILED,
              options: {
                skipCartResStoreInLS: true,
              },
            })
            .then((res: Cart) => {
              dispatch(updateCart(res));
              CartEvents.publishEvent({
                event: CartEventsEnum.UpdateMiniCartIcon,
                payload: {
                  cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
                  cart: res,
                  cart_type: '',
                },
              });
            });
        }
      });
  };

  function reassignCart(profile: AmwayUserDetails) {
    const payload = {
      amwayUser: profile,
      orderType: OrderType.Gco,
      version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
    };

    cartApi
      .reassignCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: currentCartId,
        payload,
      })
      .then((res) => {
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: cartReassignedText,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
        const subCart = (res as Cart).subCarts;
        setReassignForm(false);
        CartEvents.publishEvent({
          event: CartEventsEnum.RedirectToSubCart,
          payload: {
            cartId: subCart?.[subCart?.length - 1].subCartId,
            cart_type: '',
          },
        });
        dispatch(updateCart(res as Cart));
      });
  }

  function duplicateCart(profile: AmwayUserDetails) {
    const subCart = cart.subCarts?.find(({ subCartId }) => subCartId === currentCartId) as unknown as SubCarts;
    const filteredEntries = getFilteredEntries(subCart?.entries || [], {
      filterPromotion: true,
      filterSOP: false,
      filterIsAccountFeeProduct: true,
      filterIsAccountKitProduct: true,
      filterUnsellableProduct: true,
      filterAuxiliaryProducts: true,
    });
    const entries = validateBundleInEntries(filteredEntries);
    cartApi
      .createSubCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        payload: {
          amwayUser: profile as AmwayUser,
          entries,
          orderType: cart.orderType,
          version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
        },
      })
      .then((res) => {
        const subCart = (res as Cart).subCarts;
        setDuplicateDrawer(false);
        CartEvents.publishEvent({
          event: CartEventsEnum.RedirectToSubCart,
          payload: {
            cartId: subCart?.[subCart?.length - 1].subCartId,
            cart_type: '',
          },
        });
        if (cartId) {
          router?.push?.(CartRoutePaths.CART);
        }
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: duplicateCartText,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
        dispatch(updateCart(res as Cart));
      });
  }

  function addToListSuccess(updatedList: UserListResponse) {
    dispatch(updateMyList(getWishlist(updatedList) as ListResponse));
    createToast(
      {
        theme: CartNotificationTheme.SUCCESS,
        rightSeperator: false,
        content: addedToWishlist,
        clickIcon: 'times',
        icon: 'check-circle',
        timeOut: TOAST_TIMEOUT,
      },
      deleteToast,
    );
  }

  function handleAddAllToListTab() {
    if (isRegistered() || isEmployee()) {
      const activeCart = cart?.subCarts?.find(({ subCartId }) => subCartId === currentCartId);
      myListApi
        .addToList([
          {
            version: myList.version as number,
            entries: getFilteredEntries(activeCart?.entries || [], {
              filterPromotion: false,
              filterSOP: false,
              filterIsAccountFeeProduct: true,
              filterIsAccountKitProduct: true,
              filterUnsellableProduct: true,
              filterAuxiliaryProducts: true,
            }) as unknown as ListEntry[],
            listId: myList?.listId as string,
          },
        ])
        .then((updatedList: UserListResponse) => {
          addToListSuccess(updatedList);
          dispatch(updateListsByUser(updatedList));
        })
        .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
      return;
    }

    setListDrawer(true);
  }

  const deleteCartTab: MenuItem = {
    id: CART_ELLIPSIS_ID.DELETE_CART,
    title: t('cart.cartEllipsesMenu.delete'),
    icon: 'trash-can',
    onClick: () => {
      setShowEllipses(false);
      setDeleteCart(true);
    },
  };

  const duplicateCartTab: MenuItem = {
    id: CART_ELLIPSIS_ID.DUPLICATE_CART,
    title: t('cart.cartEllipsesMenu.duplicateCart'),
    icon: 'copy',
    onClick: () => {
      setShowEllipses(false);
      setModalHeadingText(duplicateText);
      if (isSOPMetaDataPresent) {
        setShowRemoveSOPModal(true);
      } else {
        setDuplicateDrawer(true);
      }
    },
  };

  const reassignCartTab: MenuItem = {
    id: CART_ELLIPSIS_ID.REASSIGN_CART,
    title: t('cart.cartEllipsesMenu.reassignCart'),
    icon: 'user-magnifying-glass',
    onClick: () => {
      setShowEllipses(false);
      setModalHeadingText(reassignText);
      if (isSOPMetaDataPresent) {
        setShowRemoveSOPModal(true);
      } else {
        setReassignForm(true);
      }
    },
  };

  const clearCartTab: MenuItem = {
    id: CART_ELLIPSIS_ID.CLEAR_CART,
    title: t('cart.clearCart.clear'),
    icon: 'cart-xmark',
    onClick: () => {
      setShowEllipses(false);
      setClearCart(true);
    },
  };

  const addAllToListTab: MenuItem = {
    id: CART_ELLIPSIS_ID.ADD_ALL_TO_LIST,
    title: t('cart.cartEllipsis.addAllToList'),
    icon: showProxyConsentFlag ? 'star' : 'heart',
    onClick: () => {
      setShowEllipses(false);
      handleAddAllToListTab();
    },
  };

  const nonGCOGuestMenuData: MenuItem[] = [clearCartTab];
  const nonGCOMenuData: MenuItem[] = [addAllToListTab, clearCartTab];
  // [Main Cart] Self Cart: Non-Empty State. Removing duplicate option as its not working need to add later
  const mainCartMenuData: MenuItem[] = [duplicateCartTab, clearCartTab];

  // [Main Cart] Downline Cart: Non-Empty State
  const downlineCartMenuData: MenuItem[] = [addAllToListTab, reassignCartTab, duplicateCartTab, deleteCartTab];

  // [Main Cart] Downline Cart: Empty State
  const downlineEmptySubCartMenuData: MenuItem[] = [reassignCartTab, deleteCartTab];

  const getUpdatedListByUser = () => {
    myListApi
      .getAllListByUser({
        projections: ApiProjections.FULL,
      })
      .then((res) => dispatch(updateListsByUser(res)))
      .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
  };

  useEffect(() => {
    let menuData: MenuItem[];
    const activeCart = cart?.subCarts?.find(({ subCartId }) => subCartId === currentCartId);
    if (isNonGCO) {
      menuData = isAnonymous() ? nonGCOGuestMenuData : nonGCOMenuData;
    } else if (isMainCart(currentCartId)) {
      menuData = mainCartMenuData;
    } else {
      menuData = activeCart?.entries?.length === 0 ? downlineEmptySubCartMenuData : downlineCartMenuData;
    }
    setMenuData(menuData);
  }, [cart, isNonGCO, currentCartId]);

  return (
    <>
      {showRemoveSOPModal && (
        <ItemsUnavailable
          notAvailableEntries={[]}
          allSOPEntries={currentActiveCart?.sopMetaData}
          showRemoveSOPItemsModal
          onPrimaryBtnClick={() => setShowRemoveSOPModal(false)}
          sopHeadingText={modalHeadingText}
        />
      )}
      {showLoader && <CircleLoader />}

      {showEditLabel() ? (
        <TextLink
          text={t('cart.cartEllipsisMenu.edit')}
          onClick={() => setShowEllipses(true)}
          textLinkStyle={TextLinkStyle.UNDERLINE}
        />
      ) : (
        <FAIcon onClick={() => setShowEllipses(true)} iconName="ellipsis-vertical" />
      )}

      <div className={styles['ellipsis-menu-container']} data-testid="ellipsis-menu-container">
        {showEllipses && (
          <Menu className={styles['ellipsis-menu']} menuItems={menuData} onClose={() => setShowEllipses(false)} />
        )}
      </div>
      <div>
        {reassignForm && (
          <AccountSearchDrawer
            cartData={cart}
            onPrimaryButtonClick={() => setReassignForm(false)}
            drawerHeaderTitle={t('cart.cartEllipsesMenu.reassignCart')}
            placeHolderText={btnPlaceHolderText}
            primaryButtonText={btnCancelText}
            secondaryButtonText={t('cart.cartEllipsesMenu.reassign')}
            onRadioChange={reassignCart}
          />
        )}
        {duplicateDrawer && (
          <AccountSearchDrawer
            cartData={cart}
            onPrimaryButtonClick={() => setDuplicateDrawer(false)}
            drawerHeaderTitle={t('cart.cartEllipsesMenu.duplicateCart')}
            placeHolderText={btnPlaceHolderText}
            primaryButtonText={btnCancelText}
            secondaryButtonText={t('cart.addToCartDrawer.accountAddCart')}
            onRadioChange={duplicateCart}
          />
        )}
        {deleteCart && (
          <div className={styles['commerce-gco-delete-modal']}>
            <Modal
              closeIcon={false}
              onClose={() => setDeleteCart(false)}
              headline={t('cart.cartEllipsesMenu.deleteCart')}
              primaryButtonLabel={''}
            >
              <div className={styles['commerce-gco-delete-modal-buttons']}>
                <Button title={t('cart.cartEllipsesMenu.yesDelete')} onClick={deleteSubCart} />
                <Button buttonStyle={ButtonStyles.OUTLINE} title={btnCancelText} onClick={() => setDeleteCart(false)} />
              </div>
            </Modal>
          </div>
        )}
        {clearCart && (
          <div className={styles['commerce-gco-delete-modal']}>
            <ModalWrapper
              headLineText={t('cart.clearCart.clear')}
              description={warningText}
              primaryButtonLabel={t('cart.cartEllipsesMenu.yesClear')}
              secondaryButtonLabel={btnCancelText}
              onPrimarySuccess={handleClearCart}
              onSecondarySuccess={() => setClearCart(false)}
            />
          </div>
        )}
        {listDrawer && (
          <AddToListDrawer
            heartIconFilledcb={() => getUpdatedListByUser()}
            onDrawerClose={() => setListDrawer(false)}
            cartEntriesDetails={cartEntriesDetails}
          />
        )}
      </div>
    </>
  );
};
