import {
  AccountProductType,
  Cart,
  cartApi,
  CartConstantsEnum,
  CartEntry,
  CartEntryDetails,
  CartEventsEnum,
  CartRoutePaths,
  deletePaymentDetails,
  getActiveCart,
  includesAny,
  isGroupOrder,
  navigateToCart,
  OrderType,
  PublishEvent,
  publishLoaderEvent,
  tealiumEventPublisher,
  updateCart,
  userNotRegistered,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { StorageService, Logger } from '@nextgen-web-framework/core';
import { useState } from 'react';
import {
  Breakpoints,
  FAIcon,
  TextLink,
  useBreakpoint,
  useNextgenRouter,
  useTranslation,
} from '@nextgen-web-framework/all';
import { CartMobileHeader } from '../../cart-mobile-header/CartMobileHeader';
import { EmptyCart } from '../../empty-cart/EmptyCart';
import { CartLineItems } from '../CartLineItems';
import { CartLineItemsHeader } from '../cartLineItemsHeader/CartLineItemsHeader';
import { CartEllipsisMenu } from '../../cart-ellipsis-menu/CartEllipsisMenu';
import { CartTotal } from '../../cart-total/CartTotal';
import { ExceptionModal } from '../../exception-modal/ExceptionModal';
import { useRemoveInvalidProducts } from '../../../common/hooks/useRemoveInvalidProducts';
import {
  CartNotificationTheme,
  TOAST_TIMEOUT,
  useCartNotification,
  useExceptionToast,
  useFeatureFlag,
} from '../../../common';
import { AddSubCartIcon } from '../../add-sub-cart-icon/AddSubCartIcon';
import styles from './CartItemsContainer.module.scss';
import { CartItemsContainerProps } from './propTypes';

export const CartItemsContainer = ({
  cartData,
  cartId,
  isSubCart,
  cart,
  isEmptyCart,
  exceptionModal,
  setExceptionModal,
  exceptionTitleData,
  isMainCart,
  cartDetailsPage,
  checkoutHandler,
  displayCheckoutButton,
}: CartItemsContainerProps) => {
  const { createToast, deleteToast } = useCartNotification('cartLineItem');
  const dispatch = useDispatch();
  const t = useTranslation();
  const [showCompensatedModal, setShowCompensatedModal] = useState<boolean>(false);
  const mainSubCart = getActiveCart(cartData, cartId as string);
  const { entries: cartEntries } = mainSubCart || {};
  const displayGCO = isSubCart ? false : cart.orderType === OrderType.Gco;
  const invalidProductsRemovedText = t('cart.cartLineItem.invalidProductsRemovedText');
  const showRemoveSuccess = t('cart.cartlineItemHeader.removeSuccess');
  const loggerInstance = Logger.getInstance();
  const { showProxyConsentFlag } = useFeatureFlag();
  const triggerToast = useExceptionToast();
  const notRegistered = userNotRegistered(cartData);
  const viewPort = useBreakpoint();
  const isMobileView = [Breakpoints.XS, Breakpoints.SM].includes(viewPort as Breakpoints);

  const checkoutClickHandler = () => {
    const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    if (cartId !== cart.id) {
      window.location.reload();
      return;
    }
    tealiumEventPublisher(cart, CartEventsEnum.ProceedToCheckout, () => {
      if (notRegistered) {
        router.push(CartRoutePaths.REGISTRATION_CHECKOUT);
      } else {
        checkoutHandler();
      }
    });
  };

  const router = useNextgenRouter();
  const productsRemovedText = t('cart.cartLineItem.productsRemoved');
  const continueText = t('cart.cartContainer.continueText');
  const undoText = t('cart.cartLineItem.undo');

  const backToCartList = (e: React.MouseEvent<HTMLAnchorElement, MouseEvent>) => {
    e.preventDefault();
    router.back();
  };
  const showBackToCartList = (empty = false) => (
    <>
      {isSubCart && (
        <div className={`${empty ? styles['back-To-CartContainer-empty'] : styles['back-To-CartContainer']}`}>
          <FAIcon iconName="chevron-left" onClick={backToCartList} />
          <TextLink href="" text={t('cart.cartContainer.backToCartList')} onClick={backToCartList} />
        </div>
      )}
    </>
  );

  const addToCartItem = async (cartEntry: CartEntryDetails, toastId: string) => {
    const payload = {
      subCarts: [
        {
          subCartId: mainSubCart.subCartId,
          entries: [cartEntry],
        },
      ],
      version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
    };
    const res = await cartApi.addToCart({
      cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
      subCartId: mainSubCart?.subCartId,
      payload,
    });
    deleteToast(toastId);
    dispatch(updateCart(res as Cart));
    PublishEvent({
      cartEvent: CartEventsEnum.AddToCart,
      cartEntry,
    });
  };
  const removeEntry = async (entryId: number, entryIdArray: number[] = [], isInvalid = false) => {
    try {
      const cartEntry = (cartEntries as Array<CartEntryDetails>).find((entry: CartEntry) => entry.entryId == entryId);
      publishLoaderEvent(true);
      const res = await cartApi.removeEntryFromCart({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: mainSubCart.subCartId,
        entryId: entryIdArray.length !== 0 ? encodeURIComponent(entryIdArray.join(',')) : String(cartEntry?.entryId),
      });
      const deletePaymentRes = await deletePaymentDetails(mainSubCart);
      const updatedRes = (deletePaymentRes ?? res) as Cart;
      setShowCompensatedModal(false);
      publishLoaderEvent(false);
      if (entryIdArray.length !== 0) {
        createToast(
          {
            theme: isInvalid ? CartNotificationTheme.YELLOW : CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: isInvalid ? invalidProductsRemovedText : showRemoveSuccess,
            clickIcon: isInvalid ? undefined : 'times',
            icon: isInvalid ? undefined : 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
      } else {
        createToast(
          {
            theme: CartNotificationTheme.GREEN,
            content: productsRemovedText,
            textlink: undoText,
            timeOut: TOAST_TIMEOUT,
          },
          (id: string) => addToCartItem(cartEntry as CartEntryDetails, id),
        );
      }
      dispatch(updateCart(updatedRes));
      if (cartEntry) {
        PublishEvent({
          cartEvent: CartEventsEnum.RemoveCartEntry,
          cartEntry,
          cart: updatedRes,
        });
      }
      PublishEvent({
        cartEvent: CartEventsEnum.UpdateMiniCartIcon,
        cart: updatedRes,
      });
    } catch (error) {
      triggerToast();
      publishLoaderEvent(false);
      loggerInstance.error(error);
    }
  };
  const onEntryRemove = async (entry: CartEntryDetails) => {
    const version = +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion);
    if (includesAny(entry, [AccountProductType.Ekit, AccountProductType.Pkit])) {
      const deleteAccountProcessPayload = {
        version,
        removeAccountProcess: true,
      };
      const res = await cartApi.updateCart(cartData.id, mainSubCart.subCartId as string, deleteAccountProcessPayload);
      dispatch(updateCart(res as Cart));
      PublishEvent({
        cartEvent: CartEventsEnum.UpdateMiniCartIcon,
        cart: res as Cart,
      });
      return;
    }
    removeEntry(entry.entryId as number);
  };

  useRemoveInvalidProducts(cartEntries, removeEntry);

  const renderCartContainer = () => {
    const clickedShowCart = (id: string) => {
      navigateToCart(id, router);
    };
    if (isEmptyCart) {
      return (
        <>
          {showBackToCartList(true)}
          <EmptyCart
            imgSrc="/icons/EmptyCartIcon.svg"
            cartEmptyTxt1={t('cart.emptyCart.cartEmptyTxt1')}
            cartEmptyTxt2={t('cart.emptyCart.cartEmptyTxt2')}
          />
        </>
      );
    }
    return (
      <>
        <div className={styles['cart-items']}>
          {exceptionModal && (
            <ExceptionModal
              onButtonClick={() => setExceptionModal(false)}
              buttonTitle={continueText}
              title={exceptionTitleData.title}
              description={exceptionTitleData.description}
            />
          )}
          <div
            className={`${styles['commerce-cart-item-line-page']} ${
              showProxyConsentFlag ? styles['commerce-cart-item-line-page-jp'] : ''
            }`}
          >
            {showBackToCartList()}
            <CartLineItems
              data={cartData?.subCarts.length === 0 ? cart : (cartData as Cart)}
              displayGCO={displayGCO}
              clickedShowCart={clickedShowCart}
              isMainUserCart={isSubCart ? isMainCart : true}
              cartDetailsPage={cartDetailsPage}
              removeEntry={removeEntry}
              onEntryRemove={onEntryRemove}
              showCompensatedModal={showCompensatedModal}
              setShowCompensatedModal={setShowCompensatedModal}
            />
          </div>
        </div>
      </>
    );
  };

  const renderCartHeader = () => (
    <>
      {isEmptyCart && !isMobileView && (
        <>
          {showBackToCartList(true)}
          <div className={styles['commerce-cart-desktop-header']}>
            <div className={styles['commerce-cart-desktop-header-details']}>
              <CartMobileHeader />
            </div>
          </div>
        </>
      )}
      {!isEmptyCart && !isMobileView && (
        <div className={styles['commerce-cart-line-item-header']}>
          <CartMobileHeader isGCOList={displayGCO} />
          {isGroupOrder(cartData.orderType) && !cartDetailsPage ? <AddSubCartIcon /> : null}
          {!displayGCO && cartData && (
            <div className={styles['commerce-cart-line-item-header-ellipis-menu-show']}>
              <CartEllipsisMenu
                currentCartId={mainSubCart?.subCartId}
                isNonGCO={(isSubCart ? isMainCart : true) && !isGroupOrder(cartData.orderType)}
                cartEntriesDetails={cartEntries}
              />
            </div>
          )}
        </div>
      )}
      <CartLineItemsHeader
        data={cartData}
        cartDetailsPage={cartDetailsPage}
        onEntryRemove={(entry) => onEntryRemove(entry)}
        displayGCO={isSubCart ? false : cart.orderType === OrderType.Gco}
      />
    </>
  );

  const renderCartTotal = () => (
    <div
      className={`${
        isSubCart ? styles['commerce-cart-items-total-page-subcart'] : styles['commerce-cart-items-total-page']
      } ${showProxyConsentFlag && !isSubCart ? styles['commerce-cart-items-total-page-jp'] : ''}`}
    >
      <CartTotal
        data={cart}
        clickCheckoutHandler={checkoutClickHandler}
        displayGCO={isSubCart ? false : cart.orderType === OrderType.Gco}
        displayCheckoutBtn={displayCheckoutButton}
        displayPVBV
      />
    </div>
  );
  return (
    <div className={`${styles['cart-container-content']} ${isEmptyCart ? styles['empty'] : ''}`}>
      <div className={styles['cart-head']}>{renderCartHeader()}</div>
      <div className={styles['cart-tots']}>{!isEmptyCart && renderCartTotal()}</div>
      <div className={styles['cart-body']}>{renderCartContainer()}</div>
    </div>
  );
};
