import {
  Theme,
  useTranslation,
  Modal,
  Button,
  ButtonAlignment,
  ButtonStyles,
  ButtonSize,
  useSession,
} from '@nextgen-web-framework/all';
import {
  Cart,
  CartConstantsEnum,
  cartApi,
  updateCart,
  type CartEntryDetails,
  getExceptionProducts,
  isGroupOrder,
  CartEventsEnum,
  PublishEvent,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { StorageService } from '@nextgen-web-framework/core';
import { CheckoutCardForModal } from '../../common';
import styles from './ItemsRemovedModal.module.scss';

export type ItemsRemovedModalProps = {
  cart: Cart;
};
const ItemsRemovedModal = ({ cart }: ItemsRemovedModalProps) => {
  const t = useTranslation();
  const { isABO } = useSession();
  const doneButton = t('cart.ItemsRemovedModal.done');
  const dispatch = useDispatch();

  const removedEntriesPayload = cart.subCarts.map(({ subCartId, entries }) => {
    const { removedProducts } = getExceptionProducts(entries as CartEntryDetails[]);
    return {
      subCartId,
      entries: removedProducts?.map(({ entryId, product, partnerPromotionId }) => ({
        entryId,
        product: {
          id: product.id,
        },
        partnerPromotionId,
        quantity: 0,
      })),
    };
  });

  const onDoneClickHandler = () => {
    cartApi
      .updateCartEntries({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        payload: {
          subCarts: removedEntriesPayload,
          version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
        },
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        PublishEvent({
          cartEvent: CartEventsEnum.UpdateMiniCartIcon,
          cart: res as Cart,
        });
      });
  };

  return (
    <Modal
      buttonAlignment={ButtonAlignment.VERTICAL}
      primaryButtonLabel={''}
      headline={t('cart.ItemsRemovedModal.itemsRemoved')}
      closeIcon={false}
    >
      <>
        <div className={styles['itemsRemoved-modal-container']}>
          <div className={styles['itemsRemoved-modal-container-heading']}>
            {t('cart.ItemsRemovedModal.itemsRemovedHeading')}
          </div>
          {cart.subCarts.map(({ entries, amwayUser }) => {
            const { removedProducts } = getExceptionProducts(entries as CartEntryDetails[]);
            return (
              <>
                {isGroupOrder(cart.orderType) && !!removedProducts.length && (
                  <div className={styles['itemsRemoved-modal-container-name']}>
                    {amwayUser?.primaryName ?? ''} (
                    {cart.amwayUser?.amwayUserId === amwayUser?.amwayUserId
                      ? t('cart.gcoList.You')
                      : amwayUser?.accountId}
                    )
                  </div>
                )}
                {removedProducts?.map((entry: CartEntryDetails) =>
                  CheckoutCardForModal({
                    entry,
                    isABO: isABO(),
                    className: styles['checkout-card-component'],
                  }),
                )}
              </>
            );
          })}
        </div>
        <div className={styles['done-button-container']}>
          <Button
            title={doneButton}
            buttonStyle={ButtonStyles.SOLID}
            theme={Theme.BLACK}
            size={ButtonSize.MEDIUM}
            role="button"
            onClick={onDoneClickHandler}
            aria-label={doneButton}
          />
        </div>
      </>
    </Modal>
  );
};

export { ItemsRemovedModal };
