import { useFeatureVisibility } from '@nextgen-web-framework/all';

export const useFeatureFlag = () => {
  const cartOverrideFlag = useFeatureVisibility?.('cart.cartoverride') ?? true;
  const cartSelectionFlag = useFeatureVisibility?.('purchase.cartselection') ?? false;
  const showTaxFlag = useFeatureVisibility?.('cart.enable.show.tax') ?? false;
  const checkoutV2SegmentationFlag = useFeatureVisibility('checkout.segmentation.v2.integration.enable') ?? null;
  const showProxyConsentFlag = useFeatureVisibility('cart.enable.show.proxyConsent') ?? false;
  const newAddressApiFlag = useFeatureVisibility('checkout.new.address.api.support') ?? false;
  const hideSilentPromoFlag = useFeatureVisibility('cart.enable.hide.silentPromotion') ?? false;

  return {
    cartOverrideFlag,
    cartSelectionFlag,
    showTaxFlag,
    checkoutV2SegmentationFlag,
    showProxyConsentFlag,
    newAddressApiFlag,
    hideSilentPromoFlag,
  };
};
