import { Modal, useTranslation } from '@nextgen-web-framework/all';
import {
  Cart,
  cartApi,
  CartConstantsEnum,
  CartEvents,
  CartEventsEnum,
  updateCart,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { StorageService } from '@nextgen-web-framework/core';
type InstallmentWarningModalProps = {
  setShowInstallmentWarningModal: React.Dispatch<React.SetStateAction<boolean>>;
  onInstallmentRemove?: () => void;
};

export const InstallmentWarningModal = ({
  setShowInstallmentWarningModal,
  onInstallmentRemove,
}: InstallmentWarningModalProps) => {
  const t = useTranslation();

  const dispatch = useDispatch();
  const handleClearCart = () => {
    const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    cartApi
      .clearCartEntries({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: cartId,
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart: res,
            cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
          },
          sync: true,
        });
        setShowInstallmentWarningModal(false);
        onInstallmentRemove();
      })
      .catch(() => {});
  };
  const accountCancelText = t('cart.addToCartDrawer.accountCancel');
  return (
    <Modal
      headline={t('cart.cartSwitchBanner.containsInstallment')}
      primaryButtonLabel={t('cart.cartSwitchBanner.removeItems')}
      secondaryButtonLabel={accountCancelText}
      onSecondaryButtonClick={() => setShowInstallmentWarningModal(false)}
      onPrimaryButtonClick={handleClearCart}
      closeIcon={false}
    >
      <>{t('cart.cartSwitchBanner.containsInstallmentDesc')}</>
    </Modal>
  );
};
