import { useState, useRef, useCallback, useEffect, ReactNode, SetStateAction, Dispatch } from 'react';
import {
  CardRadioButton,
  Drawer,
  Input,
  FAIcon,
  InputTypes,
  MLPVersion,
  Theme,
  useTranslation,
  InputValidations,
} from '@nextgen-web-framework/all';
import {
  ExceptionsEnum,
  getAllExceptionWithSeverity,
  Severity,
  type InitialCartState,
  cartApi,
  ApiProjections,
  CartConstantsEnum,
  KeyboardKeys,
  isProxyOrder,
  AmwayUserDetailsStatusEnum,
  SubCartDetail,
  SWITCH_PROXY_TYPE,
  switchCartNewStrategy,
  isGroupOrder,
  type AmwayUserDetails,
} from '@commerce-cart-webcomponents/sdk';
import { type AppState, StorageService } from '@nextgen-web-framework/core';
import { useSelector } from 'react-redux';
import { useCartNotification } from '../../../../common/hooks/useCartNotification';
import { CartNotificationTheme } from '../../../../common/components/cart-notification/types/enums';
import { TOAST_TIMEOUT } from '../../../types/enums';
import { DownlineSearchLoader } from '../../cart-loader/downline-search-loader/DownlineSearchLoader';
import { useFeatureFlag } from '../../../hooks/useFeatureFlag';
import { EmptyCart } from '../../../../components/empty-cart/EmptyCart';
import styles from './DrawerForm.module.scss';

export type DrawerFormProps = {
  onDrawerClose?: () => void;
  headerTitle?: string;
  inputPlaceHolderText?: string;
  onTextChange?: (e: React.ChangeEvent<HTMLInputElement>) => void;
  data: AmwayUserDetails[];
  checkedIndex?: number;
  onRadioChange: (account: AmwayUserDetails, index: number) => void;
  resultTitle?: string;
  subHeading?: string;
  showLoader?: boolean;
  interSectionObserverCallBack?: (text: string) => void;
  onKeyDown?: (e: React.KeyboardEvent<HTMLInputElement>) => void;
  onSearchClick?: (e: React.MouseEvent<HTMLSpanElement, MouseEvent>) => void;
  showActiveCarts?: boolean;
  showDisableCards?: boolean;
  showNoResultText?: boolean;
  modalConfirmClick?: (switchCartType?: SWITCH_PROXY_TYPE, profile?: AmwayUserDetails) => void;
  showSwitchModal?: boolean;
  isSopEntryExist?: boolean;
  isInstallmentExist?: boolean;
  onClose?: () => void;
  drawerFooter?: ReactNode;
  setIsInputError?: Dispatch<SetStateAction<boolean>>;
};

export function DrawerForm({
  onDrawerClose,
  headerTitle,
  inputPlaceHolderText,
  onTextChange,
  data = [],
  checkedIndex,
  onRadioChange,
  resultTitle,
  interSectionObserverCallBack,
  onKeyDown,
  onSearchClick,
  showLoader,
  subHeading,
  showActiveCarts = false,
  showDisableCards = true,
  showNoResultText = false,
  modalConfirmClick,
  showSwitchModal = false,
  isSopEntryExist,
  isInstallmentExist,
  onClose,
  drawerFooter = '',
  setIsInputError,
}: DrawerFormProps) {
  const t = useTranslation();
  const observer = useRef<IntersectionObserver>();
  const [inputText, setInputText] = useState<string>('');
  const [showResults, setShowResults] = useState<boolean>(true);
  const [searchIconClick, setSearchIconClick] = useState<boolean>(false);
  const [subCartsByUser, setSubCartsByUser] = useState<SubCartDetail[]>([]);
  const { createToast, deleteToast } = useCartNotification('DrawerForm');
  const accoutExceptionText = t('cart.addToCartDrawer.accountException');
  const enterAtleast3Char = t('cart.drawerForm.enterAtleast3Char');
  const [inputError, setInputError] = useState<boolean>(false);
  const { cartOverrideFlag, showProxyConsentFlag } = useFeatureFlag();
  const [newIndex, setNewIndex] = useState(-1);

  const [switchCartRadioButtonSelection, setSwitchCartRadioButtonSelection] = useState<SWITCH_PROXY_TYPE>();
  const [showModal, setShowModal] = useState(false);

  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { cart }: InitialCartState = commerceCartState;
  const noResultFoundText = t('cart.DrawerForm.noResultFound');
  const proxyModalHeadLine = t('cart.DrawerForm.proxyModalHeadLine');
  const subTextOverride = t('cart.DrawerForm.subTextOverride');
  const subTextOverrideSOP = t('cart.DrawerForm.subTextOverrideWithSOP');
  const subTextOverrideInstalments = t('cart.DrawerForm.subTextOverrideWithInstallment');
  const subTextSwitch = t('cart.DrawerForm.subTextSwitch');
  const overrideDescription = t('cart.DrawerForm.overrideDescription');
  const switchDescription = t('cart.DrawerForm.switchDescription');
  const noResultFoundTextJp = t('cart.DrawerForm.noResultFoundJp');

  const getOverrideText = () => {
    if (isSopEntryExist) {
      return subTextOverrideSOP;
    }

    if (isInstallmentExist) {
      return subTextOverrideInstalments;
    }

    return subTextOverride;
  };

  useEffect(() => {
    const localCartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);

    if (showActiveCarts && localCartId) {
      cartApi
        .getSubCart({
          cartId: localCartId,
          subCartId: localCartId,
          projections: ApiProjections.FULL,
          options: {
            skipCartResStoreInLS: true,
            skipCartIdStoreInLS: true,
            skipVersionStoreInLS: true,
          },
        })
        .then((res) => {
          const { subCarts } = res;
          const filteredSubCart = subCarts.filter(({ subCartId }) => subCartId !== localCartId);
          setSubCartsByUser(filteredSubCart);
        });
    }
  }, []);

  useEffect(() => {
    if (!switchCartRadioButtonSelection) {
      return;
    }
    modalConfirmClick?.(switchCartRadioButtonSelection, data[newIndex] ?? subCartsByUser[newIndex]?.amwayUser);
  }, [switchCartRadioButtonSelection]);
  useEffect(() => {
    if (inputText !== '') {
      setShowResults(true);
    } else {
      setShowResults(false);
      setSearchIconClick(false);
    }
    if (inputText.length <= 3) {
      setSearchIconClick(false);
    }
  }, [inputText]);

  useEffect(() => {
    if (inputError !== undefined) {
      setIsInputError?.(inputError);
    }
    if (inputText.length === 0) {
      setIsInputError?.(true);
    }
  }, [inputError, inputText, setIsInputError]);

  const lastElement = useCallback((node: Element) => {
    if (interSectionObserverCallBack) {
      if (observer.current) {
        observer.current.disconnect();
      }

      observer.current = new IntersectionObserver(
        (entries) => {
          if (entries[0].isIntersecting) {
            interSectionObserverCallBack(inputText);
          }
        },
        {
          rootMargin: '5px',
        },
      );

      if (node) {
        observer.current.observe(node);
      }
    }
  }, []);

  const handleInputChanged = (e: React.ChangeEvent<HTMLInputElement>) => {
    const inputFiltered = e.target.value;
    const trimmedText = inputFiltered.trimEnd().trimStart();
    setInputError(false);
    const accountException = getAllExceptionWithSeverity(
      [ExceptionsEnum.Exceptions.AccountSearchService],
      Severity.Warn,
      cart.errors ?? [],
    );

    if (accountException?.length) {
      createToast(
        {
          theme: CartNotificationTheme.RED,
          rightSeperator: false,
          content: accoutExceptionText,
          clickIcon: 'times',
          icon: 'exclamation-square',
          timeOut: TOAST_TIMEOUT,
        },
        deleteToast,
      );

      return;
    }

    setInputError(trimmedText.length < 3 && trimmedText.length > 0);
    if (onTextChange) {
      onTextChange(e);
    }
    setInputText(inputFiltered);
  };

  const drawerOnCrossHandler = () => {
    setInputText('');
    if (onDrawerClose) {
      onDrawerClose();
    }
  };

  const handleSubCartSearchIcon = (e: React.MouseEvent<HTMLSpanElement, MouseEvent>) => {
    if (!validateInput()) {
      return;
    }
    if (onSearchClick) {
      onSearchClick(e);
    }
    setSearchIconClick(true);
  };

  const handleSubCartSearchKey = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (onKeyDown) {
      onKeyDown(e);
    }
    if (e.key === KeyboardKeys.ENTER) {
      if (!validateInput()) {
        return;
      }
      setSearchIconClick(true);
    }
  };

  // Validate Input
  const validateInput = () => {
    setInputError(inputText.length < 3);
    return inputText.length >= 3;
  };

  const onCardRadioClick = (index?: number, selectedProfile?: AmwayUserDetails) => {
    setNewIndex(index as number);
    if (showSwitchOrOverrideModal(index) && !switchCartNewStrategy() && !cartOverrideFlag) {
      setShowModal(true);
      return;
    }
    onRadioChange?.(selectedProfile as AmwayUserDetails, index as number);
  };

  const renderAccounts = () => {
    if (data.length > 0 && showResults && (searchIconClick || inputText.length >= 3)) {
      return (
        <div className={styles['account-name-container-results']} data-testid="drawer-test-result">
          <div className={styles['account-name-container-results-title']}>{resultTitle}</div>
          <div className={styles['account-name-container-results-wrapper']}>
            {data.map(({ amwayUserId, accountId, primaryName, status, allowUplineForProxyOrder }, i) => {
              const checkedClass = checkedIndex === i ? styles['result-checked'] : '';
              const isAccountIdExist = cart.subCarts?.find((subcart) => subcart.amwayUser?.accountId === accountId);
              const disableCard = showDisableCards ? !!isAccountIdExist : false;
              const isProxyOrderDisabled = showProxyConsentFlag && !allowUplineForProxyOrder;
              if (i === data.length - 1) {
                return (
                  <div ref={lastElement as React.LegacyRef<HTMLDivElement>} className={checkedClass} key={accountId}>
                    <CardRadioButton
                      disabled={disableCard || status === AmwayUserDetailsStatusEnum.Inactive || isProxyOrderDisabled}
                      checked={checkedIndex === i}
                      mlpVersion={MLPVersion.ONE}
                      label={primaryName}
                      name="account-number-or-name"
                      cardDescription={`${t('cart.cartEllipsesMenu.accountNum')} ${accountId}`}
                      onChange={() => onCardRadioClick(i, { amwayUserId, accountId, primaryName, status })}
                      data-testid="drawer-search-result-item"
                      divider={true}
                    >
                      {isProxyOrderDisabled && (
                        <div className={styles['proxyUnavailable']}>{t('cart.cartSwitchBanner.proxyUnavailable')}</div>
                      )}
                    </CardRadioButton>
                  </div>
                );
              }
              return (
                <div className={checkedClass} key={accountId}>
                  <CardRadioButton
                    disabled={disableCard || status === AmwayUserDetailsStatusEnum.Inactive || isProxyOrderDisabled}
                    checked={checkedIndex === i}
                    mlpVersion={MLPVersion.ONE}
                    label={primaryName}
                    name="account-number-or-name"
                    cardDescription={`${t('cart.cartEllipsesMenu.accountNum')} ${accountId}`}
                    onChange={() => onCardRadioClick(i, { amwayUserId, accountId, primaryName, status })}
                    data-testid="drawer-search-result-item"
                    divider={true}
                  >
                    {isProxyOrderDisabled && (
                      <div className={styles['proxyUnavailable']}>{t('cart.cartSwitchBanner.proxyUnavailable')}</div>
                    )}
                  </CardRadioButton>
                </div>
              );
            })}
          </div>
        </div>
      );
    }

    if (showNoResultText) {
      //use showProxyConsentFlag for japan to render no result found
      return showProxyConsentFlag ? (
        <EmptyCart
          imgSrc="/images/NoSearchResult.svg"
          cartEmptyTxt1={noResultFoundTextJp}
          showCartEmptyBtn={false}
          fromDrawer={true}
        />
      ) : (
        <div className={styles['no-result-found-text']}>{noResultFoundText.replace('{0}', inputText)}</div>
      );
    }

    return <></>;
  };

  const showActivesCart = () =>
    showActiveCarts &&
    !!subCartsByUser.length &&
    !data.length &&
    !showLoader &&
    inputText.length === 0 &&
    (switchCartNewStrategy() ? isGroupOrder(cart.orderType) : true);

  const showSwitchOrOverrideModal = (index?: number) => {
    const activeIndex = (index ?? checkedIndex) as number;
    if (typeof checkedIndex === 'number') {
      if (data.length) {
        //when switching to subcarts from search
        return !!subCartsByUser.find(
          ({ amwayUser, entries }) =>
            (amwayUser?.amwayUserId === data[activeIndex]?.amwayUserId && entries?.length) ||
            (!data[activeIndex] && amwayUser?.amwayUserId && entries?.length),
        );
      } else {
        //when switching to subcarts from recent carts
        const updatedCart = subCartsByUser[activeIndex];
        return !!updatedCart?.entries?.length;
      }
    }

    return false;
  };

  const showOverrideDrawer = showSwitchModal && showModal && !cartOverrideFlag;

  return (
    <>
      {showOverrideDrawer && (
        <Drawer closeOnBackdropClick onClose={onClose} header={proxyModalHeadLine}>
          <div className={styles['card-radio-button']}>
            <CardRadioButton
              onChange={() => setSwitchCartRadioButtonSelection(SWITCH_PROXY_TYPE.OVERRIDE)}
              checked={switchCartRadioButtonSelection === SWITCH_PROXY_TYPE.OVERRIDE}
              divider={true}
              data-testid="card-radio-override-id"
              cardDescription={overrideDescription}
            >
              <span className={styles['card-radio-button-subtext']}>{getOverrideText()}</span>
            </CardRadioButton>

            <CardRadioButton
              onChange={() => setSwitchCartRadioButtonSelection(SWITCH_PROXY_TYPE.SWITCH)}
              checked={switchCartRadioButtonSelection === SWITCH_PROXY_TYPE.SWITCH}
              divider={true}
              data-testid="card-radio-switch-id"
              cardDescription={switchDescription}
            >
              <span className={styles['card-radio-button-subtext']}>{subTextSwitch}</span>
            </CardRadioButton>
          </div>
        </Drawer>
      )}
      {!showOverrideDrawer && (
        <Drawer
          closeOnBackdropClick={true}
          closeIcon={true}
          bottomGap={0}
          onClose={drawerOnCrossHandler}
          header={
            <div
              className={`${showProxyConsentFlag ? '' : styles['drawer-header-title']}`}
              data-testid="drawer-header-txt"
            >
              {headerTitle}
            </div>
          }
          footer={drawerFooter}
          useReactPortal={!showModal}
          portalContainerId={'react-portal-drawer'}
        >
          <div data-testid="account-name-container-testid" className={styles['account-name-container']}>
            <div>
              {!!subHeading && <span className={styles['account-name-search-sub-heading']}>{subHeading}</span>}
              <div className={styles['account-name-search']}>
                <Input
                  type={!showProxyConsentFlag ? InputTypes.TEXT : InputTypes.NUMBER}
                  inputMode={!showProxyConsentFlag ? 'text' : 'numeric'}
                  maxLength={11}
                  pattern={!showProxyConsentFlag ? null : '[0-9]*'}
                  label={inputPlaceHolderText}
                  mlpVersion={MLPVersion.TWO}
                  value={inputText}
                  onChange={handleInputChanged}
                  onKeyDown={(e) => {
                    handleSubCartSearchKey(e);
                  }}
                  name="account-name-or-number"
                  className={styles['account-name-search-input']}
                  data-testid="drawer-search-input"
                  status={
                    inputError && inputText.trimEnd().trimStart().length < 3
                      ? InputValidations.INVALID
                      : InputValidations.DEFAULT
                  }
                  message={
                    inputError &&
                    inputText.trimEnd().trimStart().length < 3 &&
                    inputText.trimEnd().trimStart().length > 0
                      ? enterAtleast3Char
                      : ''
                  }
                />
                <FAIcon
                  iconName="search"
                  theme={Theme.BLACK}
                  className={styles['account-name-search-icon']}
                  onClick={(e) => handleSubCartSearchIcon(e)}
                  data-testid="drawer-search-icon"
                />
              </div>
            </div>
            {showActivesCart() && (
              <div className={styles['account-name-container-results']}>
                <div className={styles['account-name-container-results']}>
                  <div className={styles['account-name-container-results-title']}>
                    {t('cart.drawerForm.recentCarts')}
                  </div>
                  <div className={styles['account-name-container-results-wrapper']}>
                    {subCartsByUser.map(({ subCartId, amwayUser, proxySubCart }, i) => {
                      const isDisabled = showProxyConsentFlag && !amwayUser?.allowUplineForProxyOrder;
                      return (
                        <CardRadioButton
                          disabled={
                            (isProxyOrder(cart.orderType) && proxySubCart) ||
                            amwayUser?.status === AmwayUserDetailsStatusEnum.Inactive ||
                            isDisabled
                          }
                          key={subCartId}
                          checked={checkedIndex === i}
                          mlpVersion={MLPVersion.ONE}
                          label={amwayUser?.primaryName ?? ''}
                          name="account-number-or-name"
                          onChange={() => onCardRadioClick(i, amwayUser)}
                          cardDescription={`${t('cart.cartEllipsesMenu.accountNum')} ${amwayUser?.accountId}`}
                          divider={true}
                        >
                          {isDisabled && (
                            <div className={styles['proxyUnavailable']}>
                              {t('cart.cartSwitchBanner.proxyUnavailable')}
                            </div>
                          )}
                        </CardRadioButton>
                      );
                    })}
                  </div>
                </div>
              </div>
            )}
            {showLoader ? <DownlineSearchLoader /> : renderAccounts()}
          </div>
        </Drawer>
      )}
    </>
  );
}
