import { SearchCard } from '@commerce-product-webcomponents/ui';
import { Carousel, TextLink, TextLinkStyle, useSession, useTranslation } from '@nextgen-web-framework/all';
import { AppDispatch, AppState } from '@nextgen-web-framework/core';
import { IProduct } from '@commerce-product-webcomponents/sdk';
import { useDispatch, useSelector } from 'react-redux';
import {
  ApiProjections,
  ErrorAPI,
  ListEntry,
  ListResponse,
  ListType,
  myListApi,
  UserListResponse,
  updateSavedForLaterList,
  InitialCartListState,
} from '@commerce-cart-webcomponents/sdk';
import {
  CartNotificationTheme,
  TOAST_TIMEOUT,
  useCartNotification,
  useExceptionToast,
} from '@commerce-cart-webcomponents/ui';
import { useEffect } from 'react';
import styles from './SavedForLater.module.scss';
import { MoveToCart } from './move-to-cart/MoveToCart';

const SavedForLater = () => {
  const t = useTranslation();
  const { savedForLaterList }: InitialCartListState = useSelector((state: AppState) => state.commerceMyList);
  //const [productList, setProductList] = useState<ListResponse>(savedForLaterList);
  const triggerToast = useExceptionToast();
  const { isAnonymous } = useSession();
  const dispatch = useDispatch<AppDispatch>();
  const { createToast, deleteToast } = useCartNotification('savedForLater');

  useEffect(() => {
    if (!isAnonymous()) {
      myListApi
        .getListsByUser({
          projections: ApiProjections.DETAILED,
          listType: ListType.Savedforlater,
          page: '0',
        })
        .then((res: UserListResponse) => {
          //setProductList(res.lists[0]);
          dispatch(updateSavedForLaterList(res.lists[0]));
        });
    }
  }, []);

  const addToList = (entry: ListEntry, listVersion: number, toastId: string) => {
    myListApi
      .addToList([
        {
          version: listVersion ?? savedForLaterList?.version,
          listId: savedForLaterList?.listId,
          entries: [
            {
              product: {
                id: entry?.product.id,
              },
              quantity: entry?.quantity,
              bundleSlots: entry?.bundleSlots,
            },
          ],
        },
      ])
      .then((res: UserListResponse) => {
        deleteToast(toastId);
        // setProductList(res.lists[0]);
        dispatch(updateSavedForLaterList(res));
      })
      .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
  };

  const removeEntryfromList = (entry: ListEntry, isRemoved: boolean) => {
    myListApi
      .removeEntryFromList({
        entryId: [entry?.entryId],
        listId: savedForLaterList?.listId,
      })
      .then((res: ListResponse) => {
        // setProductList(res);
        dispatch(updateSavedForLaterList(res));
        if (isRemoved) {
          createToast(
            {
              theme: CartNotificationTheme.GREEN,
              content: t('cart.savedForLater.itemsDeleted'),
              textlink: t('cart.cartLineItem.undo'),
              timeOut: TOAST_TIMEOUT,
            },
            (id: string) => addToList(entry, res?.version, id),
          );
        }
      })
      .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
  };

  if (!savedForLaterList?.payLoad?.entries?.length) {
    return <></>;
  }

  return (
    <div className={styles['saved-for-later-container']}>
      <div className={styles['saved-for-later-title']}>{`${t('cart.savedForLater.savedForLater')} (${
        savedForLaterList?.payLoad?.entries?.length
      })`}</div>
      <Carousel isTileCarousel={true}>
        {savedForLaterList?.payLoad?.entries?.map((entry: ListEntry) => {
          const { product } = entry;
          return (
            <div key={entry.entryId} className={styles['saved-for-later']}>
              <SearchCard
                key={entry.entryId}
                productData={
                  {
                    ...product,
                    brandName: product.brand,
                    displayTitle: product.name,
                    productPrice: entry.totalPrice?.value,
                    currency: entry.totalPrice?.currency,
                    productId: product.id,
                    mainLink: product.cartIconPublicUrl,
                    alt: product.cartIconAltText,
                    derivedAvailabilityStatus: product.derivedAvailabilityStatus,
                    pointValue: entry.totalPrice.amwayValue.pointValue,
                    businessVolume: entry.totalPrice.amwayValue.businessVolume,
                    firstAvailableFutureDate:
                      product?.firstAvailableFutureDate && String(product.firstAvailableFutureDate),
                    showPrefix: false,
                    showSubText: true,
                  } as unknown as IProduct
                }
                className={styles['search-card']}
                disabled={false}
                entryObj={{ productId: entry.product.id, entryId: entry?.entryId }}
                showPropertiesCollection={{
                  showAddToCartButtonComp: false,
                  showProductIdAndSizeComp: false,
                }}
              />
              <div className={styles['buttons']}>
                <MoveToCart
                  cartEntry={entry}
                  onMoveToCartClick={() => removeEntryfromList(entry, false)}
                  sopMetaDataRes={savedForLaterList?.payLoad?.sopMetaData}
                />
                <TextLink
                  text={t('cart.savedForLater.delete')}
                  onClick={() => removeEntryfromList(entry, true)}
                  textLinkStyle={TextLinkStyle.UNDERLINE}
                />
              </div>
            </div>
          );
        })}
      </Carousel>
    </div>
  );
};

export { SavedForLater };
