import {
  cartApi,
  updateCart,
  type Cart,
  CartConstantsEnum,
  CartEventsEnum,
  PublishEvent,
  CartEntryDetails,
  myListApi,
  ListResponse,
  ErrorAPI,
  updateSavedForLaterList,
  InitialCartListState,
  ListType,
  UserListResponse,
  ListBundleSlot,
  SopElementResponse,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch, useSelector } from 'react-redux';
import { useTranslation } from '@nextgen-web-framework/all';
import { AppState, StorageService } from '@nextgen-web-framework/core';
import { CartNotificationTheme } from '../components';
import { TOAST_TIMEOUT } from '../types/enums';
import { useCartNotification } from './useCartNotification';
import { useExceptionToast } from './useExceptionToast';

export const useBuyLater = () => {
  const t = useTranslation();
  const { savedForLaterList }: InitialCartListState = useSelector((state: AppState) => state.commerceMyList);
  const { createToast, deleteToast } = useCartNotification('savedForLater');
  const savedForLaterMsg = t('cart.savedForLater.savedForLaterMsg');
  const dispatch = useDispatch();
  const triggerToast = useExceptionToast();

  const buyLater = (entry: CartEntryDetails, sopMetaResponse?: SopElementResponse[]) => {
    let listValue = {} as ListResponse;
    if (!savedForLaterList?.listId) {
      myListApi
        .createList({
          name: ListType.Savedforlater,
          listType: ListType.Savedforlater,
          entries: [],
          description: ListType.Savedforlater,
          category: ListType.Savedforlater,
        })
        .then((res: ListResponse) => {
          listValue = res;
          dispatch(updateSavedForLaterList(res));
        });
    }
    myListApi
      .addToList([
        {
          version: savedForLaterList?.version ?? listValue?.version ?? 0,
          listId: savedForLaterList?.listId ?? listValue?.listId ?? '',
          entries: [
            {
              product: {
                id: entry?.product.id,
              },
              quantity: entry?.quantity,
              bundleSlots: entry?.bundleSlots as ListBundleSlot.BundleSlot[],
              ...(entry?.sopMappingKey && { sopMappingKey: entry.sopMappingKey }),
            },
          ],
          ...(entry?.sopMappingKey && sopMetaResponse && { sopMetaData: sopMetaResponse }),
        },
      ])
      .then((res: UserListResponse) => {
        dispatch(updateSavedForLaterList(res.lists[0]));
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: savedForLaterMsg,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
      })
      .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
  };

  const changeToStandardOrder = (entry: CartEntryDetails) => {
    const entriesPayload = [
      {
        product: {
          id: entry?.product.id,
        },
        quantity: entry?.quantity,
      },
      {
        sopMappingKey: entry?.sopMappingKey,
        entryId: entry?.entryId,
        product: {
          id: entry?.product.id,
        },
        quantity: 0,
      },
    ];
    cartApi
      .updateCartEntries({
        cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        subCartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
        payload: {
          subCarts: [
            {
              subCartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
              entries: entriesPayload,
            },
          ],
          version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
        },
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        PublishEvent({
          cartEvent: CartEventsEnum.UpdateMiniCartIcon,
          cart: res as Cart,
        });
      });
  };

  return { buyLater, changeToStandardOrder };
};
