import { Button, ButtonWidth, useTranslation } from '@nextgen-web-framework/all';
import { BundleSlot, ListEntry, SopElement } from '@commerce-cart-webcomponents/sdk';
import {
  DerivedAvailabilityStatusComponentGroupKey,
  includesDerivedAvailabilityStockStatus,
} from '@commerce-product-webcomponents/ui';
import { useAddToCart } from '../../add-to-cart-button/hook/useAddToCart';

export type MoveToCartProps = {
  cartEntry: ListEntry;
  sopMetaDataRes?: SopElement[];
  onMoveToCartClick: () => void;
};

const MoveToCart = ({ cartEntry, onMoveToCartClick, sopMetaDataRes }: MoveToCartProps) => {
  const t = useTranslation();
  const { product, quantity, bundleSlots } = cartEntry;
  const successMsg = t('cart.savedForLater.itemsMoveToCart');
  const { addToCart } = useAddToCart({
    entryObj: {
      productId: product?.id,
      quantity: quantity,
      bundleSlots: bundleSlots as BundleSlot[],
    },
    addToCartSuccessMsg: successMsg,
    sopMappingKey: cartEntry?.sopMappingKey,
    sopMetaDataRes,
  });

  return (
    <Button
      title={t('cart.savedForLater.moveToCart')}
      disabled={
        product?.flags?.restrictFromAddToCart ||
        includesDerivedAvailabilityStockStatus(
          product?.derivedAvailabilityStatus || '',
          DerivedAvailabilityStatusComponentGroupKey.CTA_DISABLED_STATUSES,
        )
      }
      onClick={(event: React.MouseEvent<HTMLSpanElement, MouseEvent>) => {
        addToCart(event);
        onMoveToCartClick();
      }}
      buttonWidth={ButtonWidth.FULL_WIDTH}
    />
  );
};

export { MoveToCart };
