import { Modal, useTranslation } from '@nextgen-web-framework/all';
import {
  Cart,
  cartApi,
  CartConstantsEnum,
  CartEntryDetails,
  CartEvents,
  CartEventsEnum,
  updateCart,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { StorageService } from '@nextgen-web-framework/core';
type SOPWarningModalProps = {
  setShowSOPWarningModal: React.Dispatch<React.SetStateAction<boolean>>;
  onSOPRemove?: () => void;
  // setShowAccountDrawer?: React.Dispatch<React.SetStateAction<boolean>>;
  cartEntries: CartEntryDetails[];
};

export const SOPWarningModal = ({
  setShowSOPWarningModal,
  onSOPRemove,
  // setShowAccountDrawer,
  cartEntries,
}: SOPWarningModalProps) => {
  const t = useTranslation();

  const dispatch = useDispatch();
  const removeSOPHandler = () => {
    const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    const entryIds = cartEntries.filter((entry) => entry?.sopMappingKey).map((entry) => entry?.entryId);
    // setShowAccountDrawer(true);

    cartApi
      .removeEntryFromCart({
        cartId: cartId,
        subCartId: cartId,
        entryId: encodeURIComponent(entryIds.join(',')),
      })
      .then((res) => {
        dispatch(updateCart(res as Cart));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart: res,
            cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
          },
          sync: true,
        });
        setShowSOPWarningModal(false);
        onSOPRemove();
      })
      .catch(() => {});
  };

  const accountCancelText = t('cart.addToCartDrawer.accountCancel');
  return (
    <Modal
      headline={t('cart.cartSwitchBanner.containsSOP')}
      primaryButtonLabel={t('cart.cartSwitchBanner.removeItems')}
      secondaryButtonLabel={accountCancelText}
      onSecondaryButtonClick={() => setShowSOPWarningModal(false)}
      onPrimaryButtonClick={removeSOPHandler}
      closeIcon={false}
    >
      <div style={{ textAlign: 'left' }}>{t('cart.cartSwitchBanner.containsSOPDesc')}</div>
    </Modal>
  );
};
