import { FreeProductCard } from '@commerce-product-webcomponents/ui';
import { CartEntryDetails, getStockStatus, isSellableCheck } from '@commerce-cart-webcomponents/sdk';

import styles from '../CartLineItems.module.scss';

type RenderAuxiliaryProductsType = (id: string, withoutSOPEntry: CartEntryDetails[]) => React.JSX.Element | null;

export const RenderAuxiliaryProducts: RenderAuxiliaryProductsType = (id, withoutSOPEntry) => {
  const auxiliaryProducts: CartEntryDetails[] = [];
  const receivedEntries = withoutSOPEntry.filter(
    (entry) =>
      entry?.product?.isAuxiliary && entry?.qualifyingItemIds?.length === 1 && entry?.qualifyingItemIds?.[0] === id,
  );

  if (receivedEntries) {
    auxiliaryProducts.push(...receivedEntries);
  }

  if (!auxiliaryProducts.length) {
    return null;
  }

  return (
    <>
      {auxiliaryProducts.map((entry) => {
        const { product, totalPrice } = entry;
        return (
          <div
            key={entry.entryId}
            className={styles['commerce-cart-line-item-product']}
            data-testid="product-card-test-id"
          >
            <FreeProductCard
              className={styles['cart-free-product-card']}
              brandName={product?.brand ?? ''}
              productName={product?.name ?? ''}
              link={product?.cartIconPublicUrl ?? ''}
              alt={product?.cartIconAltText ?? ''}
              productId=""
              productPrice={totalPrice?.value as number}
              currency={totalPrice?.currency as string}
              productSize=""
              derivedAvailabilityStatus={getStockStatus(entry)}
              showSubText={false}
              productQuantity={entry?.quantity}
              isSopBenefit={false}
              showLinkForProductCard={!isSellableCheck(product) && !product.isAuxiliary}
              showDispositionHandler={false}
              showPromotionTag={entry?.enablePromotionTag}
              firstAvailableFutureDate={product?.firstAvailableFutureDate && String(product.firstAvailableFutureDate)}
            />
          </div>
        );
      })}
    </>
  );
};
