import { AnyAction, AsyncThunk, createAsyncThunk, createSlice, PayloadAction } from '@reduxjs/toolkit';
import type { AppDispatch } from '@nextgen-web-framework/core';
import { RenewalNudgeType } from '@commerce-profile-webcomponents/sdk';
import type {
  InitialCartState,
  ChangeQtyCartType,
  AddToCartReqPayloadType,
  CartIdReqPayloadType,
  ProjectionReqPayloadType,
  CreateCartPayloadType,
} from '../../types';
import { cartApi } from '../requests/cartApi';
import { OrderType, SubCartDetail, type Cart, type ErrorResponseSubDetailsInner } from '../models';
import { CartAPIResponse, CartIdWithMultipleEntryIdType, SubCartIdReqPayloadType } from '../../types/cartTypes';

type GenericAsyncThunk = AsyncThunk<
  CartAPIResponse,
  unknown,
  {
    dispatch: AppDispatch; // this is store.dispatch
    state: InitialCartState; // this is
  }
>;
type PendingAction = ReturnType<GenericAsyncThunk['pending']>;
type RejectedAction = ReturnType<GenericAsyncThunk['rejected']>;
type FulfilledAction = ReturnType<GenericAsyncThunk['fulfilled']>;

function isPendingGenericAction(action: AnyAction): action is PendingAction {
  return action.type.startsWith('commerceCart') && action.type.endsWith('/pending');
}

function isFulfilledAction(action: AnyAction): action is FulfilledAction {
  return action.type.startsWith('commerceCart') && action.type.endsWith('/fulfilled');
}

function isRejectedAction(action: AnyAction): action is RejectedAction {
  return action.type.startsWith('commerceCart') && action.type.endsWith('/rejected');
}

