const initialState: InitialCartState = {
  cart: {
    id: '',
    amwayUser: {
      amwayUserId: '',
    },
    version: 0,
    orderType: OrderType.Regular,
    subCarts: [],
    metaData: {
      createdAt: new Date('2024-01-10T12:12:00Z'),
    },
  },
  cartCheckoutData: {
    subCarts: [],
  },
  isLoading: true,
  isApiInProgress: false,
  hasError: false,
  hasCartIdInStore: false,
  error: {},
  isBlockerException: false,
  isCheckoutDisabled: true,
  isQuantityStepperInFocus: false,
  redirectToHomePage: false,
  renewalFlagsData: {
    showRenewalNudge: false,
    isAutoRenewalEnabled: false,
    isAutoRenewalFailed: false,
    isLastGraceMonth: false,
    expiryDate: '',
    rawExpiryDate: '',
    inactiveDate: '',
    renewalStartDate: '',
    canRenew: false,
    canUpgrade: false,
    canDowngrade: false,
    mustRenew: false,
    canLateRenew: false,
  },
};

export const cartSlice = createSlice({
  name: 'commerceCart',
  initialState,
  reducers: {
    resetCartSlice: () => initialState,
    hasCartIdInStore: (state, action: PayloadAction<boolean>) => {
      state.hasCartIdInStore = action.payload;
    },
    updateCart: (state, action: PayloadAction<Cart>) => {
      state.cart = action.payload;
    },
    updateCartCheckoutData: (
      state,
      action: PayloadAction<{
        subCarts: SubCartDetail[];
      }>,
    ) => {
      state.cartCheckoutData = action.payload;
    },
    updateIsLoading: (state, action: PayloadAction<boolean>) => {
      state.isLoading = action.payload;
    },
    updateIsApiInProgress: (state, action: PayloadAction<boolean>) => {
      state.isApiInProgress = action.payload;
    },
    updateBlockerException: (state, action: PayloadAction<boolean>) => {
      state.isBlockerException = action.payload;
    },
    updateIsCheckoutDisabled: (state, action: PayloadAction<boolean>) => {
      state.isCheckoutDisabled = action.payload;
    },
    updateIsQuantityStepperInFocus: (state, action: PayloadAction<boolean>) => {
      state.isQuantityStepperInFocus = action.payload;
    },
    updateRedirectionToHomePage: (state, action: PayloadAction<boolean>) => {
      state.redirectToHomePage = action.payload;
    },
    updateRenewalFlagsData: (state, action: PayloadAction<RenewalNudgeType>) => {
      state.renewalFlagsData = action.payload;
    },
  },
  extraReducers: (builder) => {
    /**
     * Common reducers
     */
    builder.addMatcher(isRejectedAction, (state: InitialCartState, action: PayloadAction<unknown>) => {
      state.hasError = true;
      state.isLoading = false;
      state.error = action as ErrorResponseSubDetailsInner;
    });
    builder.addMatcher(isFulfilledAction, (state: InitialCartState, action: PayloadAction<unknown>) => {
      state.hasError = false;
      state.cart = action.payload as Cart;
    });
    builder.addMatcher(isPendingGenericAction, (state: InitialCartState) => {
      state.hasError = false;
    });
  },
});

export const {
  hasCartIdInStore,
  resetCartSlice,
  updateCart,
  updateCartCheckoutData,
  updateIsLoading,
  updateIsApiInProgress,
  updateBlockerException,
  updateIsCheckoutDisabled,
  updateIsQuantityStepperInFocus,
  updateRedirectionToHomePage,
  updateRenewalFlagsData,
} = cartSlice.actions;
