import { useEffect, useState } from 'react';
import {
  Drawer,
  Button,
  ButtonWidth,
  TextLink,
  Theme,
  CardCheckbox,
  TextLinkStyle,
  useTranslation,
  ButtonStyles,
  useSession,
  FAIcon,
  useNextgenRouter,
} from '@nextgen-web-framework/all';
import {
  ApiProjections,
  CartEntryDetails,
  CreateListRequest,
  ListEntryRequest,
  ListResponse,
  ListType,
  UpdateListRequest,
  UserListResponse,
  isProductInWishlist,
  myListApi,
  ErrorAPI,
  ListExceptionDetail,
  CartRoutePaths,
  PublishWishlistEvent,
  CartEventsEnum,
  productEntryData,
  getFilteredEntries,
  validateBundleInEntries,
  updateListsByUser,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch } from 'react-redux';
import { GCOProductCard } from '@commerce-product-webcomponents/ui';
import { ConfigService } from '@nextgen-web-framework/core';
import { IProduct } from '@commerce-product-webcomponents/sdk';
import { useCartNotification } from '../../../../common/hooks/useCartNotification';
import { TOAST_TIMEOUT } from '../../../../common/types/enums';
import { CartNotificationTheme } from '../../../../common/components/cart-notification/types/enums';
import { CreateList } from '../create-list/CreateList';
import { CartMobileHeader } from '../../../cart-mobile-header/CartMobileHeader';
import { FrameRectangle } from '../../../../common/components/cart-loader/frame-rectangle/FrameRectangle';
import { AddToListImageLoader } from '../list-loaders/add-to-list-image-loader/AddToListImageLoader';
import { ButtonLoader } from '../../../../common/components';
import { useIntersectionObserver } from '../../../../hooks/useIntersectionObserver';
import { useExceptionToast } from '../../../../common';
import { AddToListDrawerProps } from './types/propsType';
import styles from './AddToListDrawer.module.scss';
import { AddToListDrawerLoader } from './add-to-list-drawer-loader/AddToListDrawerLoader';

const AddToListDrawer = ({
  onDrawerClose,
  heartIconFilledcb,
  isMyShop,
  productData,
  cartEntriesDetails,
  fetchMyShopListsCB,
  bundleSlots = [],
  showCreateListForm = false,
  buttonLoaderCB,
}: AddToListDrawerProps) => {
  const t = useTranslation();
  const dispatch = useDispatch();
  const router = useNextgenRouter();
  const { isABO, isRegistered } = useSession();
  const configs = ConfigService.getConfigs();
  const assetsBasePath = configs.NEXT_ASSETS_BASE_PATH as string;
  const [displayCreateListForm, setDisplayCreateListForm] = useState(showCreateListForm);
  const [listData, setListData] = useState<UserListResponse>({
    lists: [],
  });
  const [createListData, setCreateListData] = useState<CreateListRequest>({
    entries: [],
    name: '',
    description: '',
    category: '',
  });
  const [selectedCheckboxes, setSelectedCheckboxes] = useState<Array<string>>([]);
  const [listCreationInProgress, setListCreationInProgress] = useState(false);
  const [showLoader, setShowLoader] = useState(true);
  const [showButtonLoader, setShowButtonLoader] = useState(false);
  const addedToWishlist = t('cart.addToListToggle.ProductAddedToWishlist');
  const addedToList = t('cart.addToListToggle.ProductAddedToList');
  const changesSaved = t('cart.myshop.changesSaved');
  const { createToast, deleteToast } = useCartNotification('addToList');
  const maxLimitReached = t('cart.createList.maxLimitReached');
  const myshopListCreated = t('cart.myshop.listCreated');
  const pleaseDeleteToCreateNew = t('cart.createList.pleaseDeleteToCreateNew');
  const [currentPage, setCurrentPage] = useState(0);
  const [lastCardCheckbox, setLastCardCheckbox] = useState<HTMLElement | null>();
  const triggerToast = useExceptionToast();
  const prodId = productData?.searchId ?? productData?.productId;

  useEffect(() => {
    myListApi
      .getListsByUser({
        projections: ApiProjections.DETAILED,
        page: currentPage.toString(),
      })
      .then((res: UserListResponse) => {
        const updatedListData = currentPage != 0 ? [...(listData.lists || []), ...(res.lists || [])] : res.lists;

        if (currentPage != 0) {
          setListData((prevData) => ({
            ...prevData,
            lists: [...(prevData?.lists || []), ...(res?.lists || [])],
          }));
        } else {
          setListData(res);
        }

        if (isMyShop) {
          const filteredLists =
            updatedListData?.filter((list) => list.isDisplayedOnShop)?.map((list) => list?.listId ?? '') ?? [];
          setSelectedCheckboxes(filteredLists ?? []);
        }
      })
      .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps))
      .finally(() => setShowLoader(false));
  }, [currentPage]);

  useIntersectionObserver(
    lastCardCheckbox,
    { rootMargin: '1px' },
    () => {
      if (listData?.lists && listData?.listCount !== undefined && listData?.lists.length < listData?.listCount) {
        setCurrentPage(currentPage + 1);
      }
    },
    [listData?.lists?.length ?? 0],
  );

  const addListToMyShop = () => {
    const finalArr: ListResponse[] = [];
    listData.lists?.forEach((list: ListResponse) => {
      if (list.listId) {
        finalArr.push({
          ...list,
          ...list.payLoad,
          isDisplayedOnShop: selectedCheckboxes.includes(list.listId),
        });
      }
    });
    if (finalArr?.length) {
      setShowButtonLoader(true);
      buttonLoaderCB?.(true);
      myListApi
        .updateList(finalArr as UpdateListRequest[])
        .then(() => {
          createToast(
            {
              theme: CartNotificationTheme.SUCCESS,
              rightSeperator: false,
              content: changesSaved,
              clickIcon: 'times',
              icon: 'check-circle',
              timeOut: TOAST_TIMEOUT,
            },
            deleteToast,
          );
        })
        .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps))
        .finally(() => {
          onDrawerClose?.();
          fetchMyShopListsCB?.();
          setShowButtonLoader(false);

          buttonLoaderCB?.(false);
        });
    }
  };

  const onConfirmButtonClick = () => {
    setShowButtonLoader(true);

    buttonLoaderCB?.(true);
    const entriesArray: Array<ListEntryRequest> = [
      {
        product: {
          id: prodId as string,
        },
        quantity: 1,
        bundleSlots,
      },
    ];

    const entriesWithoutRenewal = getFilteredEntries(cartEntriesDetails || [], {
      filterPromotion: false,
      filterSOP: false,
      filterIsAccountFeeProduct: true,
      filterIsAccountKitProduct: true,
      filterUnsellableProduct: true,
      filterAuxiliaryProducts: true,
    });

    const cartEntriesArray = validateBundleInEntries(
      entriesWithoutRenewal?.map((entry: CartEntryDetails) => ({
        product: {
          id: entry?.product.id,
        },
        quantity: entry?.quantity || 1,
        bundleId: '',
        bundleSlots: entry.bundleSlots ?? [],
      })),
    ) as ListEntryRequest[];

    const addToListPayload = selectedCheckboxes.map((checkboxId) => ({
      version: listData?.lists?.find((list) => list.listId === checkboxId)?.version as number,
      listId: checkboxId,
      entries: productData
        ? (validateBundleInEntries(entriesArray as CartEntryDetails[]) as ListEntryRequest[])
        : cartEntriesArray,
    }));

    myListApi
      .addToList(addToListPayload)
      .then((res: UserListResponse) => {
        onDrawerClose?.();
        //Also update all list by user to latest
        myListApi
          .getAllListByUser({
            projections: ApiProjections.FULL,
          })
          .then((res) => dispatch(updateListsByUser(res)))
          .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
        heartIconFilledcb?.(true);
        const productEntry = productEntryData(res, prodId || '');
        PublishWishlistEvent({
          cartEvent: CartEventsEnum.AddToWishlist,
          listEntry: productEntry,
        });
        createToast(
          {
            theme: CartNotificationTheme.SUCCESS,
            rightSeperator: false,
            content: isRegistered() ? addedToWishlist : addedToList,
            clickIcon: 'times',
            icon: 'check-circle',
            timeOut: TOAST_TIMEOUT,
          },
          deleteToast,
        );
      })
      .catch(() => {
        triggerToast();
      })
      .finally(() => {
        setShowButtonLoader(false);
        buttonLoaderCB?.(true);
      });
  };

  const handleCheckboxChange = (list: ListResponse) => {
    if (isProductInWishlist(list, prodId as string)) {
      return;
    }
    if (list.listId) {
      setSelectedCheckboxes((prevSelected) => {
        if (prevSelected.includes(list?.listId ?? '')) {
          return prevSelected.filter((selectedId) => selectedId !== list.listId);
        } else {
          return [...prevSelected, list?.listId ?? ''];
        }
      });
    }
  };

  const handleTextLinkClick = (e: React.MouseEvent<HTMLAnchorElement, MouseEvent>) => {
    e.preventDefault();
    setDisplayCreateListForm(true);
  };

  const createListHandler = () => {
    if (listCreationInProgress) {
      return;
    }
    setListCreationInProgress(true);
    myListApi
      .createList(createListData)
      .then((res) => {
        if (isMyShop) {
          router.push(`${CartRoutePaths.LIST}/${res?.listId}`);
          createToast(
            {
              theme: CartNotificationTheme.SUCCESS,
              rightSeperator: false,
              content: myshopListCreated,
              clickIcon: 'times',
              icon: 'check-circle',
              timeOut: TOAST_TIMEOUT,
            },
            deleteToast,
          );
        } else {
          setCurrentPage(0);
          if (res.listId) {
            setSelectedCheckboxes([...selectedCheckboxes, res.listId]);
          }
          myListApi
            .getListsByUser({
              projections: ApiProjections.DETAILED,
              page: '0',
            })
            .then((res: UserListResponse) => {
              setListData(res);
              setDisplayCreateListForm(false);
            })
            .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps));
        }
      })
      .catch((...errorProps: ErrorAPI[]) => {
        setListCreationInProgress(false);
        if (errorProps[0].responseBody.detail === ListExceptionDetail.ListMaxLimitExceeded) {
          createToast(
            {
              theme: CartNotificationTheme.RED,
              rightSeperator: false,
              content: maxLimitReached,
              subtext: pleaseDeleteToCreateNew,
              clickIcon: 'times',
              icon: 'exclamation-square',
              timeOut: TOAST_TIMEOUT,
            },
            deleteToast,
          );
          onDrawerClose?.();
        } else {
          triggerToast(errorProps);
        }
      });
  };

  const enableConfirmCTA = () =>
    createListData?.name?.length > 0 &&
    (createListData?.description as string)?.length > 0 &&
    (isABO() ? (createListData.category as string)?.length > 0 : true);

  const disableCheckbox = (list: ListResponse) => {
    if (productData?.productFlags?.restrictFromSharing && list.listType === ListType.Shareable) {
      return true;
    }

    return !!list.payLoad?.entries?.find(({ product }) => product.id === prodId);
  };

  const confirmButtonOrLoader = () => {
    if (showLoader) {
      return <FrameRectangle className={styles['create-list-footer-button-loader']} />;
    }

    if (showButtonLoader) {
      return <ButtonLoader className={styles['create-list-footer-button-confirm-loader']} />;
    }

    return (
      <Button
        data-testid="confirm-lists"
        title={t('cart.addToListdrawer.confirm')}
        buttonWidth={ButtonWidth.FULL_WIDTH}
        onClick={isMyShop ? addListToMyShop : onConfirmButtonClick}
        disabled={isMyShop ? false : selectedCheckboxes.length === 0}
      />
    );
  };

  const footerButtons = () => {
    if (displayCreateListForm) {
      return (
        <div className={styles['create-list-footer-button']}>
          {!isMyShop && (
            <Button
              data-testid="create-list-cancel-btn"
              title={t('cart.addToListdrawer.cancel')}
              buttonStyle={ButtonStyles.OUTLINE}
              buttonWidth={ButtonWidth.FULL_WIDTH}
              onClick={() => setDisplayCreateListForm(false)}
            />
          )}
          <Button
            disabled={!enableConfirmCTA()}
            data-testid="create-list-button"
            title={isMyShop ? t('cart.addToListdrawer.confirm') : t('cart.addToListdrawer.save')}
            buttonWidth={ButtonWidth.FULL_WIDTH}
            onClick={createListHandler}
          />
        </div>
      );
    }

    return confirmButtonOrLoader();
  };
  const getSubText = (list: ListResponse) => {
    const isPrivateList = list.listType === ListType.Private;
    return (
      <div className={styles['list-privacy']}>
        <FAIcon iconName={isPrivateList ? 'eye-slash' : 'eye'} />
        {isPrivateList ? t('cart.list.private') : t('cart.list.shareable')}
      </div>
    );
  };
  const showLoaderOrGCOCard = () => {
    if (!productData) {
      return <></>;
    }

    if (showLoader) {
      return <AddToListImageLoader />;
    }

    return (
      <GCOProductCard
        // link={productData?.mainLink as string}
        // alt={productData?.alt}
        // brandName={productData?.brandName}
        // productName={productData?.productName}
        // productId={productData?.productId}
        // productSize={productData?.productSize}
        // productPrice={productData?.productPrice}
        // pointValue={productData?.pointValue}
        // businessVolume={hideBV() ? '' : productData?.businessVolume}
        productData={productData as IProduct}
      />
    );
  };

  return (
    <Drawer
      footer={footerButtons()}
      header={isMyShop ? t('cart.addToListdrawer.addListToMyShop') : t('cart.addToListdrawer.addToList')}
      closeIcon={true}
      closeOnBackdropClick={true}
      onClose={onDrawerClose}
      bottomGap={0}
      useReactPortal={true}
      portalContainerId={'react-portal-drawer'}
    >
      {showLoaderOrGCOCard()}
      {cartEntriesDetails && <CartMobileHeader isListDrawer={true} />}
      {displayCreateListForm ? (
        <CreateList onListDataChange={(data) => setCreateListData(data)} />
      ) : (
        <>
          {showLoader ? (
            <AddToListDrawerLoader />
          ) : (
            <div className={styles[isMyShop ? 'list-container-myShop' : 'list-container']}>
              <div className={styles['list-container-title']}>
                <span>{t('cart.addToListdrawer.lists')}</span>
                <div className={styles['list-container-title-newList']}>
                  <TextLink
                    scroll={false}
                    onClick={handleTextLinkClick}
                    text={t('cart.addToListdrawer.createNewList')}
                    theme={Theme.PURPLE}
                    textLinkStyle={TextLinkStyle.UNDERLINE}
                  />
                </div>
              </div>

              {listData?.lists?.map((list: ListResponse, index: number) => {
                const isLastCard = index === (listData?.lists?.length ?? 0) - 1;
                if (list.listType === ListType.Wishlist && isMyShop) {
                  return null;
                }
                return (
                  <div
                    className={styles['list-container-cardCheckbox']}
                    key={list.listId}
                    ref={isLastCard ? setLastCardCheckbox : undefined}
                  >
                    <CardCheckbox
                      imageShadows
                      imgSrc={
                        list.payLoad?.entries?.[0]?.product.cartIconPublicUrl ?? `${assetsBasePath}/icons/EmptyList.svg`
                      }
                      id={`List${index}`}
                      text={list.payLoad?.name}
                      subText={isMyShop ? getSubText(list) : ''}
                      disabled={disableCheckbox(list)}
                      checked={
                        isProductInWishlist(list, prodId as string) ||
                        (Array.isArray(selectedCheckboxes) && selectedCheckboxes.includes(list.listId as string))
                      }
                      onChange={() => handleCheckboxChange(list)}
                    />
                  </div>
                );
              })}
            </div>
          )}
          {isMyShop && (
            <div className={styles['list-container-myShop-private-text']}>
              <FAIcon iconName="eye-slash" />
              <p data-testid="visitorPrivate">{t('cart.myshop.visitorPrivate')}</p>
            </div>
          )}
        </>
      )}
    </Drawer>
  );
};
export { type AddToListDrawerProps, AddToListDrawer as default };
