import { FAIcon, Toggle, useNextgenRouter, useTranslation } from '@nextgen-web-framework/all';
import {
  type Cart,
  getActiveCart,
  isGroupOrder,
  getUniqueFiredPromotionsExceptCoupons,
  getFiredPromotionFromEntries,
  getFiredPromotionFromSOPMetaData,
  cartApi,
  updateCart,
  PublishEvent,
  CartEventsEnum,
  CartConstantsEnum,
  promosWhichAreNonSilent,
} from '@commerce-cart-webcomponents/sdk';
import { memo } from 'react';
import { useDispatch } from 'react-redux';
import { ConsoleLogger, StorageService } from '@nextgen-web-framework/core';
import { CartNotificationTheme, TOAST_TIMEOUT, useCartNotification, useFeatureFlag } from '../../../common';
import { lazyLoad } from '../../../utils';
import styles from './CartLineItemsFooter.module.scss';

const PromotionDetails = lazyLoad(
  () =>
    import('@commerce-promotion-webcomponents/ui').then((m) => ({
      default: m.PromotionDetails,
    })),
  <></>,
);

const CartCouponsWrapper = lazyLoad(
  () =>
    import('../cart-coupon-wrapper/CartCouponsWrapper').then((m) => ({
      default: m.CartCouponsWrapper,
    })),
  <></>,
);

export const CartLineItemsFooter = memo(
  ({ cartData, cartDetailsPage = false }: { cartData: Cart; cartDetailsPage?: boolean }) => {
    const t = useTranslation();
    const router = useNextgenRouter();
    const cartId = String(router.params?.cartId);
    const currentActiveCart = getActiveCart(cartData, cartId);
    const { promotionResults, entries = [], sopMetaData = [] } = currentActiveCart;
    const { createToast, deleteToast } = useCartNotification('cartLineItemsFooter');
    const showRemoveSuccess = t('cart.cartlineItemFooter.removeSuccess');
    const showPromotions =
      (!isGroupOrder(cartData.orderType) || cartDetailsPage) &&
      (Boolean(promotionResults?.applicablePromotions?.length) ||
        Boolean(promotionResults?.potentialPromotions?.length));
    const firedPromotionsFromEntries = getFiredPromotionFromEntries(entries);
    const firedPromotionsFromSOP = getFiredPromotionFromSOPMetaData(sopMetaData);

    const { hideSilentPromoFlag } = useFeatureFlag();

    const uniqueFiredPromotions = getUniqueFiredPromotionsExceptCoupons([
      ...(promotionResults?.firedPromotions ?? []),
      ...firedPromotionsFromEntries,
      ...firedPromotionsFromSOP,
    ]);

    const showCoupons = (!isGroupOrder(cartData.orderType) || cartDetailsPage) && !currentActiveCart?.hideCouponDetails;
    const dispatch = useDispatch();

    const auxiliaryToggleHandler = async () => {
      try {
        const res = (await cartApi.updateCart(
          StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
          currentActiveCart.subCartId as string,
          {
            removeAuxiliaryProducts: !currentActiveCart?.removeAuxiliaryProducts,
            version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
          },
        )) as Cart;
        if (!currentActiveCart?.removeAuxiliaryProducts) {
          createToast(
            {
              theme: CartNotificationTheme.SUCCESS,
              rightSeperator: false,
              content: showRemoveSuccess,
              clickIcon: 'times',
              icon: 'check-circle',
              timeOut: TOAST_TIMEOUT,
            },
            deleteToast,
          );
        }
        dispatch(updateCart(res as Cart));
        PublishEvent({
          cartEvent: CartEventsEnum.UpdateMiniCartIcon,
          cart: res as Cart,
        });
      } catch (e) {
        ConsoleLogger.log(e);
      }
    };
    return (
      <>
        {currentActiveCart?.hasAuxiliaryItems && (
          <div className={`${styles['auxiliaryItemToggle']}`}>
            <FAIcon iconName={'globe-asia'} className={`${styles['auxiliaryItemToggle-globeIcon']}`} />
            <div className={`${styles['auxiliaryItemToggle-desc']}`}>
              <div className={`${styles['auxiliaryItemToggle-desc-title']}`}>
                {t('cart.cartLineItemsFooter.helpUsReducePlastic')}
              </div>
              {/* <div className={`${styles['auxiliaryItemToggle-desc-subtitle']}`}>
                {currentActiveCart?.removeAuxiliaryProducts
                  ? t('cart.cartLineItemsFooter.ThankyouForNotAccepting')
                  : t('cart.cartLineItemsFooter.getASpoonandAPlasticBag')}
              </div> */}
            </div>
            <div className={`${styles['auxiliaryItemToggle-toggle']}`}>
              <Toggle onClick={() => auxiliaryToggleHandler()} checked={currentActiveCart?.removeAuxiliaryProducts} />
            </div>
          </div>
        )}
        {(showPromotions || showCoupons) && (
          <div data-testid="cart-line-item-footer" className={styles['footer-container']}>
            {showPromotions && (
              <PromotionDetails
                firedPromotions={
                  hideSilentPromoFlag ? promosWhichAreNonSilent(uniqueFiredPromotions) : uniqueFiredPromotions
                }
                potentialPromotions={
                  hideSilentPromoFlag
                    ? promosWhichAreNonSilent(promotionResults?.potentialPromotions)
                    : promotionResults?.potentialPromotions
                }
                tabVariant
              />
            )}
            {showCoupons && <CartCouponsWrapper cart={cartData} subCart={currentActiveCart ?? {}} />}
          </div>
        )}
      </>
    );
  },
);

CartLineItemsFooter.displayName = 'CartLineItemsFooter';
