import {
  type Cart,
  cartApi,
  updateCart,
  CartEvents,
  CartEventsEnum,
  getActiveCart,
  getUniquePromotions,
  getFiredPromotionFromEntries,
  hasCouponOrderDiscountError,
} from '@commerce-cart-webcomponents/sdk';
import { Coupons } from '@commerce-promotion-webcomponents/ui';
import { useDispatch } from 'react-redux';
import type { AppDispatch } from '@nextgen-web-framework/core';
import { type EligibleCoupon, type InvalidCouponsResponse } from '@commerce-promotion-webcomponents/sdk';
import { useState } from 'react';
import { Modal, useTranslation } from '@nextgen-web-framework/all';
import { CartCouponsWrapperProps } from './types/propTypes';

const CartCouponsWrapper = ({ cart, subCart }: CartCouponsWrapperProps) => {
  const dispatch = useDispatch<AppDispatch>();
  const [showUnavailableCouponPopup, setShowUnavailableCouponPopup] = useState(false);
  const t = useTranslation();

  function applyCoupons(coupons: string[]) {
    return cartApi
      .applyCoupon({
        cartId: cart.id,
        subCartId: subCart?.subCartId as string,
        payload: {
          coupons,
          version: cart.version,
        },
      })
      .then((cart) => {
        dispatch(updateCart(cart as Cart));
        CartEvents.publishEvent({
          event: CartEventsEnum.UpdateCartEntryQty,
          payload: {
            cart,
            cartId: (cart as Cart).id,
          },
          sync: true,
        });
        const couponsError = hasCouponOrderDiscountError(cart);
        if (couponsError) {
          setShowUnavailableCouponPopup(true);
        }
        // We need to find currently open subCart.
        const activeCart = getActiveCart(cart as Cart, subCart?.subCartId as string);
        return {
          invalidCoupons: activeCart?.couponResults?.invalidCoupons as InvalidCouponsResponse[],
          hidePromotionToast: couponsError ? true : false,
        };
      });
  }

  const getAllFiredPromotion = () => {
    const { promotionResults, entries } = getActiveCart(cart as Cart, subCart?.subCartId as string);
    return getUniquePromotions(
      [...(promotionResults?.firedPromotions ?? []), ...getFiredPromotionFromEntries(entries)],
      true,
    );
  };

  return (
    <>
      <Coupons
        firedPromotions={getAllFiredPromotion()}
        applyCoupon={applyCoupons}
        applicableCoupons={subCart?.couponResults?.applicableCoupons as EligibleCoupon[]}
        appliedCoupons={subCart?.couponResults?.appliedCoupons}
        potentialCoupons={subCart?.couponResults?.potentialCoupons as EligibleCoupon[]}
        invalidCoupons={subCart?.couponResults?.invalidCoupons as InvalidCouponsResponse[]}
      />
      {showUnavailableCouponPopup && (
        <Modal
          closeIcon={false}
          data-testId
          onClose={() => setShowUnavailableCouponPopup(false)}
          headline={t('cart.coupon.couponUnavailable')}
          primaryButtonLabel={t('cart.coupon.returnToCart')}
          onPrimaryButtonClick={() => setShowUnavailableCouponPopup(false)}
        >
          <div>{t('cart.coupon.couponHasBeenRemoved')}</div>
        </Modal>
      )}
    </>
  );
};

export { CartCouponsWrapper };
