import { useState, useEffect, memo } from 'react';
import {
  useTranslation,
  AlertMessage,
  Theme,
  TextLink,
  TextLinkUnderlineStyle,
  useSession,
  useNextgenRouter,
  AlertMessageType,
  AlertMessageTheme,
  NotificationBar,
} from '@nextgen-web-framework/all';
import {
  RenewalFlag,
  Cart,
  CartConstantsEnum,
  CartEventsEnum,
  InitialCartState,
  OrderType,
  PublishEvent,
  cartApi,
  switchToRegularCart,
  updateCart,
  getAccountProductType,
  getActiveCart,
  updateRenewalFlagsData,
  AccountProductType,
  AccountType,
  AccountProcessType,
  forceAddRenewalProduct,
  getRenewalLateFeeOnlyConfig,
} from '@commerce-cart-webcomponents/sdk';
import { type AppState, DateFormats, StorageService, formatDate, formatPrice } from '@nextgen-web-framework/core';
import { useSelector, useDispatch } from 'react-redux';
import {
  AccountDetailRenewalLifecycleEnum,
  AutoRenewalOrderStatus,
  type RenewalNudgeType,
} from '@commerce-profile-webcomponents/sdk';
import { useRenewalStatus } from '@commerce-profile-webcomponents/ui';
import { ModalWrapper } from '../../../common';
import { RouteType } from '../../mini-cart/types/enums';
import styles from './AboMembershipRenewal.module.scss';

export const AboMembershipRenewal = memo(() => {
  const { isABO, isMember, isAnonymous } = useSession();
  const router = useNextgenRouter();
  const [showRenewNowModal, setShowRenewNowModal] = useState(false);
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { cart }: InitialCartState = commerceCartState;
  const cartId = String(router.params?.cartId);
  const mainSubCart = getActiveCart(cart, cartId);
  const { amwayUser, entries: cartEntries } = mainSubCart || {};
  //Added Partial<RenewalNudgeType> because there are more properties added in RenewalNudgeType which is causing error
  const [renewFlags, setRenewFlags] = useState<Partial<RenewalNudgeType>>({
    showRenewalNudge: false,
    isLastGraceMonth: false,
    renewalNudgeMessage: '',
    renewalFeeMessage: '',
    orderCancellationMessage: '',
    renewalNudgeTheme: Theme.PURPLE,
    isAutoRenewalEnabled: false,
    isAutoRenewalFailed: false,
  });
  const t = useTranslation();
  const dispatch = useDispatch();
  const renewalFlag = amwayUser?.renewalFlag;
  const expiryDate = amwayUser?.expirationDate
    ? formatDate(String(amwayUser?.expirationDate), DateFormats.SHORT_DATE, router?.params?.locale as string)
    : '';

  const feeProduct = getAccountProductType(cartEntries ?? [], AccountProductType.Fee);

  const lateFeeProduct = getAccountProductType(cartEntries ?? [], AccountProductType.LateFee);

  const { getRenewalNudgeStatus } = useRenewalStatus();
  const enableRenewalLateFeeOnly = getRenewalLateFeeOnlyConfig();

  useEffect(() => {
    const fetchNudgeStatus = async () => {
      const data = await getRenewalNudgeStatus();
      setRenewFlags(data);
      dispatch(updateRenewalFlagsData(data));
    };
    fetchNudgeStatus();
  }, []);

  const {
    showRenewalNudge,
    renewalNudgeMessage,
    renewalFeeMessage,
    renewalNudgeTheme,
    orderCancellationMessage,
    autoRenewalOrderStatus,
  } = renewFlags || {};

  const hasRenewalFlag =
    (isABO() || isMember()) &&
    renewalFlag &&
    !cart?.accountProcess &&
    showRenewalNudge &&
    amwayUser?.renewalLifeCycle === AccountDetailRenewalLifecycleEnum.None;

  // sku can be added for "none" and "cancelled".
  // sku can not be added for "failed", "pending" or "successful"
  const checkForRenewalOrderStatus = autoRenewalOrderStatus
    ? ([AutoRenewalOrderStatus.Cancelled, AutoRenewalOrderStatus.None] as AutoRenewalOrderStatus[]).includes(
        autoRenewalOrderStatus as AutoRenewalOrderStatus,
      )
    : true;

  const mustRenewAlert = hasRenewalFlag && renewalFlag === RenewalFlag.MustRenew;

  const showRenewNowAlert = hasRenewalFlag && renewalFlag === RenewalFlag.CanRenew;

  useEffect(() => {
    if (mustRenewAlert && forceAddRenewalProduct() && checkForRenewalOrderStatus) {
      renewAccount();
    }
  }, [renewalFlag, showRenewalNudge]);

  const removeAccountProcessCheck = !isAnonymous() && amwayUser?.renewalFlag;

  useEffect(() => {
    if (
      removeAccountProcessCheck &&
      typeof cart.accountProcess === 'object' &&
      (
        [AccountProcessType.Renewal, AccountProcessType.Upgrade, AccountProcessType.Downgrade] as AccountProcessType[]
      ).includes(cart.accountProcess.type as AccountProcessType) &&
      (![RenewalFlag.CanRenew as string, RenewalFlag.MustRenew as string].includes(amwayUser?.renewalFlag as string) ||
        autoRenewalOrderStatus === AutoRenewalOrderStatus.Failed ||
        (amwayUser?.renewalLifeCycle && amwayUser?.renewalLifeCycle !== AccountDetailRenewalLifecycleEnum.None))
    ) {
      const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
      cartApi
        .updateCart(cartId, cartId, {
          removeAccountProcess: true,
          orderType: OrderType.Regular,
          version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
        })
        .then((res) => {
          dispatch(updateCart(res as Cart));
          PublishEvent({
            cartEvent: CartEventsEnum.UpdateMiniCartIcon,
            cart: res as Cart,
          });
        });
    }
  }, [cart]);

  const isRegularCart = cart.orderType === OrderType.Regular;

  const renewAccount = async () => {
    const cartId = StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId);
    const res = (await cartApi.updateCart(cartId, cartId, {
      accountProcess: {
        type: AccountProcessType.Renewal,
        businessNature: isABO() ? AccountType.BusinessOwner : AccountType.Member,
      },
      orderType: OrderType.Regular,
      version: +StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion),
    })) as Cart;
    dispatch(updateCart(res as Cart));
  };

  const orderForRegularCart = async () => {
    const res = await switchToRegularCart(cart);
    dispatch(updateCart(res as Cart));
    renewAccount();
    setShowRenewNowModal(false);
  };

  return (
    <>
      {showRenewNowModal && (
        <ModalWrapper
          headLineText={t('cart.aboMembershipRenewal.renewNow')}
          description={t('cart.aboMembershipRenewal.renewNowDesc')}
          primaryButtonLabel={t('cart.cartContainer.continueText')}
          secondaryButtonLabel={t('cart.clearCart.secondaryButton')}
          onSecondarySuccess={() => setShowRenewNowModal(false)}
          onPrimarySuccess={orderForRegularCart}
        />
      )}
      {amwayUser?.renewalLifeCycle === AccountDetailRenewalLifecycleEnum.Processing && (
        <AlertMessage hasIcon={false} theme={Theme.PURPLE} className={styles['alert-message-container']}>
          {t('cart.aboMembershipRenewal.renewalInProcess')}
        </AlertMessage>
      )}
      {(showRenewNowAlert || (mustRenewAlert && !forceAddRenewalProduct())) && (
        <AlertMessage
          hasIcon={false}
          theme={(renewalNudgeTheme as AlertMessageTheme) ?? Theme.PURPLE}
          className={styles['alert-message-container']}
          type={AlertMessageType.RIBBON}
        >
          <div className={styles['alert-message-banner']}>
            <div className={styles['alert-message-banner-text']}>
              {renewalNudgeMessage || `${t('cart.aboMembershipRenewal.accountExpirationText')} ${expiryDate}`}
              {renewalFeeMessage && (
                <ul className={styles['alert-message-banner-text-list']}>
                  <li>
                    <b>{t('cart.aboMembershipRenewal.renewalFeeText')}</b>
                    {renewalFeeMessage}
                  </li>
                  <li>
                    <b>{t('cart.aboMembershipRenewal.orderCancellations')}</b>
                    {orderCancellationMessage}
                  </li>
                </ul>
              )}
            </div>
            <div className={styles['alert-message-banner-textlink']}>
              <TextLink
                onClick={() => {
                  if (checkForRenewalOrderStatus) {
                    if (isRegularCart) {
                      renewAccount();
                    } else {
                      setShowRenewNowModal(true);
                    }
                  } else {
                    router.push(RouteType.ORDER_HISTORY);
                  }
                }}
                underline={TextLinkUnderlineStyle.FIXED}
                text={t('cart.aboMembershipRenewal.renewNow')}
                theme={Theme.WHITE}
              />
            </div>
          </div>
        </AlertMessage>
      )}

      {feeProduct && cart.accountProcess?.type === AccountProcessType.Renewal && (
        <AlertMessage
          content={{
            heading: `${
              isABO() ? t('cart.aboMembershipRenewal.aboRenewalFees') : t('cart.aboMembershipRenewal.memberRenewalFees')
            } - ${formatPrice(feeProduct.totalPrice?.value ?? 0)}`,
          }}
          icon={'address-card'}
          theme={Theme.ACTION}
          className={styles['alert-message-bold']}
        />
      )}

      {lateFeeProduct && cart.accountProcess?.type === AccountProcessType.Renewal && (
        <>
          {enableRenewalLateFeeOnly ? (
            <NotificationBar message={`${t('cart.aboMembershipRenewal.membershipExpired')}`} theme={Theme.ORANGE} />
          ) : (
            <AlertMessage
              content={{
                heading: `${t('cart.aboMembershipRenewal.lateRenewalFees')} - ${formatPrice(
                  lateFeeProduct.totalPrice?.value ?? 0,
                )}`,
              }}
              icon={'address-card'}
              theme={Theme.WARNING}
              className={styles['alert-message-bold']}
            />
          )}
        </>
      )}
    </>
  );
});

AboMembershipRenewal.displayName = 'AboMembershipRenewal';
