import { useState, useContext, useEffect, useRef } from 'react';
import {
  useNextgenRouter,
  QuantityStepper,
  QuantityStepperSize,
  ButtonSize,
  QuantityStepperWidth,
  useTranslation,
} from '@nextgen-web-framework/all';
import { StorageService, type AppDispatch, type AppState } from '@nextgen-web-framework/core';
import {
  CartEventsEnum,
  type Cart,
  CartConstantsEnum,
  type CartEntry,
  type InitialCartState,
  updateCart,
  PublishEvent,
  getActiveCart,
  type CartEntryDetails,
  InitialCartListState,
  ListEntry,
  ListResponse,
  publishLoaderEvent,
  myListApi,
  getMaxProductQty,
  cartApi,
  ErrorAPI,
  updateIsQuantityStepperInFocus,
  CartEvents,
  CartEventsVersionsEnum,
  CartEventDataInterface,
  enablePartialListSelection,
} from '@commerce-cart-webcomponents/sdk';
import { useDispatch, useSelector } from 'react-redux';
import {
  AllCustomListContext,
  CartNotificationTheme,
  TOAST_TIMEOUT,
  useCartNotification,
  useExceptionToast,
  useFeatureFlag,
  type CustomListContextType,
} from '@commerce-cart-webcomponents/ui';
import { ButtonLoader } from '../../../ui/common/components/cart-loader/button-loader/ButtonLoader';
import { RouteType } from '../cart-container/types/enums';
import { QtySelectorPropTypes } from './types/propsTypes';
import styles from './QtySelector.module.scss';
import { SharedListQtySelector } from './sharedList-qty-selector/SharedListQtySelector';

export const QtySelector = ({
  disabled = false,
  entryObj,
  updateQuantityCustomHandler,
  disableApiCallOnQtyUpdate = false,
  min = '0',
  transitionToStepper = false,
  setShowStepper,
  size,
}: QtySelectorPropTypes) => {
  const dispatch = useDispatch<AppDispatch>();
  const router = useNextgenRouter();
  const cartId = router.params?.cartId ?? '';
  const listId = router.params?.listId ?? '';
  const commerceCartState = useSelector((state: AppState) => state.commerceCart);
  const { cart }: InitialCartState = commerceCartState;
  const triggerToast = useExceptionToast();
  const [plusClickCount, setPlusClickCount] = useState(0);
  const clickTimer = useRef(null);
  const inputRef = useRef<HTMLInputElement>(null);
  const stepperRef = useRef<HTMLInputElement>(null);
  const activeCart = getActiveCart(cart, String(cartId));
  const subscriptionIds = useRef<string[]>();
  const ignoreBlurRef = useRef<boolean>(false);
  const { createToast, deleteToast } = useCartNotification('QtySelector');
  const t = useTranslation();

  const { customList, updateCustomList }: CustomListContextType = useContext(AllCustomListContext);
  const { myList }: InitialCartListState = useSelector((state: AppState) => state.commerceMyList);
  const maxProductCount = getMaxProductQty();
  const itemRemovedToastText = t('cart.qtyselector.removedFromCart');

  const decodedListId = decodeURIComponent(listId as string);

  const currentList = decodedListId === myList?.listId ? myList : customList;
  const cartEntry: CartEntryDetails | undefined = activeCart?.entries?.find(
    (entry: CartEntry) => entryObj.entryId == entry.entryId,
  );

  const listEntry: ListEntry | undefined = currentList?.payLoad?.entries?.find(
    (entry: ListEntry) => entryObj.entryId == entry.entryId,
  );

  const isList = decodedListId && decodedListId === currentList?.listId;
  const maxCount = cartEntry?.rationingResult?.[0]?.availableQuantity;
  const { showProxyConsentFlag } = useFeatureFlag();
  const initialCount = isList ? (listEntry?.quantity as number) : (cartEntry?.quantity as number);
  const [count, setCount] = useState<number>(initialCount);
  const [showLoader, setShowLoader] = useState(false);
  const [updateQuantityCalled, setUpdateQuantityCalled] = useState(false);
  const isOrderPage = router.pathname?.includes(RouteType.ORDER_HISTORY);

  const showSuccessToast = () => {
    createToast(
      {
        theme: CartNotificationTheme.SUCCESS,
        rightSeperator: false,
        content: itemRemovedToastText,
        clickIcon: 'times',
        icon: 'check-circle',
        timeOut: TOAST_TIMEOUT,
      },
      deleteToast,
    );
  };

  useEffect(() => {
    if (transitionToStepper) {
      const handleClickOutside = (event) => {
        if (stepperRef.current && !stepperRef.current.contains(event.target)) {
          setShowStepper?.(false);
        }
      };

      document.addEventListener('click', handleClickOutside);

      const updateCount: string[] = CartEvents.subscribeEvents({
        topics: [CartEventsEnum.UpdateCount],
        version: CartEventsVersionsEnum['1.0.0'],
        cb: (cartEvent: string, { product_unitPrice, product_id }: CartEventDataInterface) => {
          if (entryObj.productId === product_id?.[0]) {
            setCount(Number(product_unitPrice?.[0]));
          }
        },
      });
      subscriptionIds.current = [...updateCount];

      return () => {
        document.removeEventListener('click', handleClickOutside);
        CartEvents.unsubscribe(subscriptionIds.current);
      };
    }
    return undefined;
  }, []);

  useEffect(() => {
    if (isList) {
      setCount(listEntry?.quantity as number);
    }
  }, [listEntry?.quantity]);

  useEffect(() => {
    if (!isList) {
      setCount(cartEntry?.quantity as number);
    }
  }, [cartEntry?.quantity]);
  useEffect(() => {
    if (!updateQuantityCalled) {
      return;
    }
    const input = inputRef.current;
    if (!input) {
      return;
    }

    ignoreBlurRef.current = true;
    input.focus();
    input.blur();
    ignoreBlurRef.current = false;
  }, [cartEntry?.quantity]);

  const updateQuantity = (quantity: number, productRemoved?: boolean) => {
    if (quantity <= 0 && (transitionToStepper || showProxyConsentFlag)) {
      setShowStepper?.(false);
      showSuccessToast();
    }

    if (disableApiCallOnQtyUpdate) {
      return 0;
    }
    if (!updateQuantityCalled) {
      setUpdateQuantityCalled(true);
    }
    if (!updateQuantityCustomHandler) {
      setShowLoader(true);
      const cartPayload = {
        entry: {
          entryId: entryObj.entryId,
          product: {
            id: cartEntry?.product.id as string,
          },
          quantity: quantity,
          bundleSlots: cartEntry?.bundleSlots?.map((slot) => ({
            ...slot,
            entries: slot.entries.map((entry) => ({
              ...entry,
              quantity: entry.quantity / cartEntry.quantity,
            })),
          })),
          sopMappingKey: cartEntry?.sopMappingKey || null,
        },
        version: Number(StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartReqVersion)),
      };

      const listPayload = {
        entry: {
          entryId: entryObj.entryId,
          bundleSlots: listEntry?.bundleSlots,
          product: {
            id: listEntry?.product.id as string,
          },
          quantity: quantity,
        },
        version: currentList?.version as number,
      };

      publishLoaderEvent(true, entryObj.entryId);
      if (isList) {
        myListApi
          .changeQtyForEntryFromList({
            entryId: entryObj.entryId,
            listId: currentList?.listId,
            payload: listPayload,
          })
          .then((updatedList: ListResponse) => {
            setCount(quantity);
            updateCustomList(updatedList);
          })
          .catch((...errorProps: ErrorAPI[]) => triggerToast(errorProps))
          .finally(() => {
            setShowLoader(false);
            publishLoaderEvent(false, entryObj.entryId);
          });
      } else {
        cartApi
          .changeQtyForEntryFromCart({
            cartId: StorageService.getLocalStorage().retrieve(CartConstantsEnum.CartId),
            subCartId: activeCart?.subCartId,
            entryId: entryObj.entryId,
            payload: cartPayload,
          })
          .then((res) => {
            setCount(quantity);
            setShowLoader(false);
            dispatch(updateCart(res as Cart));
            publishLoaderEvent(false, entryObj.entryId);
            clickSuccessHandler(res as Cart, productRemoved);
            if (transitionToStepper) {
              CartEvents.publishEvent({
                event: CartEventsEnum.UpdateCount,
                payload: {
                  cartId: (res as Cart).id,
                  product_id: entryObj.productId,
                  product_unitPrice: quantity,
                },
              });
            }
          })
          .catch(() => {
            triggerToast();
            setShowLoader(false);
            publishLoaderEvent(false, entryObj.entryId);
          });
      }
    } else {
      updateQuantityCustomHandler(entryObj, quantity);
    }
    return 0;
  };

  const getProductEntry = () => activeCart?.entries?.find((entry) => entryObj.productId === entry.product.id);

  const clickSuccessHandler = (res: Cart, isRemoved = false) => {
    PublishEvent({
      cartEvent: isRemoved ? CartEventsEnum.RemoveCartEntry : CartEventsEnum.AddToCart,
      cartEntry: getProductEntry(),
      cartId: res.id,
      cart: res,
    });
  };

  if (enablePartialListSelection() && (currentList?.isReceiver || isOrderPage)) {
    return <SharedListQtySelector entryObj={entryObj} />;
  }

  return showLoader ? (
    <ButtonLoader className={styles['qty-selector-loader']} isStepper={true} size={ButtonSize.SMALL} />
  ) : (
    <div ref={stepperRef}>
      <QuantityStepper
        ref={inputRef}
        count={count}
        width={transitionToStepper ? QuantityStepperWidth.FULL_WIDTH : QuantityStepperWidth.DEFAULT}
        maxLength={String(maxProductCount).length}
        maxCount={maxProductCount}
        size={QuantityStepperSize.SMALL}
        height={size === ButtonSize.MEDIUM ? 48 : 36}
        minCount={+min}
        onFocus={() => {
          dispatch(updateIsQuantityStepperInFocus(true));
        }}
        onBlur={() => {
          if (!ignoreBlurRef.current) {
            updateQuantity(count);
          }
          dispatch(updateIsQuantityStepperInFocus(false));
        }}
        inputChangeHandler={(qty: number) => {
          setCount(qty);
          return 0;
        }}
        plusClickHandler={(qty: number) => {
          if (maxCount && count > maxCount) {
            return 0;
          }
          if (transitionToStepper || showProxyConsentFlag) {
            setPlusClickCount((prev) => prev + 1);
            if (clickTimer.current) {
              clearTimeout(clickTimer.current);
            }
            // If user clicked 5 times consecutively
            if (plusClickCount + 1 === 5) {
              setCount(qty);
              setPlusClickCount(0);
              inputRef.current?.focus();
              return 0;
            }
            // If not 5 clicks yet → normal single + update with delay
            clickTimer.current = setTimeout(() => {
              updateQuantity(qty);
              setPlusClickCount(0);
            }, 500);
          } else {
            updateQuantity(qty);
          }
          return 0;
        }}
        minusClickHandler={(qty: number) => updateQuantity(qty, true)}
        disablePlusButton={maxCount && count > maxCount ? true : false}
        disabled={disabled}
      />
    </div>
  );
};

export type { QtySelectorPropTypes };
