import { logObject, type GenericObject } from '@commerce-product-webcomponents/sdk';
import { aprApi } from '@commerce-webcomponents/sdk';
import { pageNameForAPR } from '@commerce-cart-webcomponents/sdk';
import { useSession, useTranslation } from '@nextgen-web-framework/all';
import { Logger } from '@nextgen-web-framework/core';
import { useEffect, useState } from 'react';
import { CarousalType, ProductCarousal } from '@commerce-product-webcomponents/ui-composite';
import styles from './RecommendedProducts.module.scss';
import { AprContainerKey } from './types/enums';

export type AprReqPayload = {
  aprContainerKey: string;
  filter: GenericObject;
  pageName: string;
  slots: number;
};

const loggerInstance = Logger.getInstance(logObject('RecommendedProducts'));

const calculateGlobalAccountNumber = (accountNum: string): number => {
  const tenant = ConfigService.getConfigs().NEXT_PUBLIC_TENANT ?? 0; // tenant is the affiliate id
  return Number(`${tenant}00000000000`) + Number(accountNum);
};

const RecommendedProducts = () => {
  const { isAnonymous, session } = useSession();
  const t = useTranslation();
  const [isAnonymousUser, setIsAnonymousUser] = useState(true);
  const [data, setData] = useState<string[]>([]);
  const [dataForLoggedInUsers, setDataForLoggedInUsers] = useState<string[]>([]);
  const showFavCarousel = !isAnonymousUser;

  useEffect(() => {
    setIsAnonymousUser(isAnonymous());
  }, [session]);

  useEffect(() => {
    getAprProducts();
  }, []);

  useEffect(() => {
    if (showFavCarousel) {
      getAprProductsForLoggedInUsers();
    }
  }, [isAnonymousUser]);

  const createPayload = (): AprReqPayload => ({
    aprContainerKey: AprContainerKey.RECOMMENDED_FOR_YOU,
    filter: {},
    pageName: (pageNameForAPR() as string) ?? '',
    slots: 4,
  });

  const getAprProductsForLoggedInUsers = () => {
    const payload = createPayload();
    const { aboNum = '' } = session || {};
    const globalAccountNumber = calculateGlobalAccountNumber(aboNum).toString();

    aprApi
      .getProductIdsByAPR({
        ...payload,
        aprContainerKey: AprContainerKey.YOUR_FAVORITES,
        ...(globalAccountNumber && { accountNum: globalAccountNumber }),
      })
      .then((data: string[]) => setDataForLoggedInUsers(data))
      .catch((err: Error) => {
        loggerInstance.error('Error occured while fetching APR data for loggedIn users', err);
      });
  };

  const getAprProducts = () => {
    const payload = createPayload();
    aprApi
      .getProductIdsByAPR(payload)
      .then((data: string[]) => setData(data))
      .catch((err: Error) => {
        loggerInstance.error('Error occured while fetching APR data for anonymous users', err);
      });
  };

  const getProductIds = (data: string[]) => data.map((id) => ({ productId: id, isBundle: false }));

  return (
    <>
      <div className={styles['recommended-products-container']}>
        <ProductCarousal
          products={getProductIds(data)}
          type={CarousalType.Vertical}
          title={t('product.composite.productContainer.recommendedForYou')}
        />
        {showFavCarousel && (
          <ProductCarousal
            products={getProductIds(dataForLoggedInUsers)}
            type={CarousalType.Vertical}
            title={t('product.composite.productContainer.yourFavorites')}
          />
        )}
      </div>
    </>
  );
};

export { RecommendedProducts };
